/* AUTO-GENERATED — Alaska Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["AK"] = {"code":"AK","name":"Alaska","agency":"Alaska DMV","agencyShort":"DMV","handbook":"https://dmv.alaska.gov/credential-services/commercial-drivers-license-cdl/","links":{},"en":[{"q":"In Alaska, what is the maximum legal width of a vehicle, including its load, on the state highway system?","options":["102 inches","96 inches","108 inches","114 inches"],"answer":0,"explanation":"Alaska sets the maximum vehicle width, including load, at 102 inches; attached equipment may extend no more than 3 inches beyond that on each side. Source: 17 AAC 25.012(a) (Alaska DOT&PF, Chapter 25 Operations, Wheeled Vehicles), consistent with the Alaska CDL Manual.","handbook":"","hbref":""},{"q":"What is the general maximum legal height of a vehicle and load on most Alaska highways?","options":["15 feet","13 feet 6 inches","14 feet","16 feet"],"answer":0,"explanation":"Under 17 AAC 25.012(b), an Alaska vehicle including load may not exceed 15 feet in height, except for the Dalton/Elliott Highway corridor between the Fox Weigh Station and Prudhoe Bay, where 17 feet is allowed. Source: 17 AAC 25.012(b), Alaska DOT&PF.","handbook":"","hbref":""},{"q":"On the Dalton and Elliott Highways between the Fox Weigh Station and Prudhoe Bay, what increased height is allowed for a vehicle and load?","options":["15 feet 6 inches","16 feet","17 feet","18 feet"],"answer":2,"explanation":"17 AAC 25.012(b) allows a height, including load, of 17 feet for a vehicle operating between the Fox Weigh Station and Prudhoe Bay on the Dalton and Elliott Highways, versus the 15-foot general limit. Source: 17 AAC 25.012(b), Alaska DOT&PF.","handbook":"","hbref":""},{"q":"On Alaska's National Highway System routes, what is the maximum length of a single power vehicle (the truck or truck tractor itself)?","options":["40 feet","48 feet","53 feet","45 feet"],"answer":3,"explanation":"17 AAC 25.012(c)(1) limits the length of a power vehicle to 45 feet on NHS routes (and 17 AAC 25.012(d)(1) sets the same 45-foot limit on the rest of the state highway system). Source: 17 AAC 25.012, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"In Alaska, what is the maximum cargo-carrying length of a semitrailer or trailer used in a combination?","options":["48 feet","57 feet","60 feet","53 feet"],"answer":3,"explanation":"17 AAC 25.012(c)(3) and (e)(1) cap the cargo-carrying length of a semitrailer or trailer at 53 feet on all routes. Source: 17 AAC 25.012, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"What is the maximum overall length of a standard combination consisting of a truck and one cargo-carrying vehicle, or a truck tractor and two cargo-carrying vehicles, on Alaska highways?","options":["65 feet","70 feet","75 feet","80 feet"],"answer":2,"explanation":"17 AAC 25.012(c)(4) and (d)(3) limit such combinations to an overall length of 75 feet; a truck tractor with a single cargo-carrying vehicle is not subject to an overall length limit. Source: 17 AAC 25.012, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"In Alaska, how far may a load or equipment extend beyond the front bumper of the vehicle before it exceeds the legal limit?","options":["3 feet","4 feet","5 feet","6 feet"],"answer":0,"explanation":"17 AAC 25.012(c)(6) and (d)(4) allow a load or equipment to overhang no more than 3 feet beyond the front bumper (and no more than 4 feet beyond the rear). Source: 17 AAC 25.012, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"In Alaska, how far may a load extend beyond the rear of a vehicle before it exceeds the legal limit?","options":["3 feet","5 feet","6 feet","4 feet"],"answer":3,"explanation":"17 AAC 25.012(c)(6)(B) and (d)(4)(B) permit a rear overhang of no more than 4 feet (front overhang is limited to 3 feet). Source: 17 AAC 25.012, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"What is the maximum legal weight allowed on a single axle in Alaska?","options":["18,000 pounds","22,400 pounds","34,000 pounds","20,000 pounds"],"answer":3,"explanation":"17 AAC 25.013(a)(4) sets the single-axle weight limit at 20,000 pounds, with a minimum 8'1\" spacing for an axle to count as a single axle. Source: 17 AAC 25.013, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"Under Alaska's axle-group table, what is the maximum weight allowed on a 2-axle group (tandem axle)?","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"answer":2,"explanation":"Alaska's axle-group weight table in 17 AAC 25.013(a)(4) allows 38,000 pounds on a 2-axle group (tandem), which is higher than the 34,000-pound federal tandem standard used in many states. Source: 17 AAC 25.013, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"Under Alaska's axle-group weight table, what is the maximum weight allowed on a 3-axle group?","options":["38,000 pounds","46,000 pounds","50,000 pounds","42,000 pounds"],"answer":3,"explanation":"17 AAC 25.013(a)(4) allows 42,000 pounds on a 3-axle group (with a 3'6\" minimum axle spacing). Source: 17 AAC 25.013, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"What minimum axle spacing must be maintained for an axle to be treated as a 'single axle' rather than part of an axle group in Alaska?","options":["8 feet 1 inch","3 feet 6 inches","6 feet","10 feet"],"answer":0,"explanation":"Per the note to 17 AAC 25.013(a)(4), any axle spaced less than 8 feet 1 inch from another axle (center to center) is considered part of an axle group; the single-axle limit applies at 8'1\" minimum spacing. Source: 17 AAC 25.013, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"How does Alaska determine the maximum gross vehicle weight for a long combination?","options":["A flat 80,000-pound cap on all highways","By multiplying axle count by 20,000 pounds","By applying the state's Bridge Gross Weight Formula based on axle count and spacing","By a fixed 105,500-pound limit set by statute"],"answer":2,"explanation":"17 AAC 25.013(a)(6) sets maximum gross weight by the Bridge Gross Weight Formula W = 500[LN/(N-1) + 12N + 36] (with +3,000 added when there are no lift axles in the drive group), not by a flat 80,000-pound cap. Source: 17 AAC 25.013, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"In Alaska's Bridge Gross Weight Formula W = 500[LN/(N-1) + 12N + 36], what does the variable 'L' represent?","options":["The legal load weight in tons","The distance in feet between the centers of the extreme axles","The length of the longest trailer","The lift-axle capacity"],"answer":1,"explanation":"In 17 AAC 25.013(a)(6), 'L' is the distance in whole feet measured between the centers of the extreme axles of the vehicle or combination, and 'N' is the number of axles. Source: 17 AAC 25.013, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a tire in Alaska, based on the manufacturer's nominal tire width?","options":["600 pounds per inch of tire width","500 pounds per inch of tire width","550 pounds per inch of tire width","650 pounds per inch of tire width"],"answer":0,"explanation":"17 AAC 25.013(a)(1) limits tire weight to 600 pounds per linear inch of tire width, based on the tire manufacturer's rating of nominal tire width. Source: 17 AAC 25.013, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"When is an Alaska DOT&PF oversize/overweight permit required?","options":["Only for loads over 100,000 pounds gross weight","When a vehicle or load exceeds the maximum dimensions or weights in 17 AAC 25 and will travel on a public road","Only when crossing a state border into Canada","Only for vehicles wider than 12 feet"],"answer":1,"explanation":"Per the Administrative Permit Manual (Sec. 2.2.1) and 17 AAC 25.320, a permit is required whenever a vehicle or vehicle-with-load exceeds the maximum dimensions or weights in 17 AAC 25 and requests to travel on a public road. Source: Alaska DOT&PF Administrative Permit Manual; 17 AAC 25.320.","handbook":"","hbref":""},{"q":"Alaska issues oversize/overweight permits only for loads that are which of the following?","options":["Divisible loads that can be split into legal portions","Non-divisible loads that cannot be reduced to legal size or weight","Loads owned by government agencies","Loads carrying hazardous materials"],"answer":1,"explanation":"Alaska permits are issued for non-divisible loads (those that cannot be practically reduced to legal dimensions/weight); divisible loads must be broken down to legal limits. Source: Alaska DOT&PF Administrative Permit Manual Sec. 2.2 and 17 AAC 25.320(a)(1).","handbook":"","hbref":""},{"q":"In Alaska, what is the standard validity period of a single-trip oversize/overweight permit (for a move of 400 miles or less one way)?","options":["1 day","3 days","7 days","30 days"],"answer":1,"explanation":"Per the Administrative Permit Manual Sec. 3.2.1, a single-trip permit is valid for a 3-day period (extended to 5 days if traveling more than 400 miles one way). Source: Alaska DOT&PF Administrative Permit Manual.","handbook":"","hbref":""},{"q":"During winter months in Alaska, what extra gross-weight allowance may be granted for documented snow and ice build-up on a vehicle?","options":["500 pounds","1,000 pounds","1,500 pounds","2,000 pounds"],"answer":2,"explanation":"17 AAC 25.335(b)(1) grants an additional 1,500-pound allowance from October 1 through April 30 when there is evidence of snow and ice build-up; this is the maximum regardless of combination type. Source: 17 AAC 25.335, Alaska DOT&PF.","handbook":"","hbref":""},{"q":"Which CDL class does Alaska require to operate a single vehicle with a gross vehicle weight rating (GVWR) of 26,001 pounds or more, such as a dump truck or motor coach?","options":["Class A","Class B","Class C","Class D"],"answer":1,"explanation":"The Alaska CDL Manual defines Class B as any single vehicle with a GVWR in excess of 26,001 pounds, or such a vehicle towing a unit not weighing 10,000 lbs or more (dump trucks, cement mixers, box trucks, motor coaches). Source: Alaska DMV CDL Manual, Section 1, Vehicle Classifications.","handbook":"","hbref":""},{"q":"Per the Alaska CDL Manual, a Class A CDL is required for any combination of vehicles with a GCWR of 26,001 lbs or more, provided the GVWR of the towed unit(s) exceeds what weight?","options":["8,000 pounds","10,000 pounds","16,000 pounds","26,001 pounds"],"answer":1,"explanation":"Alaska defines Class A as a combination with GCWR of 26,001+ lbs where the GVWR of the vehicle(s) being towed is more than 10,000 pounds (e.g., 18-wheelers, logging trucks). Source: Alaska DMV CDL Manual, Section 1, Class A definition.","handbook":"","hbref":""},{"q":"Under Alaska rules, a vehicle with a GVWR under 26,001 lbs still falls into the CDL program (Class C) if it is designed to carry how many passengers, including the driver?","options":["8 or more","11 or more","15 or more","16 or more"],"answer":3,"explanation":"The Alaska CDL Manual includes a smaller vehicle in the CDL program as Class C if it is designed to carry 16 or more passengers including the driver, or transports placardable hazardous materials. Source: Alaska DMV CDL Manual, Section 1, Class C definition.","handbook":"","hbref":""},{"q":"In Alaska, which endorsement letter is placed on the CDL for transporting hazardous materials in placardable amounts?","options":["Endorsement H","Endorsement N","Endorsement X","Endorsement T"],"answer":0,"explanation":"Alaska uses endorsement H (Hazardous Materials) for any vehicle used to transport hazardous materials in placardable amounts. Source: Alaska DMV CDL Manual, Section 1, Endorsements table.","handbook":"","hbref":""},{"q":"Which endorsement does Alaska require for any vehicle intended for hauling liquids in bulk (tank trucks)?","options":["Endorsement H","Endorsement N","Endorsement P","Endorsement T"],"answer":1,"explanation":"The Alaska CDL Manual lists endorsement N (Tanker) for any vehicle intended for hauling liquids in bulk. Note that Alaska's code letter for the tank endorsement is N. Source: Alaska DMV CDL Manual, Section 1, Endorsements table.","handbook":"","hbref":""},{"q":"Which Alaska CDL endorsement is required to pull double or triple trailers?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement X"],"answer":2,"explanation":"Alaska assigns endorsement T (Double or Triple Trailers) for combinations pulling two or three trailers; only a knowledge test is required. Source: Alaska DMV CDL Manual, Section 1, Endorsements table.","handbook":"","hbref":""},{"q":"According to the Alaska CDL Manual, which endorsement is required for a vehicle designed to transport 16 or more passengers (including the driver)?","options":["Endorsement S","Endorsement P","Endorsement N","Endorsement H"],"answer":1,"explanation":"Alaska requires endorsement P (Passenger) for any vehicle designed to transport 16 or more passengers including the driver, regardless of how many are actually carried. It requires a knowledge and road skills test. Source: Alaska DMV CDL Manual, Section 1, Endorsements table.","handbook":"","hbref":""},{"q":"In Alaska, the X endorsement on a CDL represents what combination?","options":["Combined tanker and hazardous materials","Combined passenger and school bus","Combined doubles and triples","Combined air brakes and tanker"],"answer":0,"explanation":"Alaska uses endorsement X for a combo tanker/hazardous materials operation: any tank vehicle used to transport placardable amounts of hazardous materials. It requires a knowledge test and a background check. Source: Alaska DMV CDL Manual, Section 1, Endorsements table.","handbook":"","hbref":""},{"q":"Before Alaska will issue or renew a CDL with a hazardous materials (H) endorsement, the applicant must first complete which step?","options":["A defensive driving course","A Transportation Security Administration background check","A 30-day waiting period","A commercial vehicle inspection course"],"answer":1,"explanation":"The Alaska CDL Manual states that all applicants obtaining, adding, or renewing a HazMat endorsement must pass a background check prior to issuance, processed through TSA/universalenroll.dhs.gov. Source: Alaska DMV CDL Manual, Section 1, Endorsement H notes.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued an Alaska CDL restricted to intrastate (in-state only) commerce?","options":["16 years","17 years","18 years","21 years"],"answer":2,"explanation":"The Alaska CDL Manual states an applicant must be at least 18 years of age to operate in intrastate commerce (effective 11/14/19) at the time of application, and have held a valid driver license for at least one year. Source: Alaska DMV CDL Manual, Section 1, Age requirements.","handbook":"","hbref":""},{"q":"What minimum age does Alaska require for a CDL holder to operate in interstate commerce?","options":["18 years","19 years","20 years","21 years"],"answer":3,"explanation":"The Alaska CDL Manual states an applicant must be at least 21 years of age to operate in interstate commerce. Drivers under 21 receive a K (intrastate only) restriction. Source: Alaska DMV CDL Manual, Section 1, Age requirements and Restriction K.","handbook":"","hbref":""},{"q":"Under both federal rule and Alaska practice, how long must an applicant hold a Commercial Learner's Permit (CLP) before taking the CDL road skills test?","options":["At least 7 days","At least 10 days","At least 14 days","At least 30 days"],"answer":2,"explanation":"The Alaska CDL Manual states an applicant must hold a CLP for at least 14 days before taking a road skills test, including when upgrading class or adding an endorsement that requires a skills test. Source: Alaska DMV CDL Manual, Section 1, Testing and Issuance Requirements.","handbook":"","hbref":""},{"q":"Before obtaining an Alaska Commercial Learner's Permit, what must the applicant already hold?","options":["A current valid Alaska non-commercial driver license","A federal DOT operating authority number","A completed apprenticeship certificate","A prior CDL from another state"],"answer":0,"explanation":"The Alaska DMV CLP page requires applicants to have a current valid Alaska non-commercial driver license before being issued a CLP. Source: Alaska DMV Commercial Learner's Permit (CLP) page.","handbook":"","hbref":""},{"q":"While driving on an Alaska CLP, the accompanying licensed driver in the seat next to the permit holder must hold the proper class/endorsements and be at least what age?","options":["18 years old","19 years old","21 years old","25 years old"],"answer":2,"explanation":"Per the Alaska DMV CLP page, a CLP holder may operate only a vehicle of their class or smaller, with a valid licensed driver in the adjacent seat who is at least 21, holds the appropriate class and endorsements, and has been licensed for one year. Source: Alaska DMV Commercial Learner's Permit (CLP) page.","handbook":"","hbref":""},{"q":"A CLP holder in Alaska who has a Passenger (P) endorsement is subject to which restriction?","options":["May only drive empty passenger buses on private property","May carry no passengers in a CMV bus except specified examiners, trainees, and the accompanying CDL holder","May carry up to 8 passengers during daylight hours","May carry passengers only on intrastate routes"],"answer":1,"explanation":"The Alaska CDL Manual's P restriction states a CLP holder with a P endorsement is prohibited from carrying passengers in a CMV bus, other than federal/state auditors, inspectors, test examiners, other trainees, and the accompanying CDL holder (per 49 CFR 383.25). Source: Alaska DMV CDL Manual, Restriction P.","handbook":"","hbref":""},{"q":"A CLP holder in Alaska with an N (tanker) endorsement is limited by the X restriction to operating tank vehicles in what condition?","options":["Only empty tank vehicles, not those with unpurged hazmat residue","Only tank vehicles under 1,000 gallons","Only single-axle tank vehicles","Only tank vehicles on private roads"],"answer":0,"explanation":"The Alaska CDL Manual's X restriction states a permit holder with an N endorsement may only operate an empty tank vehicle and is prohibited from operating any tank vehicle that previously contained hazardous materials and has not been purged of residue. Source: Alaska DMV CDL Manual, Restriction X.","handbook":"","hbref":""},{"q":"Effective January 1, 2012, all Alaska CDL drivers must self-certify to one of how many types of CMV operation?","options":["Two","Three","Four","Five"],"answer":2,"explanation":"The Alaska CDL Manual lists four self-certification categories: non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate. Source: Alaska DMV CDL Manual, Medical Certificate and Self-Certification Requirements (49 CFR 383.71).","handbook":"","hbref":""},{"q":"If an Alaska CDL holder's medical examiner's certificate on file expires, how long does the state have before it must downgrade the CDL?","options":["Within 15 days of expiration","Within 30 days of expiration","Within 60 days of expiration","Within 90 days of expiration"],"answer":2,"explanation":"The Alaska CDL Manual states that, effective January 1, 2012, the state is required to downgrade any CDL holder with an expired medical certificate on file within 60 days of expiration. Source: Alaska DMV CDL Manual, Medical Certificate and Self-Certification Requirements.","handbook":"","hbref":""},{"q":"Under the federal ELDT rule applied in Alaska, a first-time applicant must complete Entry-Level Driver Training from a provider listed where before taking the skills test?","options":["The Alaska DMV's internal training database","The FMCSA Training Provider Registry","The state apprenticeship council list","The CDLIS national driver registry"],"answer":1,"explanation":"Alaska requires ELDT for first-time Class A or B applicants, upgrades, and new H/P/S endorsements; training must come from a provider listed on the FMCSA Training Provider Registry, which transmits completion to the DMV before the skills test. Source: Alaska DMV Entry-Level Driver Training (ELDT) page.","handbook":"","hbref":""},{"q":"Per Alaska statute/regulation (2 AAC 90.420), which document is specifically required to obtain a CDL along with birth and identity documents for anyone never before licensed in Alaska?","options":["A Social Security number","A passport card","A voter registration card","A vehicle title"],"answer":0,"explanation":"The Alaska CDL Manual cites 2 AAC 90.420(a): a Social Security number is required to obtain a CDL, along with birth and identity documents, for applicants never previously licensed in Alaska. Proof of Alaska domicile and lawful presence are also required. Source: Alaska DMV CDL Manual, Testing and Issuance Requirements; 2 AAC 90.420.","handbook":"","hbref":""},{"q":"In Alaska, at what blood alcohol concentration (BAC) is it illegal to operate a commercial motor vehicle (CMV)?","options":["0.04% or more","0.08% or more","0.02% or more","0.10% or more"],"answer":0,"explanation":"Alaska CDL Manual section 1.3.2 states it is illegal to operate a CMV if your BAC is .04% or more, half the 0.08% limit for non-commercial drivers. Source: Alaska DMV Commercial Driver License Manual, sec. 1.3.2.","handbook":"","hbref":""},{"q":"Under Alaska's implied consent law, what have you agreed to simply by operating a CMV in the state?","options":["To submit to a chemical test of your breath for alcohol","To allow a search of your cargo at any time","To pay all citation fines before leaving the scene","To carry a portable breath testing device in the cab"],"answer":0,"explanation":"The Alaska CDL Manual states that when you operate a CMV you have already consented to a chemical test of your breath, and you are 'deemed to have given your consent to alcohol testing.' Source: Alaska DMV CDL Manual, Implied Consent / sec. 1.3.2.","handbook":"","hbref":""},{"q":"An Alaska CDL holder commits a first major offense, such as driving a CMV with a BAC of 0.04% or higher. What is the minimum disqualification?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"Alaska disqualifies a driver for at least 1 year for a first major offense (DUI, refusal, leaving the scene, etc.). Source: Alaska DMV CDL Manual, secs. 1.3.2 and Major Disqualifying Offenses table (mirrors 49 CFR 383.51).","handbook":"","hbref":""},{"q":"If a first major offense occurs while the driver is operating a CMV placarded for hazardous materials, how long is the Alaska disqualification?","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"Alaska increases the first-major-offense disqualification to at least 3 years when the offense occurs in a CMV placarded for hazardous materials. Source: Alaska DMV CDL Manual, sec. 1.3.2 / Major Disqualifying Offenses table.","handbook":"","hbref":""},{"q":"What is the Alaska disqualification for a SECOND major offense (for example, a second DUI in a CMV)?","options":["Lifetime","10 years","3 years","5 years"],"answer":0,"explanation":"Alaska disqualifies a driver for life for a second major offense. Source: Alaska DMV CDL Manual, sec. 1.3.2 and Major Disqualifying Offenses table (49 CFR 383.51).","handbook":"","hbref":""},{"q":"Using a CMV to commit a felony involving the manufacture, distribution, or dispensing of a controlled substance carries what Alaska disqualification, even on a first offense?","options":["Lifetime, with no reinstatement","1 year","3 years","10 years"],"answer":0,"explanation":"The Alaska CDL Manual states you will lose your CDL for life if you use a CMV to commit a felony involving controlled substances. Source: Alaska DMV CDL Manual, sec. 1.3.2.","handbook":"","hbref":""},{"q":"Which of the following is listed as a MAJOR disqualifying offense in the Alaska CDL Manual?","options":["Leaving the scene of an accident involving a CMV","Following another vehicle too closely","Speeding 15 mph or more over the limit","An improper or erratic lane change"],"answer":0,"explanation":"Leaving the scene of an accident is a major offense (1 year / lifetime). The other three are serious traffic violations, not major offenses. Source: Alaska DMV CDL Manual, sec. 1.3.2 and 1.3.3.","handbook":"","hbref":""},{"q":"If you refuse to submit to alcohol testing in Alaska, what happens to your CDL for a first refusal?","options":["Disqualified for at least 1 year (3 years if hauling hazmat)","Disqualified for 90 days","A warning only; no disqualification","Disqualified for life"],"answer":0,"explanation":"Refusal is treated as a major offense: at least 1 year disqualification, or 3 years if transporting hazardous materials. Source: Alaska DMV CDL Manual, Implied Consent and sec. 1.3.2.","handbook":"","hbref":""},{"q":"Per the Alaska CDL Manual's implied-consent provision, what is the minimum disqualification for a second or subsequent refusal to submit to a chemical test?","options":["10 years","3 years","5 years","1 year"],"answer":0,"explanation":"The Alaska CDL Manual's implied-consent text states a second and subsequent refusal carries a minimum 10-year disqualification. Source: Alaska DMV CDL Manual, Implied Consent provision.","handbook":"","hbref":""},{"q":"What happens to an Alaska CMV driver found to have any detectable amount of alcohol below 0.04%?","options":["Placed out-of-service for 24 hours","Disqualified for 60 days","Disqualified for 1 year","Fined $500 with no out-of-service period"],"answer":0,"explanation":"The Alaska CDL Manual states you will be put out-of-service for 24 hours if you have any detectable amount of alcohol under .04%. Source: Alaska DMV CDL Manual, sec. 1.3.2.","handbook":"","hbref":""},{"q":"What is the minimum speed over the posted limit that counts as a SERIOUS traffic violation for an Alaska CDL holder?","options":["15 mph or more over the limit","10 mph or more over the limit","20 mph or more over the limit","5 mph or more over the limit"],"answer":0,"explanation":"Excessive speeding means 15 mph or more above the posted limit, a serious traffic violation. Source: Alaska DMV CDL Manual, sec. 1.3.3.","handbook":"","hbref":""},{"q":"How long is the Alaska disqualification for committing TWO serious traffic violations in a CMV within a three-year period?","options":["At least 60 days","At least 30 days","At least 120 days","At least 1 year"],"answer":0,"explanation":"Two serious traffic violations within 3 years results in disqualification of at least 60 days. Source: Alaska DMV CDL Manual, sec. 1.3.3 and Serious Disqualifying Offenses table.","handbook":"","hbref":""},{"q":"How long is the Alaska disqualification for THREE or more serious traffic violations in a CMV within a three-year period?","options":["At least 120 days","At least 60 days","At least 90 days","At least 1 year"],"answer":0,"explanation":"Three or more serious traffic violations within 3 years results in disqualification of at least 120 days. Source: Alaska DMV CDL Manual, sec. 1.3.3 and Serious Disqualifying Offenses table.","handbook":"","hbref":""},{"q":"Which of these is NOT listed as a serious traffic violation in the Alaska CDL Manual?","options":["Driving a CMV with a BAC of 0.04% or higher","Following a vehicle too closely","Improper or erratic lane changes","Driving a CMV without the proper class of CDL"],"answer":0,"explanation":"Driving with a BAC of 0.04% or higher is a MAJOR offense, not a serious traffic violation. The other three are serious traffic violations. Source: Alaska DMV CDL Manual, secs. 1.3.2 and 1.3.3.","handbook":"","hbref":""},{"q":"Under Alaska law (AS 28.33.190), texting or using a hand-held mobile phone while driving a CMV is classified as what?","options":["A serious traffic violation (use of an electronic device)","A major disqualifying offense","An out-of-service order violation","A non-reportable infraction"],"answer":0,"explanation":"Alaska lists 'use of an electronic device while driving' (AS 28.33.190(16)(H)) among serious disqualifying offenses, counting toward the 60-day/120-day thresholds. Source: Alaska DMV CDL Manual, Serious Disqualifying Offenses; AS 28.33.190.","handbook":"","hbref":""},{"q":"What is the maximum civil penalty a CMV driver may face for violating the hand-held mobile phone prohibition described in the Alaska CDL Manual?","options":["Up to $2,750","Up to $11,000","Up to $500","Up to $1,000"],"answer":0,"explanation":"Each hand-held phone violation is subject to a civil penalty of up to $2,750 on the driver; employers face up to $11,000. Source: Alaska DMV CDL Manual, sec. 2.9.4 (hand-held mobile telephones).","handbook":"","hbref":""},{"q":"What is the Alaska disqualification for a FIRST violation of an out-of-service (OOS) order while operating a CMV (no hazmat or passengers)?","options":["No less than 180 days and no more than 1 year","No less than 90 days and no more than 1 year","Exactly 60 days","No less than 2 years and no more than 5 years"],"answer":0,"explanation":"Alaska disqualifies a first OOS-order violation for not less than 180 days and not more than 1 year. Source: Alaska DMV CDL Manual, Violating Out-of-Service Orders table (AS 28.33.140(j)).","handbook":"","hbref":""},{"q":"How long is the Alaska disqualification for a FIRST out-of-service order violation committed while transporting hazardous materials or passengers?","options":["No less than 180 days and no more than 2 years","No less than 180 days and no more than 1 year","No less than 1 year and no more than 5 years","Exactly 120 days"],"answer":0,"explanation":"A first OOS-order violation while hauling hazmat or passengers is disqualified for not less than 180 days and not more than 2 years. Source: Alaska DMV CDL Manual, Violating Out-of-Service Orders table (AS 28.33.140(j)).","handbook":"","hbref":""},{"q":"What is the Alaska disqualification for a SECOND out-of-service order violation (non-hazmat) within a 10-year period?","options":["No less than 1 year and no more than 5 years","No less than 180 days and no more than 1 year","No less than 3 years and no more than 5 years","Lifetime"],"answer":0,"explanation":"A second OOS-order violation within 10 years carries not less than 1 year and not more than 5 years; with hazmat or passengers it is 3 to 5 years. Source: Alaska DMV CDL Manual, Violating Out-of-Service Orders table.","handbook":"","hbref":""},{"q":"For a FIRST railroad-highway grade crossing violation while operating a CMV, what is the Alaska disqualification?","options":["At least 60 days","At least 15 days","At least 120 days","At least 1 year"],"answer":0,"explanation":"Alaska disqualifies a first railroad-highway grade crossing violation for at least 60 days; a second within 3 years is 120 days, and a third within 3 years is 1 year. Source: Alaska DMV CDL Manual, sec. 1.3.5 / Railroad-Highway Grade Crossing Violations table.","handbook":"","hbref":""},{"q":"In Alaska, a bus or a vehicle carrying placarded hazardous materials must stop at a railroad-highway crossing within what distance of the nearest rail?","options":["Between 15 and 50 feet","Between 5 and 15 feet","Between 50 and 100 feet","Between 10 and 25 feet"],"answer":0,"explanation":"The Alaska CDL Manual (Sections 4.3.5 and 9.6.12) requires buses and placarded HazMat vehicles to stop no closer than 15 feet and no farther than 50 feet from the nearest rail, then look and listen before crossing.","handbook":"","hbref":""},{"q":"Under Alaska's Move Over law, when a driver approaches a stationary emergency vehicle displaying flashing lights on a road with two or more lanes in the same direction, the driver must:","options":["Vacate the lane closest to the emergency vehicle when it is safe to do so","Come to a complete stop until the emergency vehicle leaves","Sound the horn and continue at the posted speed","Pull onto the shoulder and wait three minutes"],"answer":0,"explanation":"Alaska Statute AS 28.35.185 requires drivers on a road with two or more lanes in the same direction to vacate the lane closest to a stationary emergency, fire, law enforcement, tow, maintenance, or animal-control vehicle with flashing lights, if it is safe to do so.","handbook":"","hbref":""},{"q":"When stopping for a school bus that has its red lights flashing, Alaska law requires an approaching driver to stop at least how far from the bus?","options":["30 feet","15 feet","20 feet","50 feet"],"answer":0,"explanation":"Alaska Statute AS 28.35.145 requires a driver approaching a school bus with flashing red lights to stop not less than 30 feet from the bus and not proceed until the lights stop flashing.","handbook":"","hbref":""},{"q":"On any roadway other than an alley, business district, or residential district, what is the maximum lawful speed for a commercial motor vehicle in Alaska unless otherwise posted?","options":["55 mph","65 mph","60 mph","70 mph"],"answer":0,"explanation":"Alaska Administrative Code 13 AAC 03.275 sets the maximum lawful speed for commercial motor vehicles at 55 mph on any other roadway (15 mph in an alley, 20 mph in a business district, 25 mph in a residential district).","handbook":"","hbref":""},{"q":"Alaska's school-bus stopping law contains an exception for divided highways. When is an approaching driver NOT required to stop for a school bus?","options":["When the bus is on a different roadway of a highway with separate roadways","When the driver is traveling at least 10 mph below the limit","When the bus is more than 100 feet away","When there are no children visible near the bus"],"answer":0,"explanation":"Under AS 28.35.145, a driver on a highway with separate roadways is not required to stop when meeting or passing a school bus that is on a different roadway (the divided-highway exception).","handbook":"","hbref":""},{"q":"After stopping a commercial vehicle on a one-way or divided highway in Alaska, at what locations must the driver place the three warning triangles?","options":["About 10 feet, 100 feet, and 200 feet toward approaching traffic","About 10 feet, 50 feet, and 150 feet toward approaching traffic","About 25 feet, 100 feet, and 250 feet toward approaching traffic","About 50 feet, 100 feet, and 500 feet toward approaching traffic"],"answer":0,"explanation":"Per the Alaska CDL Manual (Section 2.5), on a one-way or divided highway the warning devices are placed at 10 feet, 100 feet, and 200 feet from the vehicle toward the approaching traffic.","handbook":"","hbref":""},{"q":"A driver who violates Alaska's Move Over law (AS 28.35.185) and causes personal injury is guilty of what offense?","options":["A class A misdemeanor","An infraction only","A class B felony","A violation carrying no points"],"answer":0,"explanation":"AS 28.35.185(b) makes a Move Over violation a class A misdemeanor when personal injury results from the failure to vacate the lane or slow down; otherwise it is an infraction.","handbook":"","hbref":""},{"q":"On a two-lane road carrying traffic in both directions, where does the Alaska CDL Manual direct a driver to place warning triangles after stopping?","options":["Within 10 feet of the vehicle, and 100 feet behind and ahead of it","Within 25 feet of the vehicle, and 200 feet behind and ahead of it","Only 100 feet behind the vehicle","At 10, 100, and 200 feet behind the vehicle only"],"answer":0,"explanation":"The Alaska CDL Manual (Section 2.5) says on an undivided two-way road, place a triangle within 10 feet of the vehicle and one each 100 feet behind and ahead of it on the shoulder or in the lane.","handbook":"","hbref":""},{"q":"Which list of vehicles is required to make a mandatory stop before crossing railroad tracks under Alaska CDL rules?","options":["Placarded vehicles, any vehicle carrying chlorine, and cargo-tank vehicles used for hazardous materials","Only triple-trailer combinations","Only buses carrying more than 30 passengers","All vehicles over 26,000 pounds gross weight"],"answer":0,"explanation":"Alaska CDL Manual Section 9.6.12 lists the vehicles that must stop at railroad crossings: placarded vehicles, any vehicle carrying any amount of chlorine, and cargo-tank vehicles (loaded or empty) used for hazardous materials.","handbook":"","hbref":""},{"q":"How long after stopping on the road does an Alaska CDL driver have to put out the emergency warning devices?","options":["Within 10 minutes","Within 5 minutes","Within 15 minutes","Immediately, within 1 minute"],"answer":0,"explanation":"The Alaska CDL Manual (Section 2.5) states that if you must stop on or by a road, you must put out your emergency warning devices within 10 minutes.","handbook":"","hbref":""},{"q":"When an Alaska CDL driver must stop a commercial vehicle on the roadside, what are the three required warning devices?","options":["Three red reflective triangles, or 6 fusees, or 3 liquid-burning flares","Two red lanterns and one red flag","Four amber reflectors","One reflective triangle and two road flares"],"answer":0,"explanation":"The Alaska CDL Manual lists acceptable warning devices for parked vehicles as three red reflective triangles, at least 6 fusees, or 3 liquid-burning flares.","handbook":"","hbref":""},{"q":"A school-bus driver in Alaska who must stop at a railroad crossing should also do which of the following before crossing?","options":["Open the forward door if it improves the ability to see or hear an approaching train","Sound the horn three times","Have all passengers exit the bus first","Shift into a lower gear while on the tracks"],"answer":0,"explanation":"The Alaska CDL Manual (Section 4.3.5) instructs bus drivers to stop 15 to 50 feet before the crossing, look and listen both ways, and open the forward door if it improves the ability to see or hear a train.","handbook":"","hbref":""},{"q":"If a commercial vehicle is stopped on the roadside beyond a hill or curve that blocks other drivers' view within 500 feet, what should the Alaska CDL driver do with the warning triangles?","options":["Move the rearmost triangle back down the road so warning is provided beyond the obstruction","Place all three triangles directly behind the vehicle","Remove the triangles and rely on the four-way flashers only","Place a triangle on top of the cab"],"answer":0,"explanation":"The Alaska CDL Manual (Section 2.5) directs that if a hill, curve, or other obstruction blocks the line of sight within 500 feet, the driver should move the rearmost triangle back down the road so warning is provided.","handbook":"","hbref":""},{"q":"On a divided highway in Alaska, which approaching driver is exempt from stopping for a school bus loading children?","options":["A driver on the opposite roadway separated from the bus by a median or barrier","A driver directly behind the bus in the same lane","A driver passing the bus on the right shoulder","Any driver traveling under 20 mph"],"answer":0,"explanation":"AS 28.35.145's separate-roadways exception applies to drivers on the opposite roadway of a divided highway; drivers on the same roadway as the bus, including those behind it, must still stop.","handbook":"","hbref":""},{"q":"On a road with fewer than two lanes traveling in the same direction, what does Alaska's Move Over law require when a driver passes a stationary emergency vehicle with flashing lights?","options":["Slow to a reasonable and prudent speed given traffic, roadway, and weather","Maintain the posted speed limit exactly","Stop completely until signaled to proceed","Move fully onto the opposite shoulder"],"answer":0,"explanation":"AS 28.35.185 requires that where there are fewer than two lanes in the same direction, the driver must slow to a reasonable and prudent speed considering traffic, roadway, and weather conditions.","handbook":"","hbref":""},{"q":"While crossing railroad tracks in Alaska, a CDL driver should:","options":["Not shift gears while crossing the tracks","Downshift to first gear on the tracks for maximum control","Stop on the tracks if a train is not visible","Accelerate hard and shift up midway across"],"answer":0,"explanation":"The Alaska CDL Manual (Sections 2.15 and 9.6.12) warns drivers never to shift gears while crossing the tracks, because a missed shift could leave the vehicle stalled on the crossing.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle/load width in Alaska that may travel on a public highway without an oversize permit?","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","120 inches (10 feet)","108 inches (9 feet)"],"answer":0,"explanation":"Alaska's Oversize/Overweight Permit Manual references the 102-inch (8 feet 6 inches) legal width limitation of 17 AAC 25; anything wider requires a permit and OVERSIZE/WIDE LOAD signs.","handbook":"","hbref":""},{"q":"Under Alaska's oversize-permit rules, a wide load requires at least one pilot/escort vehicle on all routes once its width exceeds:","options":["10 feet 6 inches","8 feet 6 inches","12 feet","9 feet"],"answer":0,"explanation":"Alaska's Oversize/Overweight Permit Manual (Section 6.2.1) requires at least one pilot/escort vehicle on all routes when a vehicle or load exceeds 10 feet 6 inches in width.","handbook":"","hbref":""},{"q":"Under Alaska's permit rules, a load that exceeds 17 feet in height is restricted to what maximum highway speed (absent a more restrictive factor)?","options":["45 mph","55 mph","35 mph","25 mph"],"answer":0,"explanation":"Alaska's Oversize/Overweight Permit Manual (Section 9.3.1) limits loads over 17 feet in height to a maximum highway speed of 45 mph unless other factors are more restrictive.","handbook":"","hbref":""},{"q":"At an Alaska drawbridge with no signal light or attendant controlling traffic, where must a CDL driver stop?","options":["At least 50 feet before the draw of the bridge","At least 15 feet before the draw of the bridge","At least 100 feet before the draw of the bridge","Directly at the edge of the draw"],"answer":0,"explanation":"The Alaska CDL Manual (Section 4.3.6) requires stopping at least 50 feet before the draw of a drawbridge that has no signal light or traffic-control attendant, and verifying the draw is fully closed before crossing.","handbook":"","hbref":""},{"q":"Which Alaska state agency issues Commercial Driver Licenses (CDLs)?","options":["The Alaska Division of Motor Vehicles (DMV)","The Alaska Department of Public Safety","The Federal Motor Carrier Safety Administration (FMCSA)","The Alaska Department of Transportation and Public Facilities (DOT&PF)"],"answer":0,"explanation":"In Alaska, the Division of Motor Vehicles (DMV) is the State Driver Licensing Agency that issues CDLs and administers the knowledge and skills tests. FMCSA sets federal CDL standards but does not issue the license. Source: Alaska DMV, Commercial Driver's License (CDL) page.","handbook":"","hbref":""},{"q":"What minimum score must an applicant achieve to pass each Alaska CDL knowledge test?","options":["70%","75%","80%","90%"],"answer":2,"explanation":"Alaska requires a score of at least 80% to pass each CDL knowledge test (general knowledge and any endorsement tests). Source: Alaska DMV CDL Manual / Alaska DMV CDL requirements.","handbook":"","hbref":""},{"q":"The Alaska CDL skills test is divided into three parts. Which set correctly lists all three?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Vision screening, written knowledge, and on-road driving","Pre-trip inspection, air brake check, and parallel parking","Backing, coupling/uncoupling, and a timed maneuverability course"],"answer":0,"explanation":"Alaska's CDL skills test has three parts: the pre-trip (vehicle) inspection test, the basic vehicle control skills test, and the on-road driving test. Source: Alaska DMV CDL Manual.","handbook":"","hbref":""},{"q":"Who is responsible for supplying the vehicle used for the Alaska CDL on-road skills test?","options":["The applicant must provide a representative vehicle of the class and type they intend to drive","The DMV provides a standard test vehicle for all applicants","The FMCSA Training Provider Registry assigns a vehicle","The Alaska DOT&PF loans a vehicle from its motor pool"],"answer":0,"explanation":"The applicant must bring their own representative vehicle of the same class and type they plan to drive; the DMV office does not provide a test vehicle. Source: Alaska DMV CDL Manual / Alaska DMV CDL requirements.","handbook":"","hbref":""},{"q":"After being issued a Commercial Learner's Permit (CLP), how long must an Alaska applicant wait before taking the CDL skills (road) test?","options":["At least 14 days","At least 7 days","At least 30 days","There is no waiting period"],"answer":0,"explanation":"Alaska follows the federal rule requiring a CLP holder to wait at least 14 days after the CLP is issued before taking any road test for the CDL. Source: Alaska DMV CLP page (49 CFR 383.25).","handbook":"","hbref":""},{"q":"How long is an Alaska Commercial Learner's Permit (CLP) valid before it must be renewed?","options":["180 days","30 days","1 year","5 years"],"answer":0,"explanation":"An Alaska CLP is valid for 180 days and may be renewed (reissued) one time for an additional 180 days without retaking the general knowledge test. Source: Alaska DMV CLP information (49 CFR 383.25).","handbook":"","hbref":""},{"q":"How many times may an Alaska CLP be renewed/reissued for an additional 180-day period under the federal standard Alaska follows?","options":["One time","It cannot be renewed at all","Two times","An unlimited number of times"],"answer":0,"explanation":"A CLP is valid for 180 days and may be renewed once for an additional 180 days (a maximum of 360 days total). Source: Alaska DMV CLP information (49 CFR 383.25).","handbook":"","hbref":""},{"q":"Before a first-time applicant can take the Alaska CDL skills test for a Class A or Class B license, what training must be completed?","options":["Entry-Level Driver Training (ELDT) from a provider listed on the FMCSA Training Provider Registry","A defensive-driving course approved by the Alaska Court System","A 40-hour Alaska winter-driving certification","An apprenticeship registered with the Alaska Department of Labor"],"answer":0,"explanation":"Since February 7, 2022, first-time CDL applicants must complete Entry-Level Driver Training (ELDT) from a provider on the FMCSA Training Provider Registry before taking the skills test; the state must verify the record was submitted. Source: FMCSA ELDT rule (49 CFR Part 380), applied by Alaska DMV.","handbook":"","hbref":""},{"q":"CDL self-certification in Alaska requires a driver to declare which type of operation they expect to perform. How many self-certification categories are there?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"Drivers must self-certify into one of four categories formed by combining interstate/intrastate with excepted/non-excepted operation. Source: Alaska DMV CDL Self-Certification Requirement page.","handbook":"","hbref":""},{"q":"Which of the following is one of the four Alaska CDL self-certification categories?","options":["Interstate non-excepted","Interstate seasonal","Intrastate hazardous-only","Federal exempt carrier"],"answer":0,"explanation":"The four categories are interstate non-excepted, interstate excepted, intrastate non-excepted, and intrastate excepted. \"Interstate non-excepted\" is the category for drivers who must meet federal DOT medical-card requirements. Source: Alaska DMV CDL Self-Certification Requirement page.","handbook":"","hbref":""},{"q":"An Alaska driver who self-certifies as \"non-excepted\" (interstate or intrastate) must provide which document to the DMV?","options":["A valid DOT medical examiner's certificate (medical card)","A notarized employer sponsorship letter","A signed waiver of federal medical standards","An Alaska commercial vehicle inspection sticker"],"answer":0,"explanation":"Non-excepted drivers must hold and submit a valid DOT medical examiner's certificate (medical card) to keep CDL privileges; excepted drivers are not required to submit one. Source: Alaska DMV CDL Self-Certification Requirement page.","handbook":"","hbref":""},{"q":"How may an Alaska CDL holder submit their self-certification and DOT medical examiner's certificate to the DMV?","options":["Complete Form 413 and present or email a legible copy of the medical card to the DMV's CDL email address","Upload the card to the FMCSA Training Provider Registry only","Mail the original card directly to FMCSA in Washington, D.C.","File it with the Alaska Department of Labor and Workforce Development"],"answer":0,"explanation":"Drivers complete the self-certification (Form 413) with each application and present the medical card at a DMV office or email a legible copy to the DMV's CDL address (doa.dmv.cdl@alaska.gov). Source: Alaska DMV CDL Self-Certification Requirement page.","handbook":"","hbref":""},{"q":"What is the consequence in Alaska if a non-excepted CDL holder fails to keep a current DOT medical examiner's certificate on file with the DMV?","options":["The CDL privileges are downgraded or cancelled","A one-time $500 federal penalty is assessed but the CDL stays valid","Nothing, because the medical card is filed only with the employer","The driver is automatically reclassified as an excepted intrastate driver"],"answer":0,"explanation":"If a non-excepted driver's medical certification lapses, Alaska DMV cancels or downgrades the CDL privileges; operating a CMV afterward is driving without proper privileges. Source: Alaska DMV CDL Self-Certification Requirement page.","handbook":"","hbref":""},{"q":"How long is an Alaska CDL valid before it must be renewed?","options":["5 years","4 years","8 years","2 years"],"answer":0,"explanation":"An Alaska CDL is valid for 5 years and expires on the holder's birthday. Source: Alaska DMV renewal information.","handbook":"","hbref":""},{"q":"On what date does an Alaska CDL typically expire within its renewal year?","options":["On the holder's birthday","On December 31","Exactly five years from the issue date regardless of birthday","On the last day of the issue month"],"answer":0,"explanation":"Alaska driver licenses, including CDLs, are issued for 5 years and expire on the holder's birthday. Source: Alaska DMV renewal information.","handbook":"","hbref":""},{"q":"How early before expiration may an Alaska CDL holder begin the renewal process?","options":["Up to 1 year before expiration","Up to 30 days before expiration","Only on the expiration date","Up to 6 months after expiration"],"answer":0,"explanation":"Alaska allows CDL renewal to begin as early as one year before the license expires; the state offers no grace period for an already-expired license. Source: Alaska DMV renewal information.","handbook":"","hbref":""},{"q":"Which document set is required when applying for an original Alaska CDL?","options":["Proof of U.S. citizenship/legal presence, an Alaska residence/domicile address, a Social Security Number, and a DOT medical card when applicable","Only a current out-of-state CDL and a passport photo","A vehicle title, proof of insurance, and an Alaska fishing license","An FMCSA carrier number and a notarized affidavit only"],"answer":0,"explanation":"Alaska requires proof of citizenship/legal presence, proof of an Alaska residence address (domicile), a Social Security Number, a current driver license, and a DOT medical card when applicable. Source: Alaska DMV Commercial Driver's License (CDL) page.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Alaska CDL restricted to intrastate (within-Alaska) operation?","options":["18 years old","16 years old","21 years old","25 years old"],"answer":0,"explanation":"The minimum age for an Alaska CDL is 18 for intrastate operation; interstate operation, hazmat, and school bus endorsements require age 21. Source: Alaska DMV CDL / CLP pages.","handbook":"","hbref":""},{"q":"A driver who wants to operate in interstate commerce or carry hazardous materials must be at least what age to hold an Alaska CDL for that operation?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"Alaska requires a driver to be at least 21 to operate interstate or to hold a hazmat or school bus endorsement, while intrastate-only CDLs are available at 18. Source: Alaska DMV CDL / CLP pages.","handbook":"","hbref":""},{"q":"Regarding Alaska CDL application fees, which statement is accurate about how the process works?","options":["Applicable CDL and road-test fees are paid to the DMV at application, and exact amounts are set by the state and can change over time","Alaska charges no fee for an original CDL","All CDL fees are paid directly to FMCSA, not the DMV","The road-test fee is fully refundable if the applicant fails"],"answer":0,"explanation":"Alaska CDL applicants pay the applicable license and road-test fees to the DMV at the time of application; specific dollar amounts are set by the state and are subject to change, so process (not a fixed amount) is the reliable point. Source: Alaska DMV CDL page / fee schedule.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова на Аляске максимальная допустимая ширина транспортного средства, включая груз, на дорогах сети штата?","options":["102 inches","96 inches","108 inches","114 inches"],"explanation":"На Аляске максимальная ширина транспортного средства, включая груз, установлена в 102 inches; закрепленное оборудование может выступать не более чем на 3 inches за этот предел с каждой стороны. Источник: 17 AAC 25.012(a) (Alaska DOT&PF, Chapter 25 Operations, Wheeled Vehicles), в соответствии с Alaska CDL Manual."},"1":{"q":"Какова общая максимальная допустимая высота транспортного средства с грузом на большинстве дорог Аляски?","options":["15 feet","13 feet 6 inches","14 feet","16 feet"],"explanation":"Согласно 17 AAC 25.012(b), транспортное средство на Аляске вместе с грузом не может превышать 15 feet в высоту, за исключением коридора Dalton/Elliott Highway между Fox Weigh Station и Prudhoe Bay, где разрешается 17 feet. Источник: 17 AAC 25.012(b), Alaska DOT&PF."},"2":{"q":"На Dalton и Elliott Highways между Fox Weigh Station и Prudhoe Bay какая увеличенная высота разрешена для транспортного средства с грузом?","options":["15 feet 6 inches","16 feet","17 feet","18 feet"],"explanation":"17 AAC 25.012(b) разрешает высоту, включая груз, в 17 feet для транспортного средства, движущегося между Fox Weigh Station и Prudhoe Bay по Dalton и Elliott Highways, по сравнению с общим пределом в 15 feet. Источник: 17 AAC 25.012(b), Alaska DOT&PF."},"3":{"q":"На маршрутах National Highway System Аляски какова максимальная длина одиночного тягового транспортного средства (самого грузовика или седельного тягача)?","options":["40 feet","48 feet","53 feet","45 feet"],"explanation":"17 AAC 25.012(c)(1) ограничивает длину тягового транспортного средства 45 feet на маршрутах NHS (а 17 AAC 25.012(d)(1) устанавливает тот же предел в 45 feet на остальной части дорожной сети штата). Источник: 17 AAC 25.012, Alaska DOT&PF."},"4":{"q":"Какова на Аляске максимальная грузонесущая длина полуприцепа или прицепа, используемого в составе автопоезда?","options":["48 feet","57 feet","60 feet","53 feet"],"explanation":"17 AAC 25.012(c)(3) и (e)(1) ограничивают грузонесущую длину полуприцепа или прицепа 53 feet на всех маршрутах. Источник: 17 AAC 25.012, Alaska DOT&PF."},"5":{"q":"Какова максимальная общая длина стандартного автопоезда, состоящего из грузовика и одного грузонесущего звена, или седельного тягача и двух грузонесущих звеньев, на дорогах Аляски?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"17 AAC 25.012(c)(4) и (d)(3) ограничивают такие автопоезда общей длиной в 75 feet; седельный тягач с одним грузонесущим звеном не подпадает под ограничение общей длины. Источник: 17 AAC 25.012, Alaska DOT&PF."},"6":{"q":"На Аляске на сколько груз или оборудование может выступать за передний бампер транспортного средства, не превышая допустимый предел?","options":["3 feet","4 feet","5 feet","6 feet"],"explanation":"17 AAC 25.012(c)(6) и (d)(4) разрешают грузу или оборудованию выступать не более чем на 3 feet за передний бампер (и не более чем на 4 feet за заднюю часть). Источник: 17 AAC 25.012, Alaska DOT&PF."},"7":{"q":"На Аляске на сколько груз может выступать за заднюю часть транспортного средства, не превышая допустимый предел?","options":["3 feet","5 feet","6 feet","4 feet"],"explanation":"17 AAC 25.012(c)(6)(B) и (d)(4)(B) допускают задний свес не более чем на 4 feet (передний свес ограничен 3 feet). Источник: 17 AAC 25.012, Alaska DOT&PF."},"8":{"q":"Какова максимальная допустимая нагрузка на одиночную ось на Аляске?","options":["18,000 pounds","22,400 pounds","34,000 pounds","20,000 pounds"],"explanation":"17 AAC 25.013(a)(4) устанавливает предел нагрузки на одиночную ось в 20,000 pounds при минимальном расстоянии 8'1\" для того, чтобы ось считалась одиночной. Источник: 17 AAC 25.013, Alaska DOT&PF."},"9":{"q":"Согласно таблице осевых групп Аляски, какова максимальная нагрузка, допустимая для группы из 2 осей (сдвоенной оси)?","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"explanation":"Таблица весов осевых групп Аляски в 17 AAC 25.013(a)(4) допускает 38,000 pounds на группу из 2 осей (сдвоенную), что выше федерального стандарта в 34,000 pounds для сдвоенной оси, используемого во многих штатах. Источник: 17 AAC 25.013, Alaska DOT&PF."},"10":{"q":"Согласно таблице весов осевых групп Аляски, какова максимальная нагрузка, допустимая для группы из 3 осей?","options":["38,000 pounds","46,000 pounds","50,000 pounds","42,000 pounds"],"explanation":"17 AAC 25.013(a)(4) допускает 42,000 pounds на группу из 3 осей (при минимальном расстоянии между осями 3'6\"). Источник: 17 AAC 25.013, Alaska DOT&PF."},"11":{"q":"Какое минимальное расстояние между осями должно соблюдаться, чтобы ось на Аляске считалась 'одиночной осью', а не частью осевой группы?","options":["8 feet 1 inch","3 feet 6 inches","6 feet","10 feet"],"explanation":"Согласно примечанию к 17 AAC 25.013(a)(4), любая ось, расположенная менее чем в 8 feet 1 inch от другой оси (от центра к центру), считается частью осевой группы; предел для одиночной оси применяется при минимальном расстоянии 8'1\". Источник: 17 AAC 25.013, Alaska DOT&PF."},"12":{"q":"Как Аляска определяет максимальную полную массу транспортного средства для длинного автопоезда?","options":["Единый предел в 80,000 pounds на всех дорогах","Умножением количества осей на 20,000 pounds","Применением Bridge Gross Weight Formula штата на основе количества осей и расстояния между ними","Фиксированным пределом в 105,500 pounds, установленным законом"],"explanation":"17 AAC 25.013(a)(6) определяет максимальную полную массу по Bridge Gross Weight Formula W = 500[LN/(N-1) + 12N + 36] (с добавлением +3,000, когда в ведущей группе нет подъемных осей), а не по единому пределу в 80,000 pounds. Источник: 17 AAC 25.013, Alaska DOT&PF."},"13":{"q":"В Bridge Gross Weight Formula Аляски W = 500[LN/(N-1) + 12N + 36] что обозначает переменная 'L'?","options":["Допустимую массу груза в тоннах","Расстояние в feet между центрами крайних осей","Длину самого длинного прицепа","Грузоподъемность подъемной оси"],"explanation":"В 17 AAC 25.013(a)(6) 'L' — это расстояние в целых feet, измеренное между центрами крайних осей транспортного средства или автопоезда, а 'N' — это количество осей. Источник: 17 AAC 25.013, Alaska DOT&PF."},"14":{"q":"Какова максимальная допустимая нагрузка на шину на Аляске, исходя из номинальной ширины шины по данным производителя?","options":["600 pounds на каждый inch ширины шины","500 pounds на каждый inch ширины шины","550 pounds на каждый inch ширины шины","650 pounds на каждый inch ширины шины"],"explanation":"17 AAC 25.013(a)(1) ограничивает нагрузку на шину 600 pounds на каждый линейный inch ширины шины, исходя из указанной производителем номинальной ширины шины. Источник: 17 AAC 25.013, Alaska DOT&PF."},"15":{"q":"Когда требуется разрешение Alaska DOT&PF на негабаритный/перевесный груз?","options":["Только для грузов с полной массой более 100,000 pounds","Когда транспортное средство или груз превышает максимальные габариты или массу по 17 AAC 25 и будет двигаться по дороге общего пользования","Только при пересечении границы штата в Канаду","Только для транспортных средств шире 12 feet"],"explanation":"Согласно Administrative Permit Manual (Sec. 2.2.1) и 17 AAC 25.320, разрешение требуется всякий раз, когда транспортное средство или транспортное средство с грузом превышает максимальные габариты или массу по 17 AAC 25 и запрашивает движение по дороге общего пользования. Источник: Alaska DOT&PF Administrative Permit Manual; 17 AAC 25.320."},"16":{"q":"Аляска выдает разрешения на негабаритный/перевесный груз только для грузов, которые относятся к какому из следующих типов?","options":["Делимые грузы, которые можно разделить на части в пределах нормы","Неделимые грузы, которые невозможно уменьшить до допустимых габаритов или массы","Грузы, принадлежащие государственным учреждениям","Грузы с опасными материалами"],"explanation":"Разрешения на Аляске выдаются для неделимых грузов (тех, которые невозможно практически уменьшить до допустимых габаритов/массы); делимые грузы должны быть разбиты до допустимых пределов. Источник: Alaska DOT&PF Administrative Permit Manual Sec. 2.2 и 17 AAC 25.320(a)(1)."},"17":{"q":"Каков на Аляске стандартный срок действия разрешения на один рейс для негабаритного/перевесного груза (для перевозки в одну сторону на 400 миль или менее)?","options":["1 день","3 дня","7 дней","30 дней"],"explanation":"Согласно Administrative Permit Manual Sec. 3.2.1, разрешение на один рейс действительно в течение 3-дневного периода (продлевается до 5 дней при движении более чем на 400 миль в одну сторону). Источник: Alaska DOT&PF Administrative Permit Manual."},"18":{"q":"В зимние месяцы на Аляске какая дополнительная надбавка к полной массе может быть предоставлена при документально подтвержденном налипании снега и льда на транспортном средстве?","options":["500 pounds","1,000 pounds","1,500 pounds","2,000 pounds"],"explanation":"17 AAC 25.335(b)(1) предоставляет дополнительную надбавку в 1,500 pounds с 1 октября по 30 апреля при наличии признаков налипания снега и льда; это максимум независимо от типа автопоезда. Источник: 17 AAC 25.335, Alaska DOT&PF."},"19":{"q":"Какой класс CDL требует Аляска для управления одиночным транспортным средством с полной разрешенной массой (GVWR) 26,001 pounds или более, например самосвалом или туристическим автобусом?","options":["Class A","Class B","Class C","Class D"],"explanation":"Alaska CDL Manual определяет Class B как любое одиночное транспортное средство с GVWR свыше 26,001 pounds или такое транспортное средство, буксирующее звено массой менее 10,000 lbs (самосвалы, бетономешалки, фургоны, туристические автобусы). Источник: Alaska DMV CDL Manual, Section 1, Vehicle Classifications."},"20":{"q":"Согласно Alaska CDL Manual, Class A CDL требуется для любого автопоезда с GCWR 26,001 lbs или более при условии, что GVWR буксируемого звена (звеньев) превышает какую массу?","options":["8,000 pounds","10,000 pounds","16,000 pounds","26,001 pounds"],"explanation":"Аляска определяет Class A как автопоезд с GCWR 26,001+ lbs, где GVWR буксируемого транспортного средства (средств) превышает 10,000 pounds (например, фуры, лесовозы). Источник: Alaska DMV CDL Manual, Section 1, определение Class A."},"21":{"q":"По правилам Аляски транспортное средство с GVWR менее 26,001 lbs все равно подпадает под программу CDL (Class C), если оно рассчитано на перевозку какого количества пассажиров, включая водителя?","options":["8 или более","11 или более","15 или более","16 или более"],"explanation":"Alaska CDL Manual включает меньшее транспортное средство в программу CDL как Class C, если оно рассчитано на перевозку 16 или более пассажиров, включая водителя, или перевозит опасные материалы, требующие установки знаков (placard). Источник: Alaska DMV CDL Manual, Section 1, определение Class C."},"22":{"q":"На Аляске какая буква эндорсмента проставляется на CDL для перевозки опасных материалов в количествах, требующих установки знаков (placard)?","options":["Endorsement H","Endorsement N","Endorsement X","Endorsement T"],"explanation":"Аляска использует эндорсмент H (Hazardous Materials) для любого транспортного средства, используемого для перевозки опасных материалов в количествах, требующих установки знаков. Источник: Alaska DMV CDL Manual, Section 1, таблица Endorsements."},"23":{"q":"Какой эндорсмент требует Аляска для любого транспортного средства, предназначенного для перевозки жидкостей наливом (автоцистерн)?","options":["Endorsement H","Endorsement N","Endorsement P","Endorsement T"],"explanation":"Alaska CDL Manual указывает эндорсмент N (Tanker) для любого транспортного средства, предназначенного для перевозки жидкостей наливом. Обратите внимание, что на Аляске кодовая буква для эндорсмента цистерны — N. Источник: Alaska DMV CDL Manual, Section 1, таблица Endorsements."},"24":{"q":"Какой эндорсмент CDL Аляски требуется для буксировки двойных или тройных прицепов?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement X"],"explanation":"Аляска присваивает эндорсмент T (Double or Triple Trailers) для автопоездов, буксирующих два или три прицепа; требуется только теоретический экзамен. Источник: Alaska DMV CDL Manual, Section 1, таблица Endorsements."},"25":{"q":"Согласно Alaska CDL Manual, какой эндорсмент требуется для транспортного средства, рассчитанного на перевозку 16 или более пассажиров (включая водителя)?","options":["Endorsement S","Endorsement P","Endorsement N","Endorsement H"],"explanation":"Аляска требует эндорсмент P (Passenger) для любого транспортного средства, рассчитанного на перевозку 16 или более пассажиров, включая водителя, независимо от того, сколько фактически перевозится. Требуется теоретический экзамен и экзамен по вождению. Источник: Alaska DMV CDL Manual, Section 1, таблица Endorsements."},"26":{"q":"На Аляске эндорсмент X на CDL обозначает какую комбинацию?","options":["Совмещенные цистерну и опасные материалы","Совмещенные пассажирский и школьный автобус","Совмещенные двойные и тройные прицепы","Совмещенные пневматические тормоза и цистерну"],"explanation":"Аляска использует эндорсмент X для совмещенной операции цистерна/опасные материалы: любое цистерновое транспортное средство, используемое для перевозки опасных материалов в количествах, требующих установки знаков. Требуется теоретический экзамен и проверка биографических данных. Источник: Alaska DMV CDL Manual, Section 1, таблица Endorsements."},"27":{"q":"Прежде чем Аляска выдаст или продлит CDL с эндорсментом на опасные материалы (H), заявитель должен сначала выполнить какой шаг?","options":["Курс безопасного вождения","Проверку биографических данных в Transportation Security Administration","30-дневный период ожидания","Курс по осмотру коммерческих транспортных средств"],"explanation":"Alaska CDL Manual указывает, что все заявители, получающие, добавляющие или продлевающие эндорсмент HazMat, должны пройти проверку биографических данных до выдачи, проводимую через TSA/universalenroll.dhs.gov. Источник: Alaska DMV CDL Manual, Section 1, примечания к Endorsement H."},"28":{"q":"Каков минимальный возраст для выдачи CDL Аляски с ограничением на внутриштатные (только в пределах штата) перевозки?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"Alaska CDL Manual указывает, что заявитель должен быть не моложе 18 лет для работы во внутриштатных перевозках (вступило в силу 11/14/19) на момент подачи заявления и иметь действующее водительское удостоверение не менее одного года. Источник: Alaska DMV CDL Manual, Section 1, требования к возрасту."},"29":{"q":"Какой минимальный возраст требует Аляска для держателя CDL для работы в межштатных перевозках?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Alaska CDL Manual указывает, что заявитель должен быть не моложе 21 года для работы в межштатных перевозках. Водители младше 21 года получают ограничение K (только внутриштатные). Источник: Alaska DMV CDL Manual, Section 1, требования к возрасту и Restriction K."},"30":{"q":"Согласно как федеральному правилу, так и практике Аляски, как долго заявитель должен иметь Commercial Learner's Permit (CLP) перед сдачей экзамена по вождению на CDL?","options":["Не менее 7 дней","Не менее 10 дней","Не менее 14 дней","Не менее 30 дней"],"explanation":"Alaska CDL Manual указывает, что заявитель должен иметь CLP не менее 14 дней перед сдачей экзамена по вождению, в том числе при повышении класса или добавлении эндорсмента, требующего экзамена по вождению. Источник: Alaska DMV CDL Manual, Section 1, Testing and Issuance Requirements."},"31":{"q":"Прежде чем получить Commercial Learner's Permit Аляски, что заявитель уже должен иметь?","options":["Действующее некоммерческое водительское удостоверение Аляски","Федеральный номер операторских полномочий DOT","Завершенный сертификат ученичества","Ранее выданный CDL из другого штата"],"explanation":"Страница Alaska DMV CLP требует, чтобы заявители имели действующее некоммерческое водительское удостоверение Аляски перед выдачей CLP. Источник: страница Alaska DMV Commercial Learner's Permit (CLP)."},"32":{"q":"При вождении по CLP Аляски сопровождающий лицензированный водитель на сиденье рядом с держателем разрешения должен иметь надлежащий класс/эндорсменты и быть не моложе какого возраста?","options":["18 лет","19 лет","21 год","25 лет"],"explanation":"Согласно странице Alaska DMV CLP, держатель CLP может управлять только транспортным средством своего класса или меньше, при наличии действующего лицензированного водителя на соседнем сиденье, которому не менее 21 года, который имеет соответствующий класс и эндорсменты и имеет лицензию не менее одного года. Источник: страница Alaska DMV Commercial Learner's Permit (CLP)."},"33":{"q":"Держатель CLP на Аляске, имеющий эндорсмент Passenger (P), подпадает под какое ограничение?","options":["Может управлять только пустыми пассажирскими автобусами на частной территории","Не может перевозить пассажиров в автобусе CMV, кроме указанных экзаменаторов, обучающихся и сопровождающего держателя CDL","Может перевозить до 8 пассажиров в светлое время суток","Может перевозить пассажиров только на внутриштатных маршрутах"],"explanation":"Ограничение P в Alaska CDL Manual указывает, что держателю CLP с эндорсментом P запрещено перевозить пассажиров в автобусе CMV, кроме федеральных/штатных аудиторов, инспекторов, экзаменаторов, других обучающихся и сопровождающего держателя CDL (согласно 49 CFR 383.25). Источник: Alaska DMV CDL Manual, Restriction P."},"34":{"q":"Держатель CLP на Аляске с эндорсментом N (цистерна) ограничен ограничением X управлением цистерновыми транспортными средствами в каком состоянии?","options":["Только пустыми цистерновыми транспортными средствами, не теми, что содержат неочищенные остатки опасных материалов","Только цистерновыми транспортными средствами объемом менее 1,000 галлонов","Только одноосными цистерновыми транспортными средствами","Только цистерновыми транспортными средствами на частных дорогах"],"explanation":"Ограничение X в Alaska CDL Manual указывает, что держатель разрешения с эндорсментом N может управлять только пустым цистерновым транспортным средством, и ему запрещено управлять любым цистерновым транспортным средством, которое ранее содержало опасные материалы и не было очищено от остатков. Источник: Alaska DMV CDL Manual, Restriction X."},"35":{"q":"С 1 января 2012 года все водители CDL Аляски должны самостоятельно подтвердить (self-certify) один из скольких типов работы CMV?","options":["Два","Три","Четыре","Пять"],"explanation":"Alaska CDL Manual перечисляет четыре категории самосертификации: non-excepted interstate, excepted interstate, non-excepted intrastate и excepted intrastate. Источник: Alaska DMV CDL Manual, Medical Certificate and Self-Certification Requirements (49 CFR 383.71)."},"36":{"q":"Если хранящаяся медицинская справка (medical examiner's certificate) держателя CDL Аляски истекает, сколько времени есть у штата, прежде чем он должен понизить класс CDL (downgrade)?","options":["В течение 15 дней после истечения срока","В течение 30 дней после истечения срока","В течение 60 дней после истечения срока","В течение 90 дней после истечения срока"],"explanation":"Alaska CDL Manual указывает, что с 1 января 2012 года штат обязан понизить класс любого держателя CDL с истекшей медицинской справкой в течение 60 дней после истечения срока. Источник: Alaska DMV CDL Manual, Medical Certificate and Self-Certification Requirements."},"37":{"q":"Согласно федеральному правилу ELDT, применяемому на Аляске, заявитель, обращающийся впервые, должен пройти Entry-Level Driver Training у поставщика, указанного где, перед сдачей экзамена по вождению?","options":["Во внутренней учебной базе данных Alaska DMV","В FMCSA Training Provider Registry","В списке совета по ученичеству штата","В национальном реестре водителей CDLIS"],"explanation":"Аляска требует ELDT для впервые обращающихся заявителей Class A или B, при повышении класса и для новых эндорсментов H/P/S; обучение должно проводиться поставщиком, указанным в FMCSA Training Provider Registry, который передает данные о завершении обучения в DMV перед экзаменом по вождению. Источник: страница Alaska DMV Entry-Level Driver Training (ELDT)."},"38":{"q":"Согласно закону/нормативному акту Аляски (2 AAC 90.420), какой документ конкретно требуется для получения CDL наряду с документами о рождении и удостоверением личности для любого, кто никогда ранее не получал лицензию на Аляске?","options":["Номер Social Security","Карта-паспорт (passport card)","Карта регистрации избирателя","Свидетельство о праве собственности на транспортное средство"],"explanation":"Alaska CDL Manual ссылается на 2 AAC 90.420(a): для получения CDL требуется номер Social Security наряду с документами о рождении и удостоверением личности для заявителей, никогда ранее не получавших лицензию на Аляске. Также требуются подтверждение проживания на Аляске (domicile) и законного пребывания. Источник: Alaska DMV CDL Manual, Testing and Issuance Requirements; 2 AAC 90.420."},"39":{"q":"На Аляске при какой концентрации алкоголя в крови (BAC) запрещено управлять коммерческим транспортным средством (CMV)?","options":["0.04% или более","0.08% или более","0.02% или более","0.10% или более"],"explanation":"Раздел 1.3.2 Alaska CDL Manual гласит, что управлять CMV запрещено, если ваш BAC составляет .04% или более — это половина предела в 0.08% для некоммерческих водителей. Источник: Alaska DMV Commercial Driver License Manual, sec. 1.3.2."},"40":{"q":"Согласно закону Аляски о подразумеваемом согласии (implied consent), на что вы согласились просто управляя CMV в штате?","options":["Пройти химический тест выдыхаемого воздуха на алкоголь","Разрешить досмотр вашего груза в любое время","Оплатить все штрафы по протоколу до выезда с места","Возить в кабине портативный прибор для проверки дыхания"],"explanation":"Alaska CDL Manual гласит, что управляя CMV вы уже дали согласие на химический тест выдыхаемого воздуха и 'считается, что вы дали согласие на проверку на алкоголь'. Источник: Alaska DMV CDL Manual, Implied Consent / sec. 1.3.2."},"41":{"q":"Держатель CDL Аляски совершает первое тяжкое нарушение (major offense), например управление CMV с BAC 0.04% или выше. Какова минимальная дисквалификация?","options":["1 год","60 дней","6 месяцев","3 года"],"explanation":"Аляска дисквалифицирует водителя не менее чем на 1 год за первое тяжкое нарушение (DUI, отказ, оставление места происшествия и т. д.). Источник: Alaska DMV CDL Manual, sec. 1.3.2 и таблица Major Disqualifying Offenses (соответствует 49 CFR 383.51)."},"42":{"q":"Если первое тяжкое нарушение совершено во время управления водителем CMV, имеющим знаки (placard) опасных материалов, какова продолжительность дисквалификации на Аляске?","options":["3 года","1 год","5 лет","Пожизненно"],"explanation":"Аляска увеличивает дисквалификацию за первое тяжкое нарушение до не менее чем 3 лет, когда нарушение совершено в CMV со знаками опасных материалов. Источник: Alaska DMV CDL Manual, sec. 1.3.2 / таблица Major Disqualifying Offenses."},"43":{"q":"Какова дисквалификация на Аляске за ВТОРОЕ тяжкое нарушение (например, второй DUI в CMV)?","options":["Пожизненно","10 лет","3 года","5 лет"],"explanation":"Аляска дисквалифицирует водителя пожизненно за второе тяжкое нарушение. Источник: Alaska DMV CDL Manual, sec. 1.3.2 и таблица Major Disqualifying Offenses (49 CFR 383.51)."},"44":{"q":"Использование CMV для совершения тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества, влечет какую дисквалификацию на Аляске, даже при первом нарушении?","options":["Пожизненно, без восстановления","1 год","3 года","10 лет"],"explanation":"Alaska CDL Manual гласит, что вы лишитесь CDL пожизненно, если используете CMV для совершения тяжкого преступления, связанного с контролируемыми веществами. Источник: Alaska DMV CDL Manual, sec. 1.3.2."},"45":{"q":"Что из перечисленного указано как ТЯЖКОЕ дисквалифицирующее нарушение в Alaska CDL Manual?","options":["Оставление места ДТП с участием CMV","Движение слишком близко за другим транспортным средством","Превышение скорости на 15 mph или более сверх лимита","Неправильная или беспорядочная смена полосы движения"],"explanation":"Оставление места ДТП является тяжким нарушением (1 год / пожизненно). Остальные три — серьезные нарушения правил дорожного движения, а не тяжкие нарушения. Источник: Alaska DMV CDL Manual, sec. 1.3.2 и 1.3.3."},"46":{"q":"Если вы откажетесь пройти проверку на алкоголь на Аляске, что произойдет с вашим CDL при первом отказе?","options":["Дисквалификация не менее чем на 1 год (3 года при перевозке hazmat)","Дисквалификация на 90 дней","Только предупреждение; без дисквалификации","Дисквалификация пожизненно"],"explanation":"Отказ рассматривается как тяжкое нарушение: дисквалификация не менее чем на 1 год или на 3 года при перевозке опасных материалов. Источник: Alaska DMV CDL Manual, Implied Consent и sec. 1.3.2."},"47":{"q":"Согласно положению о подразумеваемом согласии в Alaska CDL Manual, какова минимальная дисквалификация за второй или последующий отказ пройти химический тест?","options":["10 лет","3 года","5 лет","1 год"],"explanation":"Текст о подразумеваемом согласии в Alaska CDL Manual гласит, что второй и последующий отказ влечет минимальную дисквалификацию в 10 лет. Источник: Alaska DMV CDL Manual, положение Implied Consent."},"48":{"q":"Что происходит с водителем CMV на Аляске, у которого обнаружено любое определяемое количество алкоголя ниже 0.04%?","options":["Отстранение от работы (out-of-service) на 24 часа","Дисквалификация на 60 дней","Дисквалификация на 1 год","Штраф $500 без отстранения от работы"],"explanation":"Alaska CDL Manual гласит, что вы будете отстранены от работы (out-of-service) на 24 часа, если у вас обнаружено любое определяемое количество алкоголя ниже .04%. Источник: Alaska DMV CDL Manual, sec. 1.3.2."},"49":{"q":"Какова минимальная скорость сверх установленного лимита, которая считается СЕРЬЕЗНЫМ нарушением правил дорожного движения для держателя CDL Аляски?","options":["15 mph или более сверх лимита","10 mph или более сверх лимита","20 mph или более сверх лимита","5 mph или более сверх лимита"],"explanation":"Чрезмерное превышение скорости означает 15 mph или более сверх установленного лимита — это серьезное нарушение правил дорожного движения. Источник: Alaska DMV CDL Manual, sec. 1.3.3."},"50":{"q":"Какова продолжительность дисквалификации на Аляске за совершение ДВУХ серьезных нарушений ПДД на CMV в течение трехлетнего периода?","options":["Не менее 60 дней","Не менее 30 дней","Не менее 120 дней","Не менее 1 года"],"explanation":"Два серьезных нарушения ПДД в течение 3 лет влекут дисквалификацию не менее чем на 60 дней. Источник: Alaska DMV CDL Manual, sec. 1.3.3 и таблица Serious Disqualifying Offenses."},"51":{"q":"Какова продолжительность дисквалификации на Аляске за ТРИ или более серьезных нарушения ПДД на CMV в течение трехлетнего периода?","options":["Не менее 120 дней","Не менее 60 дней","Не менее 90 дней","Не менее 1 года"],"explanation":"Три или более серьезных нарушения ПДД в течение 3 лет влекут дисквалификацию не менее чем на 120 дней. Источник: Alaska DMV CDL Manual, sec. 1.3.3 и таблица Serious Disqualifying Offenses."},"52":{"q":"Что из перечисленного НЕ указано как серьезное нарушение ПДД в Alaska CDL Manual?","options":["Управление CMV с BAC 0.04% или выше","Движение слишком близко за транспортным средством","Неправильная или беспорядочная смена полосы движения","Управление CMV без надлежащего класса CDL"],"explanation":"Управление с BAC 0.04% или выше является ТЯЖКИМ нарушением, а не серьезным нарушением ПДД. Остальные три — серьезные нарушения ПДД. Источник: Alaska DMV CDL Manual, sec. 1.3.2 и 1.3.3."},"53":{"q":"Согласно закону Аляски (AS 28.33.190), отправка текстовых сообщений или использование ручного мобильного телефона во время управления CMV классифицируется как что?","options":["Серьезное нарушение ПДД (использование электронного устройства)","Тяжкое дисквалифицирующее нарушение","Нарушение приказа об отстранении от работы (out-of-service)","Незарегистрируемое мелкое нарушение"],"explanation":"Аляска относит 'использование электронного устройства во время вождения' (AS 28.33.190(16)(H)) к серьезным дисквалифицирующим нарушениям, которые учитываются при достижении порогов в 60 дней/120 дней. Источник: Alaska DMV CDL Manual, Serious Disqualifying Offenses; AS 28.33.190."},"54":{"q":"Каков максимальный гражданско-правовой штраф, который может грозить водителю CMV за нарушение запрета на ручной мобильный телефон, описанного в Alaska CDL Manual?","options":["До $2,750","До $11,000","До $500","До $1,000"],"explanation":"Каждое нарушение, связанное с ручным телефоном, влечет гражданско-правовой штраф до $2,750 для водителя; работодателям грозит до $11,000. Источник: Alaska DMV CDL Manual, sec. 2.9.4 (hand-held mobile telephones)."},"55":{"q":"Какова дисквалификация на Аляске за ПЕРВОЕ нарушение приказа об отстранении от работы (out-of-service, OOS) во время управления CMV (без hazmat или пассажиров)?","options":["Не менее 180 дней и не более 1 года","Не менее 90 дней и не более 1 года","Ровно 60 дней","Не менее 2 лет и не более 5 лет"],"explanation":"Аляска дисквалифицирует за первое нарушение приказа OOS на срок не менее 180 дней и не более 1 года. Источник: Alaska DMV CDL Manual, таблица Violating Out-of-Service Orders (AS 28.33.140(j))."},"56":{"q":"Какова продолжительность дисквалификации на Аляске за ПЕРВОЕ нарушение приказа об отстранении от работы, совершенное во время перевозки опасных материалов или пассажиров?","options":["Не менее 180 дней и не более 2 лет","Не менее 180 дней и не более 1 года","Не менее 1 года и не более 5 лет","Ровно 120 дней"],"explanation":"Первое нарушение приказа OOS во время перевозки hazmat или пассажиров влечет дисквалификацию на срок не менее 180 дней и не более 2 лет. Источник: Alaska DMV CDL Manual, таблица Violating Out-of-Service Orders (AS 28.33.140(j))."},"57":{"q":"Какова дисквалификация на Аляске за ВТОРОЕ нарушение приказа об отстранении от работы (без hazmat) в течение 10-летнего периода?","options":["Не менее 1 года и не более 5 лет","Не менее 180 дней и не более 1 года","Не менее 3 лет и не более 5 лет","Пожизненно"],"explanation":"Второе нарушение приказа OOS в течение 10 лет влечет дисквалификацию на срок не менее 1 года и не более 5 лет; при наличии hazmat или пассажиров — от 3 до 5 лет. Источник: Alaska DMV CDL Manual, таблица Violating Out-of-Service Orders."},"58":{"q":"За ПЕРВОЕ нарушение на железнодорожном переезде во время управления CMV какова дисквалификация на Аляске?","options":["Не менее 60 дней","Не менее 15 дней","Не менее 120 дней","Не менее 1 года"],"explanation":"Аляска дисквалифицирует за первое нарушение на железнодорожном переезде не менее чем на 60 дней; второе в течение 3 лет — 120 дней, а третье в течение 3 лет — 1 год. Источник: Alaska DMV CDL Manual, sec. 1.3.5 / таблица Railroad-Highway Grade Crossing Violations."},"59":{"q":"В Аляске автобус или транспортное средство, перевозящее опасные материалы с табличками (placard), должен остановиться перед железнодорожным переездом на каком расстоянии от ближайшего рельса?","options":["От 15 до 50 футов","От 5 до 15 футов","От 50 до 100 футов","От 10 до 25 футов"],"explanation":"Руководство CDL Аляски (разделы 4.3.5 и 9.6.12) требует, чтобы автобусы и транспортные средства с табличками HazMat останавливались не ближе 15 футов и не дальше 50 футов от ближайшего рельса, а затем смотрели и прислушивались перед переездом."},"60":{"q":"Согласно закону Аляски «Move Over» (об уступке полосы), когда водитель приближается к неподвижному аварийному транспортному средству с включёнными мигающими огнями на дороге с двумя или более полосами в одном направлении, водитель обязан:","options":["Освободить полосу, ближайшую к аварийному транспортному средству, когда это безопасно","Полностью остановиться до тех пор, пока аварийное транспортное средство не уедет","Подать звуковой сигнал и продолжать движение с установленной скоростью","Съехать на обочину и подождать три минуты"],"explanation":"Статут Аляски AS 28.35.185 требует, чтобы водители на дороге с двумя или более полосами в одном направлении освобождали полосу, ближайшую к неподвижному аварийному, пожарному, полицейскому, эвакуационному, ремонтному транспортному средству или машине службы контроля за животными с мигающими огнями, если это безопасно."},"61":{"q":"При остановке для школьного автобуса с мигающими красными огнями закон Аляски требует, чтобы приближающийся водитель остановился на каком минимальном расстоянии от автобуса?","options":["30 футов","15 футов","20 футов","50 футов"],"explanation":"Статут Аляски AS 28.35.145 требует, чтобы водитель, приближающийся к школьному автобусу с мигающими красными огнями, остановился не менее чем в 30 футах от автобуса и не продолжал движение, пока огни не перестанут мигать."},"62":{"q":"На любой проезжей части, кроме переулка, делового района или жилого района, какова максимально разрешённая скорость для коммерческого транспортного средства в Аляске, если не указано иное?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"Административный кодекс Аляски 13 AAC 03.275 устанавливает максимально разрешённую скорость для коммерческих транспортных средств в 55 mph на любой другой проезжей части (15 mph в переулке, 20 mph в деловом районе, 25 mph в жилом районе)."},"63":{"q":"Закон Аляски об остановке перед школьным автобусом содержит исключение для разделённых автомагистралей. Когда приближающийся водитель НЕ обязан останавливаться для школьного автобуса?","options":["Когда автобус находится на другой проезжей части автомагистрали с раздельными проезжими частями","Когда водитель движется как минимум на 10 mph ниже ограничения","Когда автобус находится дальше 100 футов","Когда рядом с автобусом не видно детей"],"explanation":"Согласно AS 28.35.145, водитель на автомагистрали с раздельными проезжими частями не обязан останавливаться при встрече или обгоне школьного автобуса, находящегося на другой проезжей части (исключение для разделённой автомагистрали)."},"64":{"q":"После остановки коммерческого транспортного средства на дороге с односторонним движением или разделённой автомагистрали в Аляске, в каких местах водитель должен разместить три предупреждающих треугольника?","options":["Примерно в 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта","Примерно в 10 футах, 50 футах и 150 футах в сторону приближающегося транспорта","Примерно в 25 футах, 100 футах и 250 футах в сторону приближающегося транспорта","Примерно в 50 футах, 100 футах и 500 футах в сторону приближающегося транспорта"],"explanation":"Согласно Руководству CDL Аляски (раздел 2.5), на дороге с односторонним движением или разделённой автомагистрали предупреждающие устройства размещаются в 10 футах, 100 футах и 200 футах от транспортного средства в сторону приближающегося транспорта."},"65":{"q":"Водитель, нарушивший закон Аляски «Move Over» (AS 28.35.185) и причинивший телесные повреждения, виновен в каком правонарушении?","options":["Проступок класса A (class A misdemeanor)","Только нарушение (infraction)","Тяжкое преступление класса B (class B felony)","Нарушение без начисления штрафных баллов"],"explanation":"AS 28.35.185(b) квалифицирует нарушение «Move Over» как проступок класса A, когда в результате несоблюдения требования освободить полосу или снизить скорость наступают телесные повреждения; в противном случае это нарушение (infraction)."},"66":{"q":"На двухполосной дороге с движением в обоих направлениях, где Руководство CDL Аляски предписывает водителю размещать предупреждающие треугольники после остановки?","options":["В пределах 10 футов от транспортного средства, а также в 100 футах позади и впереди него","В пределах 25 футов от транспортного средства, а также в 200 футах позади и впереди него","Только в 100 футах позади транспортного средства","В 10, 100 и 200 футах только позади транспортного средства"],"explanation":"Руководство CDL Аляски (раздел 2.5) гласит, что на неразделённой дороге с двусторонним движением следует разместить треугольник в пределах 10 футов от транспортного средства и по одному в 100 футах позади и впереди него на обочине или на полосе."},"67":{"q":"Какой перечень транспортных средств обязан совершать обязательную остановку перед пересечением железнодорожных путей согласно правилам CDL Аляски?","options":["Транспортные средства с табличками, любое транспортное средство, перевозящее хлор, и автоцистерны, используемые для опасных материалов","Только комбинации с тремя прицепами","Только автобусы, перевозящие более 30 пассажиров","Все транспортные средства с полной массой свыше 26 000 фунтов"],"explanation":"Раздел 9.6.12 Руководства CDL Аляски перечисляет транспортные средства, которые должны останавливаться на железнодорожных переездах: транспортные средства с табличками, любое транспортное средство, перевозящее любое количество хлора, и автоцистерны (гружёные или порожние), используемые для опасных материалов."},"68":{"q":"Через какое время после остановки на дороге водитель CDL в Аляске обязан выставить аварийные предупреждающие устройства?","options":["В течение 10 минут","В течение 5 минут","В течение 15 минут","Немедленно, в течение 1 минуты"],"explanation":"Руководство CDL Аляски (раздел 2.5) гласит, что если вы вынуждены остановиться на дороге или рядом с ней, вы должны выставить аварийные предупреждающие устройства в течение 10 минут."},"69":{"q":"Когда водитель CDL в Аляске вынужден остановить коммерческое транспортное средство на обочине, какие три требуемых предупреждающих устройства должны использоваться?","options":["Три красных светоотражающих треугольника, либо 6 фальшфейеров, либо 3 жидкостных сигнальных огня","Два красных фонаря и один красный флаг","Четыре жёлтых отражателя","Один светоотражающий треугольник и два дорожных сигнальных огня"],"explanation":"Руководство CDL Аляски перечисляет допустимые предупреждающие устройства для припаркованных транспортных средств: три красных светоотражающих треугольника, не менее 6 фальшфейеров или 3 жидкостных сигнальных огня."},"70":{"q":"Водитель школьного автобуса в Аляске, который должен остановиться на железнодорожном переезде, также должен выполнить какое из следующих действий перед переездом?","options":["Открыть переднюю дверь, если это улучшает возможность видеть или слышать приближающийся поезд","Подать звуковой сигнал три раза","Сначала высадить из автобуса всех пассажиров","Перейти на пониженную передачу, находясь на путях"],"explanation":"Руководство CDL Аляски (раздел 4.3.5) предписывает водителям автобусов останавливаться за 15–50 футов до переезда, смотреть и прислушиваться в обе стороны и открывать переднюю дверь, если это улучшает возможность видеть или слышать поезд."},"71":{"q":"Если коммерческое транспортное средство остановлено на обочине за холмом или поворотом, который закрывает обзор другим водителям в пределах 500 футов, что водитель CDL в Аляске должен сделать с предупреждающими треугольниками?","options":["Переместить задний треугольник дальше назад по дороге, чтобы предупреждение было обеспечено за пределами препятствия","Разместить все три треугольника прямо позади транспортного средства","Убрать треугольники и полагаться только на аварийную сигнализацию","Разместить треугольник на крыше кабины"],"explanation":"Руководство CDL Аляски (раздел 2.5) предписывает, что если холм, поворот или иное препятствие закрывает линию обзора в пределах 500 футов, водитель должен переместить задний треугольник дальше назад по дороге, чтобы обеспечить предупреждение."},"72":{"q":"На разделённой автомагистрали в Аляске какой приближающийся водитель освобождён от обязанности останавливаться для школьного автобуса, который сажает детей?","options":["Водитель на противоположной проезжей части, отделённой от автобуса разделительной полосой или барьером","Водитель непосредственно позади автобуса на той же полосе","Водитель, обгоняющий автобус по правой обочине","Любой водитель, движущийся со скоростью менее 20 mph"],"explanation":"Исключение для раздельных проезжих частей в AS 28.35.145 применяется к водителям на противоположной проезжей части разделённой автомагистрали; водители на той же проезжей части, что и автобус, включая едущих позади него, всё равно обязаны остановиться."},"73":{"q":"На дороге, где в одном направлении менее двух полос, что требует закон Аляски «Move Over», когда водитель проезжает мимо неподвижного аварийного транспортного средства с мигающими огнями?","options":["Снизить скорость до разумной и безопасной с учётом транспорта, состояния дороги и погоды","Точно поддерживать установленное ограничение скорости","Полностью остановиться до получения сигнала продолжать движение","Полностью съехать на противоположную обочину"],"explanation":"AS 28.35.185 требует, чтобы там, где в одном направлении менее двух полос, водитель снижал скорость до разумной и безопасной с учётом транспорта, состояния дороги и погодных условий."},"74":{"q":"При пересечении железнодорожных путей в Аляске водитель CDL должен:","options":["Не переключать передачи во время пересечения путей","Перейти на первую передачу на путях для максимального контроля","Остановиться на путях, если поезда не видно","Резко ускориться и переключиться на повышенную передачу на середине"],"explanation":"Руководство CDL Аляски (разделы 2.15 и 9.6.12) предупреждает водителей никогда не переключать передачи во время пересечения путей, поскольку неудачное переключение может оставить транспортное средство заглохшим на переезде."},"75":{"q":"Какова максимально разрешённая законом ширина транспортного средства/груза в Аляске, при которой можно двигаться по дороге общего пользования без специального разрешения на негабаритный груз?","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","120 inches (10 feet)","108 inches (9 feet)"],"explanation":"Руководство Аляски по разрешениям на негабаритные/сверхтяжёлые грузы ссылается на ограничение законной ширины в 102 inches (8 feet 6 inches) согласно 17 AAC 25; всё, что шире, требует разрешения и знаков OVERSIZE/WIDE LOAD."},"76":{"q":"Согласно правилам Аляски о разрешениях на негабаритные грузы, широкий груз требует как минимум одного машины сопровождения (pilot/escort) на всех маршрутах, как только его ширина превышает:","options":["10 feet 6 inches","8 feet 6 inches","12 feet","9 feet"],"explanation":"Руководство Аляски по разрешениям на негабаритные/сверхтяжёлые грузы (раздел 6.2.1) требует как минимум одну машину сопровождения (pilot/escort) на всех маршрутах, когда ширина транспортного средства или груза превышает 10 feet 6 inches."},"77":{"q":"Согласно правилам Аляски о разрешениях, груз, высота которого превышает 17 feet, ограничен какой максимальной скоростью на дороге (при отсутствии более строгого ограничивающего фактора)?","options":["45 mph","55 mph","35 mph","25 mph"],"explanation":"Руководство Аляски по разрешениям на негабаритные/сверхтяжёлые грузы (раздел 9.3.1) ограничивает грузы высотой более 17 feet максимальной скоростью на дороге в 45 mph, если иные факторы не являются более строгими."},"78":{"q":"На разводном мосту в Аляске, где нет сигнального светофора или служащего, регулирующего движение, где должен остановиться водитель CDL?","options":["Не менее чем за 50 футов до разводной части моста","Не менее чем за 15 футов до разводной части моста","Не менее чем за 100 футов до разводной части моста","Прямо у края разводной части"],"explanation":"Руководство CDL Аляски (раздел 4.3.6) требует остановки не менее чем за 50 футов до разводной части моста, на котором нет сигнального светофора или служащего, регулирующего движение, и проверки того, что разводная часть полностью закрыта, перед переездом."},"79":{"q":"Какое государственное ведомство Аляски выдаёт коммерческие водительские удостоверения (CDL)?","options":["Управление транспортных средств Аляски (Alaska Division of Motor Vehicles, DMV)","Департамент общественной безопасности Аляски","Федеральное управление безопасности автоперевозчиков (FMCSA)","Департамент транспорта и общественных сооружений Аляски (DOT&PF)"],"explanation":"В Аляске Управление транспортных средств (DMV) является государственным ведомством по лицензированию водителей, которое выдаёт CDL и проводит тесты на знания и навыки. FMCSA устанавливает федеральные стандарты CDL, но не выдаёт само удостоверение. Источник: Alaska DMV, страница Commercial Driver's License (CDL)."},"80":{"q":"Какой минимальный балл должен набрать заявитель, чтобы сдать каждый тест на знания CDL в Аляске?","options":["70%","75%","80%","90%"],"explanation":"Аляска требует набрать не менее 80%, чтобы сдать каждый тест на знания CDL (общие знания и любые тесты на дополнительные разрешения). Источник: Руководство CDL Alaska DMV / требования к CDL Alaska DMV."},"81":{"q":"Тест на навыки CDL в Аляске разделён на три части. В каком наборе правильно перечислены все три?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Проверка зрения, письменный тест на знания и вождение по дороге","Предрейсовый осмотр, проверка пневматических тормозов и параллельная парковка","Движение задним ходом, сцепка/расцепка и манёвренная трасса на время"],"explanation":"Тест на навыки CDL в Аляске состоит из трёх частей: тест предрейсового (технического) осмотра, тест базового управления транспортным средством и тест вождения по дороге. Источник: Руководство CDL Alaska DMV."},"82":{"q":"Кто отвечает за предоставление транспортного средства, используемого для дорожного теста на навыки CDL в Аляске?","options":["Заявитель должен предоставить транспортное средство, представляющее класс и тип, на котором он намерен ездить","DMV предоставляет стандартное тестовое транспортное средство всем заявителям","Реестр поставщиков обучения FMCSA (Training Provider Registry) назначает транспортное средство","Alaska DOT&PF предоставляет транспортное средство из своего автопарка"],"explanation":"Заявитель должен привезти собственное транспортное средство, представляющее тот же класс и тип, на котором он планирует ездить; офис DMV не предоставляет тестовое транспортное средство. Источник: Руководство CDL Alaska DMV / требования к CDL Alaska DMV."},"83":{"q":"После получения коммерческого ученического разрешения (CLP) сколько должен ждать заявитель в Аляске, прежде чем сдавать тест на навыки CDL (дорожный тест)?","options":["Не менее 14 days","Не менее 7 days","Не менее 30 days","Период ожидания отсутствует"],"explanation":"Аляска следует федеральному правилу, требующему, чтобы держатель CLP ждал не менее 14 days после выдачи CLP, прежде чем сдавать любой дорожный тест на CDL. Источник: страница CLP Alaska DMV (49 CFR 383.25)."},"84":{"q":"Сколько времени действует коммерческое ученическое разрешение (CLP) в Аляске до того, как его необходимо продлить?","options":["180 days","30 days","1 год","5 лет"],"explanation":"CLP в Аляске действует 180 days и может быть продлено (переоформлено) один раз ещё на 180 days без повторной сдачи теста на общие знания. Источник: информация о CLP Alaska DMV (49 CFR 383.25)."},"85":{"q":"Сколько раз CLP в Аляске может быть продлено/переоформлено на дополнительный период в 180 days согласно федеральному стандарту, которому следует Аляска?","options":["Один раз","Оно вообще не может быть продлено","Два раза","Неограниченное число раз"],"explanation":"CLP действует 180 days и может быть продлено один раз ещё на 180 days (максимум 360 days в общей сложности). Источник: информация о CLP Alaska DMV (49 CFR 383.25)."},"86":{"q":"Прежде чем впервые подающий заявление сможет сдать тест на навыки CDL в Аляске для удостоверения класса A или класса B, какое обучение должно быть завершено?","options":["Обучение водителей начального уровня (ELDT) у поставщика, внесённого в Реестр поставщиков обучения FMCSA","Курс защитного вождения, одобренный судебной системой Аляски","40-часовая сертификация по зимнему вождению в Аляске","Ученичество, зарегистрированное в Департаменте труда Аляски"],"explanation":"С 7 февраля 2022 года впервые подающие заявление на CDL должны пройти обучение водителей начального уровня (ELDT) у поставщика из Реестра поставщиков обучения FMCSA, прежде чем сдавать тест на навыки; штат должен подтвердить, что запись была подана. Источник: правило ELDT FMCSA (49 CFR Part 380), применяемое Alaska DMV."},"87":{"q":"Самосертификация CDL в Аляске требует, чтобы водитель указал, какой тип перевозок он предполагает выполнять. Сколько существует категорий самосертификации?","options":["Четыре","Две","Три","Пять"],"explanation":"Водители должны самосертифицироваться в одну из четырёх категорий, образованных сочетанием межштатных/внутриштатных перевозок с освобождёнными/неосвобождёнными (excepted/non-excepted) перевозками. Источник: страница CDL Self-Certification Requirement Alaska DMV."},"88":{"q":"Какая из следующих является одной из четырёх категорий самосертификации CDL в Аляске?","options":["Межштатная неосвобождённая (interstate non-excepted)","Межштатная сезонная","Внутриштатная только для опасных грузов","Федеральный освобождённый перевозчик"],"explanation":"Четыре категории: межштатная неосвобождённая (interstate non-excepted), межштатная освобождённая (interstate excepted), внутриштатная неосвобождённая (intrastate non-excepted) и внутриштатная освобождённая (intrastate excepted). «Interstate non-excepted» — это категория для водителей, которые обязаны соответствовать федеральным требованиям к медицинской карте DOT. Источник: страница CDL Self-Certification Requirement Alaska DMV."},"89":{"q":"Водитель в Аляске, который самосертифицируется как «non-excepted» (межштатный или внутриштатный), должен предоставить в DMV какой документ?","options":["Действующую медицинскую справку медэксперта DOT (медицинскую карту)","Нотариально заверенное письмо о спонсорстве от работодателя","Подписанный отказ от соблюдения федеральных медицинских стандартов","Стикер о техосмотре коммерческого транспорта Аляски"],"explanation":"Водители категории non-excepted должны иметь и предоставить действующую медицинскую справку медэксперта DOT (медицинскую карту) для сохранения привилегий CDL; водители категории excepted не обязаны её предоставлять. Источник: страница CDL Self-Certification Requirement Alaska DMV."},"90":{"q":"Каким образом держатель CDL в Аляске может подать свою самосертификацию и медицинскую справку медэксперта DOT в DMV?","options":["Заполнить форму Form 413 и предъявить или отправить по электронной почте разборчивую копию медицинской карты на адрес электронной почты DMV по вопросам CDL","Загрузить карту только в Реестр поставщиков обучения FMCSA","Отправить оригинал карты напрямую в FMCSA в Вашингтон, округ Колумбия","Подать её в Департамент труда и развития рабочей силы Аляски"],"explanation":"Водители заполняют самосертификацию (Form 413) с каждым заявлением и предъявляют медицинскую карту в офисе DMV либо отправляют по электронной почте разборчивую копию на адрес DMV по вопросам CDL (doa.dmv.cdl@alaska.gov). Источник: страница CDL Self-Certification Requirement Alaska DMV."},"91":{"q":"Каковы последствия в Аляске, если держатель CDL категории non-excepted не сохраняет действующую медицинскую справку медэксперта DOT в DMV?","options":["Привилегии CDL понижаются или аннулируются","Налагается единовременный федеральный штраф в размере $500, но CDL остаётся действительным","Ничего, потому что медицинская карта подаётся только работодателю","Водитель автоматически переклассифицируется как внутриштатный водитель категории excepted"],"explanation":"Если медицинская сертификация водителя категории non-excepted истекает, Alaska DMV аннулирует или понижает привилегии CDL; управление CMV после этого является вождением без надлежащих привилегий. Источник: страница CDL Self-Certification Requirement Alaska DMV."},"92":{"q":"Сколько времени действует CDL в Аляске до того, как его необходимо продлить?","options":["5 лет","4 года","8 лет","2 года"],"explanation":"CDL в Аляске действителен 5 лет и истекает в день рождения держателя. Источник: информация о продлении Alaska DMV."},"93":{"q":"В какую дату обычно истекает срок действия CDL в Аляске в год его продления?","options":["В день рождения держателя","31 декабря","Ровно через пять лет с даты выдачи независимо от дня рождения","В последний день месяца выдачи"],"explanation":"Водительские удостоверения Аляски, включая CDL, выдаются на 5 лет и истекают в день рождения держателя. Источник: информация о продлении Alaska DMV."},"94":{"q":"Насколько заранее до истечения срока держатель CDL в Аляске может начать процесс продления?","options":["За 1 год до истечения срока","За 30 days до истечения срока","Только в дату истечения срока","В течение 6 месяцев после истечения срока"],"explanation":"Аляска позволяет начать продление CDL уже за один год до истечения срока действия удостоверения; штат не предоставляет льготного периода для уже просроченного удостоверения. Источник: информация о продлении Alaska DMV."},"95":{"q":"Какой набор документов требуется при подаче заявления на первичное получение CDL в Аляске?","options":["Подтверждение гражданства США/законного пребывания, адрес проживания/места жительства в Аляске, номер социального страхования (Social Security Number) и медицинская карта DOT, когда применимо","Только действующее CDL другого штата и фотография на паспорт","Свидетельство о праве собственности на транспортное средство, подтверждение страховки и лицензия на рыбалку в Аляске","Только номер перевозчика FMCSA и нотариально заверенный аффидевит"],"explanation":"Аляска требует подтверждение гражданства/законного пребывания, подтверждение адреса проживания в Аляске (места жительства), номер социального страхования (Social Security Number), действующее водительское удостоверение и медицинскую карту DOT, когда применимо. Источник: страница Commercial Driver's License (CDL) Alaska DMV."},"96":{"q":"Каков минимальный возраст для получения CDL в Аляске с ограничением только на внутриштатные (в пределах Аляски) перевозки?","options":["18 лет","16 лет","21 год","25 лет"],"explanation":"Минимальный возраст для CDL в Аляске составляет 18 лет для внутриштатных перевозок; межштатные перевозки, перевозка опасных грузов (hazmat) и разрешение на управление школьным автобусом требуют возраста 21 год. Источник: страницы CDL / CLP Alaska DMV."},"97":{"q":"Водитель, желающий работать в межштатных перевозках или перевозить опасные материалы, должен быть не моложе какого возраста, чтобы иметь CDL Аляски для такой деятельности?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Аляска требует, чтобы водителю было не менее 21 года для межштатных перевозок или для получения разрешения на hazmat либо на управление школьным автобусом, тогда как CDL только для внутриштатных перевозок доступны с 18 лет. Источник: страницы CDL / CLP Alaska DMV."},"98":{"q":"Относительно сборов за подачу заявления на CDL в Аляске, какое утверждение точно описывает, как устроен процесс?","options":["Применимые сборы за CDL и дорожный тест уплачиваются в DMV при подаче заявления, а точные суммы устанавливаются штатом и могут со временем меняться","Аляска не взимает плату за первичное получение CDL","Все сборы за CDL уплачиваются напрямую в FMCSA, а не в DMV","Сбор за дорожный тест полностью возвращается, если заявитель не сдаёт"],"explanation":"Заявители на CDL в Аляске уплачивают применимые сборы за удостоверение и дорожный тест в DMV в момент подачи заявления; конкретные суммы устанавливаются штатом и могут меняться, поэтому надёжным ориентиром является процесс, а не фиксированная сумма. Источник: страница CDL Alaska DMV / тарифная сетка."}},"tr":{"0":{"q":"Alaska'da, eyalet karayolu sisteminde bir aracın, yükü dahil olmak üzere yasal azami genişliği nedir?","options":["102 inç","96 inç","108 inç","114 inç"],"explanation":"Alaska, yük dahil azami araç genişliğini 102 inç olarak belirler; takılı ekipman bunun ötesine her iki tarafta en fazla 3 inç taşabilir. Kaynak: 17 AAC 25.012(a) (Alaska DOT&PF, Bölüm 25 Operasyonlar, Tekerlekli Araçlar), Alaska CDL Kılavuzu ile tutarlıdır."},"1":{"q":"Alaska karayollarının çoğunda bir aracın ve yükünün genel yasal azami yüksekliği nedir?","options":["15 fit","13 fit 6 inç","14 fit","16 fit"],"explanation":"17 AAC 25.012(b) uyarınca, bir Alaska aracı yükü dahil olmak üzere 15 fit yüksekliği aşamaz; bunun istisnası, Fox Tartı İstasyonu ile Prudhoe Bay arasındaki Dalton/Elliott Karayolu koridorudur; burada 17 fite izin verilir. Kaynak: 17 AAC 25.012(b), Alaska DOT&PF."},"2":{"q":"Fox Tartı İstasyonu ile Prudhoe Bay arasındaki Dalton ve Elliott Karayollarında, bir araç ve yükü için izin verilen artırılmış yükseklik nedir?","options":["15 fit 6 inç","16 fit","17 fit","18 fit"],"explanation":"17 AAC 25.012(b), Dalton ve Elliott Karayollarında Fox Tartı İstasyonu ile Prudhoe Bay arasında çalışan bir araç için, genel 15 fitlik limite karşılık, yük dahil 17 fit yüksekliğe izin verir. Kaynak: 17 AAC 25.012(b), Alaska DOT&PF."},"3":{"q":"Alaska'nın Ulusal Karayolu Sistemi (NHS) güzergahlarında, tek bir motorlu aracın (kamyonun ya da çekicinin kendisinin) azami uzunluğu nedir?","options":["40 fit","48 fit","53 fit","45 fit"],"explanation":"17 AAC 25.012(c)(1), NHS güzergahlarında bir motorlu aracın uzunluğunu 45 fitle sınırlar (ve 17 AAC 25.012(d)(1), eyalet karayolu sisteminin geri kalanında da aynı 45 fitlik limiti belirler). Kaynak: 17 AAC 25.012, Alaska DOT&PF."},"4":{"q":"Alaska'da, bir kombinasyonda kullanılan yarı römork veya römorkun azami yük taşıma uzunluğu nedir?","options":["48 fit","57 fit","60 fit","53 fit"],"explanation":"17 AAC 25.012(c)(3) ve (e)(1), tüm güzergahlarda bir yarı römork veya römorkun yük taşıma uzunluğunu 53 fitle sınırlar. Kaynak: 17 AAC 25.012, Alaska DOT&PF."},"5":{"q":"Alaska karayollarında, bir kamyon ile bir yük taşıyan araçtan ya da bir çekici ile iki yük taşıyan araçtan oluşan standart bir kombinasyonun azami toplam uzunluğu nedir?","options":["65 fit","70 fit","75 fit","80 fit"],"explanation":"17 AAC 25.012(c)(4) ve (d)(3), bu tür kombinasyonları 75 fitlik bir toplam uzunlukla sınırlar; tek bir yük taşıyan araca sahip bir çekici, toplam uzunluk limitine tabi değildir. Kaynak: 17 AAC 25.012, Alaska DOT&PF."},"6":{"q":"Alaska'da, bir yük veya ekipman, yasal limiti aşmadan önce aracın ön tamponunun ötesine ne kadar uzanabilir?","options":["3 fit","4 fit","5 fit","6 fit"],"explanation":"17 AAC 25.012(c)(6) ve (d)(4), bir yük veya ekipmanın ön tamponun ötesine en fazla 3 fit (ve arkanın ötesine en fazla 4 fit) taşmasına izin verir. Kaynak: 17 AAC 25.012, Alaska DOT&PF."},"7":{"q":"Alaska'da, bir yük, yasal limiti aşmadan önce aracın arkasının ötesine ne kadar uzanabilir?","options":["3 fit","5 fit","6 fit","4 fit"],"explanation":"17 AAC 25.012(c)(6)(B) ve (d)(4)(B), en fazla 4 fitlik bir arka taşmaya izin verir (ön taşma 3 fitle sınırlıdır). Kaynak: 17 AAC 25.012, Alaska DOT&PF."},"8":{"q":"Alaska'da tek bir aksta izin verilen yasal azami ağırlık nedir?","options":["18.000 pound","22.400 pound","34.000 pound","20.000 pound"],"explanation":"17 AAC 25.013(a)(4), bir aksın tek aks olarak sayılması için en az 8'1\" aralıkla, tek aks ağırlık limitini 20.000 pound olarak belirler. Kaynak: 17 AAC 25.013, Alaska DOT&PF."},"9":{"q":"Alaska'nın aks grubu tablosuna göre, 2 akslı bir grupta (tandem aks) izin verilen azami ağırlık nedir?","options":["34.000 pound","36.000 pound","38.000 pound","40.000 pound"],"explanation":"17 AAC 25.013(a)(4)'teki Alaska aks grubu ağırlık tablosu, 2 akslı bir grupta (tandem) 38.000 pounda izin verir; bu, birçok eyalette kullanılan 34.000 poundluk federal tandem standardından daha yüksektir. Kaynak: 17 AAC 25.013, Alaska DOT&PF."},"10":{"q":"Alaska'nın aks grubu ağırlık tablosuna göre, 3 akslı bir grupta izin verilen azami ağırlık nedir?","options":["38.000 pound","46.000 pound","50.000 pound","42.000 pound"],"explanation":"17 AAC 25.013(a)(4), 3 akslı bir grupta (3'6\" asgari aks aralığıyla) 42.000 pounda izin verir. Kaynak: 17 AAC 25.013, Alaska DOT&PF."},"11":{"q":"Alaska'da bir aksın, bir aks grubunun parçası yerine 'tek aks' olarak değerlendirilmesi için korunması gereken asgari aks aralığı nedir?","options":["8 fit 1 inç","3 fit 6 inç","6 fit","10 fit"],"explanation":"17 AAC 25.013(a)(4)'e ilişkin nota göre, başka bir akstan (merkezden merkeze) 8 fit 1 inçten daha az aralıkta olan herhangi bir aks, bir aks grubunun parçası sayılır; tek aks limiti, asgari 8'1\" aralıkta uygulanır. Kaynak: 17 AAC 25.013, Alaska DOT&PF."},"12":{"q":"Alaska, uzun bir kombinasyon için azami brüt araç ağırlığını nasıl belirler?","options":["Tüm karayollarında sabit 80.000 poundluk bir üst sınırla","Aks sayısını 20.000 poundla çarparak","Aks sayısı ve aralığına dayalı olarak eyaletin Köprü Brüt Ağırlık Formülünü uygulayarak","Yasayla belirlenmiş sabit 105.500 poundluk bir limitle"],"explanation":"17 AAC 25.013(a)(6), azami brüt ağırlığı sabit 80.000 poundluk bir üst sınırla değil, W = 500[LN/(N-1) + 12N + 36] Köprü Brüt Ağırlık Formülüyle belirler (tahrik grubunda kaldırma aksı olmadığında +3.000 eklenir). Kaynak: 17 AAC 25.013, Alaska DOT&PF."},"13":{"q":"Alaska'nın Köprü Brüt Ağırlık Formülü W = 500[LN/(N-1) + 12N + 36]'da, 'L' değişkeni neyi temsil eder?","options":["Ton cinsinden yasal yük ağırlığı","Uç aksların merkezleri arasındaki fit cinsinden mesafe","En uzun römorkun uzunluğu","Kaldırma aksı kapasitesi"],"explanation":"17 AAC 25.013(a)(6)'da 'L', aracın veya kombinasyonun uç akslarının merkezleri arasında tam fit olarak ölçülen mesafedir ve 'N', aks sayısıdır. Kaynak: 17 AAC 25.013, Alaska DOT&PF."},"14":{"q":"Alaska'da, üreticinin nominal lastik genişliğine dayalı olarak bir lastikte izin verilen azami ağırlık nedir?","options":["Lastik genişliğinin her inçi için 600 pound","Lastik genişliğinin her inçi için 500 pound","Lastik genişliğinin her inçi için 550 pound","Lastik genişliğinin her inçi için 650 pound"],"explanation":"17 AAC 25.013(a)(1), lastik üreticisinin nominal lastik genişliği derecelendirmesine dayalı olarak lastik ağırlığını, lastik genişliğinin doğrusal inçi başına 600 poundla sınırlar. Kaynak: 17 AAC 25.013, Alaska DOT&PF."},"15":{"q":"Alaska DOT&PF büyük boy/aşırı ağırlık izni ne zaman gereklidir?","options":["Yalnızca 100.000 pound brüt ağırlığın üzerindeki yükler için","Bir araç veya yük 17 AAC 25'teki azami boyutları veya ağırlıkları aştığında ve bir kamu yolunda seyahat edeceğinde","Yalnızca Kanada'ya bir eyalet sınırını geçerken","Yalnızca 12 fitten geniş araçlar için"],"explanation":"İdari İzin Kılavuzu (Bölüm 2.2.1) ve 17 AAC 25.320 uyarınca, bir araç veya yüklü araç 17 AAC 25'teki azami boyutları veya ağırlıkları aştığında ve bir kamu yolunda seyahat etmek istediğinde her zaman bir izin gereklidir. Kaynak: Alaska DOT&PF İdari İzin Kılavuzu; 17 AAC 25.320."},"16":{"q":"Alaska, büyük boy/aşırı ağırlık izinlerini yalnızca aşağıdakilerden hangisi olan yükler için verir?","options":["Yasal parçalara bölünebilen bölünebilir yükler","Yasal boyuta veya ağırlığa indirgenemeyen bölünemez yükler","Devlet kurumlarına ait yükler","Tehlikeli madde taşıyan yükler"],"explanation":"Alaska izinleri, bölünemez yükler (yasal boyutlara/ağırlığa pratik olarak indirgenemeyenler) için verilir; bölünebilir yükler yasal limitlere indirgenmelidir. Kaynak: Alaska DOT&PF İdari İzin Kılavuzu Bölüm 2.2 ve 17 AAC 25.320(a)(1)."},"17":{"q":"Alaska'da, tek seferlik bir büyük boy/aşırı ağırlık izninin (tek yönde 400 mil veya daha az bir taşıma için) standart geçerlilik süresi nedir?","options":["1 gün","3 gün","7 gün","30 gün"],"explanation":"İdari İzin Kılavuzu Bölüm 3.2.1 uyarınca, tek seferlik bir izin 3 günlük bir süre için geçerlidir (tek yönde 400 milden fazla seyahat ediliyorsa 5 güne uzatılır). Kaynak: Alaska DOT&PF İdari İzin Kılavuzu."},"18":{"q":"Alaska'da kış aylarında, bir araç üzerinde belgelenmiş kar ve buz birikmesi için ne kadar ekstra brüt ağırlık ödeneği verilebilir?","options":["500 pound","1.000 pound","1.500 pound","2.000 pound"],"explanation":"17 AAC 25.335(b)(1), kar ve buz birikmesine dair kanıt olduğunda 1 Ekim ile 30 Nisan arasında ek 1.500 poundluk bir ödenek verir; bu, kombinasyon türünden bağımsız olarak azami değerdir. Kaynak: 17 AAC 25.335, Alaska DOT&PF."},"19":{"q":"Alaska, damperli kamyon veya yolcu otobüsü gibi 26.001 pound veya daha fazla brüt araç ağırlık derecelendirmesine (GVWR) sahip tek bir aracı kullanmak için hangi CDL sınıfını gerektirir?","options":["A Sınıfı","B Sınıfı","C Sınıfı","D Sınıfı"],"explanation":"Alaska CDL Kılavuzu, B Sınıfını GVWR'si 26.001 poundun üzerinde olan tek bir araç ya da 10.000 lbs veya daha fazla ağırlıkta olmayan bir birimi çeken böyle bir araç (damperli kamyonlar, çimento mikserleri, kapalı kasa kamyonlar, yolcu otobüsleri) olarak tanımlar. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, Araç Sınıflandırmaları."},"20":{"q":"Alaska CDL Kılavuzu'na göre, çekilen birim(ler)in GVWR'si hangi ağırlığı aşması koşuluyla, 26.001 lbs veya daha fazla GCWR'ye sahip herhangi bir araç kombinasyonu için A Sınıfı CDL gereklidir?","options":["8.000 pound","10.000 pound","16.000 pound","26.001 pound"],"explanation":"Alaska, A Sınıfını, çekilen araç(lar)ın GVWR'sinin 10.000 poundtan fazla olduğu 26.001+ lbs GCWR'ye sahip bir kombinasyon olarak tanımlar (örneğin 18 tekerlekli kamyonlar, tomruk kamyonları). Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, A Sınıfı tanımı."},"21":{"q":"Alaska kurallarına göre, GVWR'si 26.001 lbs'nin altında olan bir araç, sürücü dahil kaç yolcu taşımak üzere tasarlanmışsa hala CDL programına (C Sınıfı) girer?","options":["8 veya daha fazla","11 veya daha fazla","15 veya daha fazla","16 veya daha fazla"],"explanation":"Alaska CDL Kılavuzu, sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmışsa ya da plakart gerektiren tehlikeli madde taşıyorsa, daha küçük bir aracı C Sınıfı olarak CDL programına dahil eder. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, C Sınıfı tanımı."},"22":{"q":"Alaska'da, plakart gerektiren miktarlarda tehlikeli madde taşımak için CDL üzerine hangi onay harfi yerleştirilir?","options":["H Onayı","N Onayı","X Onayı","T Onayı"],"explanation":"Alaska, plakart gerektiren miktarlarda tehlikeli madde taşımak için kullanılan herhangi bir araç için H (Tehlikeli Maddeler) onayını kullanır. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, Onaylar tablosu."},"23":{"q":"Alaska, dökme halinde sıvı taşımaya yönelik herhangi bir araç (tanker kamyonlar) için hangi onayı gerektirir?","options":["H Onayı","N Onayı","P Onayı","T Onayı"],"explanation":"Alaska CDL Kılavuzu, dökme halinde sıvı taşımaya yönelik herhangi bir araç için N (Tanker) onayını listeler. Alaska'nın tank onayı için kod harfinin N olduğunu unutmayın. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, Onaylar tablosu."},"24":{"q":"Çift veya üçlü römork çekmek için hangi Alaska CDL onayı gereklidir?","options":["N Onayı","P Onayı","T Onayı","X Onayı"],"explanation":"Alaska, iki veya üç römork çeken kombinasyonlar için T (Çift veya Üçlü Römorklar) onayını verir; yalnızca bir bilgi testi gereklidir. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, Onaylar tablosu."},"25":{"q":"Alaska CDL Kılavuzu'na göre, 16 veya daha fazla yolcu (sürücü dahil) taşımak üzere tasarlanmış bir araç için hangi onay gereklidir?","options":["S Onayı","P Onayı","N Onayı","H Onayı"],"explanation":"Alaska, gerçekte kaç yolcu taşındığına bakılmaksızın, sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış herhangi bir araç için P (Yolcu) onayını gerektirir. Bir bilgi ve yol becerileri testi gerektirir. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, Onaylar tablosu."},"26":{"q":"Alaska'da, bir CDL üzerindeki X onayı hangi kombinasyonu temsil eder?","options":["Birleşik tanker ve tehlikeli maddeler","Birleşik yolcu ve okul otobüsü","Birleşik çiftler ve üçlüler","Birleşik hava frenleri ve tanker"],"explanation":"Alaska, bir tanker/tehlikeli madde birleşik operasyonu için X onayını kullanır: plakart gerektiren miktarlarda tehlikeli madde taşımak için kullanılan herhangi bir tank aracı. Bir bilgi testi ve bir geçmiş kontrolü gerektirir. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, Onaylar tablosu."},"27":{"q":"Alaska, tehlikeli madde (H) onaylı bir CDL düzenlemeden veya yenilemeden önce, başvuru sahibinin önce hangi adımı tamamlamasını ister?","options":["Bir defansif sürüş kursu","Bir Ulaştırma Güvenliği İdaresi geçmiş kontrolü","30 günlük bir bekleme süresi","Bir ticari araç muayene kursu"],"explanation":"Alaska CDL Kılavuzu, bir HazMat onayı alan, ekleyen veya yenileyen tüm başvuru sahiplerinin, TSA/universalenroll.dhs.gov üzerinden işlenen bir geçmiş kontrolünü, düzenlemeden önce geçmesi gerektiğini belirtir. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, H Onayı notları."},"28":{"q":"Eyalet içi (yalnızca eyalet içi) ticaretle sınırlı bir Alaska CDL'sinin düzenlenmesi için asgari yaş nedir?","options":["16 yaş","17 yaş","18 yaş","21 yaş"],"explanation":"Alaska CDL Kılavuzu, bir başvuru sahibinin başvuru anında eyalet içi ticarette çalışmak için en az 18 yaşında olması (14.11.19 itibarıyla geçerli) ve en az bir yıldır geçerli bir sürücü belgesine sahip olması gerektiğini belirtir. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, Yaş gereksinimleri."},"29":{"q":"Alaska, bir CDL sahibinin eyaletler arası ticarette çalışması için hangi asgari yaşı gerektirir?","options":["18 yaş","19 yaş","20 yaş","21 yaş"],"explanation":"Alaska CDL Kılavuzu, bir başvuru sahibinin eyaletler arası ticarette çalışmak için en az 21 yaşında olması gerektiğini belirtir. 21 yaş altındaki sürücüler bir K (yalnızca eyalet içi) kısıtlaması alır. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, Yaş gereksinimleri ve K Kısıtlaması."},"30":{"q":"Hem federal kural hem de Alaska uygulamasına göre, bir başvuru sahibinin CDL yol becerileri testine girmeden önce bir Ticari Öğrenci Belgesini (CLP) ne kadar süre elinde tutması gerekir?","options":["En az 7 gün","En az 10 gün","En az 14 gün","En az 30 gün"],"explanation":"Alaska CDL Kılavuzu, bir başvuru sahibinin, sınıfını yükseltirken veya beceri testi gerektiren bir onay eklerken dahil olmak üzere, bir yol becerileri testine girmeden önce bir CLP'yi en az 14 gün elinde tutması gerektiğini belirtir. Kaynak: Alaska DMV CDL Kılavuzu, Bölüm 1, Test ve Düzenleme Gereksinimleri."},"31":{"q":"Bir Alaska Ticari Öğrenci Belgesi almadan önce, başvuru sahibinin halihazırda neye sahip olması gerekir?","options":["Geçerli güncel bir Alaska ticari olmayan sürücü belgesi","Bir federal DOT işletme yetkisi numarası","Tamamlanmış bir çıraklık sertifikası","Başka bir eyaletten önceden alınmış bir CDL"],"explanation":"Alaska DMV CLP sayfası, başvuru sahiplerinin bir CLP düzenlenmeden önce geçerli güncel bir Alaska ticari olmayan sürücü belgesine sahip olmasını ister. Kaynak: Alaska DMV Ticari Öğrenci Belgesi (CLP) sayfası."},"32":{"q":"Bir Alaska CLP'siyle araç kullanırken, belge sahibinin yanındaki koltukta bulunan eşlik eden belgeli sürücünün uygun sınıf/onaylara sahip olması ve en az kaç yaşında olması gerekir?","options":["18 yaşında","19 yaşında","21 yaşında","25 yaşında"],"explanation":"Alaska DMV CLP sayfasına göre, bir CLP sahibi yalnızca kendi sınıfından veya daha küçük bir aracı, yandaki koltukta en az 21 yaşında, uygun sınıf ve onaylara sahip olan ve bir yıldır belgeli olan geçerli belgeli bir sürücüyle kullanabilir. Kaynak: Alaska DMV Ticari Öğrenci Belgesi (CLP) sayfası."},"33":{"q":"Alaska'da Yolcu (P) onayına sahip bir CLP sahibi hangi kısıtlamaya tabidir?","options":["Yalnızca özel mülkte boş yolcu otobüsleri kullanabilir","Belirtilen sınav görevlileri, stajyerler ve eşlik eden CDL sahibi dışında bir CMV otobüsünde hiç yolcu taşıyamaz","Gündüz saatlerinde en fazla 8 yolcu taşıyabilir","Yalnızca eyalet içi güzergahlarda yolcu taşıyabilir"],"explanation":"Alaska CDL Kılavuzu'nun P kısıtlaması, P onaylı bir CLP sahibinin, federal/eyalet denetçileri, müfettişler, sınav görevlileri, diğer stajyerler ve eşlik eden CDL sahibi dışında bir CMV otobüsünde yolcu taşımasının yasak olduğunu belirtir (49 CFR 383.25 uyarınca). Kaynak: Alaska DMV CDL Kılavuzu, P Kısıtlaması."},"34":{"q":"Alaska'da N (tanker) onaylı bir CLP sahibi, X kısıtlaması nedeniyle tank araçlarını hangi durumda kullanmakla sınırlıdır?","options":["Yalnızca boş tank araçları, arındırılmamış hazmat kalıntısı olanlar değil","Yalnızca 1.000 galonun altındaki tank araçları","Yalnızca tek akslı tank araçları","Yalnızca özel yollardaki tank araçları"],"explanation":"Alaska CDL Kılavuzu'nun X kısıtlaması, N onaylı bir belge sahibinin yalnızca boş bir tank aracı kullanabileceğini ve daha önce tehlikeli madde içermiş ve kalıntısı arındırılmamış herhangi bir tank aracını kullanmasının yasak olduğunu belirtir. Kaynak: Alaska DMV CDL Kılavuzu, X Kısıtlaması."},"35":{"q":"1 Ocak 2012 itibarıyla geçerli olmak üzere, tüm Alaska CDL sürücüleri kaç tür CMV operasyonundan birini öz beyan etmelidir?","options":["İki","Üç","Dört","Beş"],"explanation":"Alaska CDL Kılavuzu dört öz beyan kategorisi listeler: istisna olmayan eyaletler arası, istisnalı eyaletler arası, istisna olmayan eyalet içi ve istisnalı eyalet içi. Kaynak: Alaska DMV CDL Kılavuzu, Tıbbi Sertifika ve Öz Beyan Gereksinimleri (49 CFR 383.71)."},"36":{"q":"Bir Alaska CDL sahibinin dosyadaki tıbbi muayene sertifikasının süresi dolarsa, eyaletin CDL'yi sınıf düşürmeden önce ne kadar süresi vardır?","options":["Süre dolumundan itibaren 15 gün içinde","Süre dolumundan itibaren 30 gün içinde","Süre dolumundan itibaren 60 gün içinde","Süre dolumundan itibaren 90 gün içinde"],"explanation":"Alaska CDL Kılavuzu, 1 Ocak 2012 itibarıyla geçerli olmak üzere, eyaletin, dosyasında süresi dolmuş tıbbi sertifikası olan herhangi bir CDL sahibini süre dolumundan itibaren 60 gün içinde sınıf düşürmesinin gerektiğini belirtir. Kaynak: Alaska DMV CDL Kılavuzu, Tıbbi Sertifika ve Öz Beyan Gereksinimleri."},"37":{"q":"Alaska'da uygulanan federal ELDT kuralına göre, ilk kez başvuran bir kişi, beceri testine girmeden önce nerede listelenen bir sağlayıcıdan Başlangıç Düzeyi Sürücü Eğitimini tamamlamalıdır?","options":["Alaska DMV'nin dahili eğitim veritabanı","FMCSA Eğitim Sağlayıcı Kayıt Defteri","Eyalet çıraklık konseyi listesi","CDLIS ulusal sürücü kayıt defteri"],"explanation":"Alaska, ilk kez başvuran A veya B Sınıfı başvuru sahipleri, yükseltmeler ve yeni H/P/S onayları için ELDT'yi gerektirir; eğitim, tamamlanmayı beceri testinden önce DMV'ye ileten FMCSA Eğitim Sağlayıcı Kayıt Defteri'nde listelenen bir sağlayıcıdan gelmelidir. Kaynak: Alaska DMV Başlangıç Düzeyi Sürücü Eğitimi (ELDT) sayfası."},"38":{"q":"Alaska yasası/yönetmeliği (2 AAC 90.420) uyarınca, Alaska'da daha önce hiç belge almamış herhangi biri için bir CDL almak üzere doğum ve kimlik belgeleriyle birlikte özellikle hangi belge gereklidir?","options":["Bir Sosyal Güvenlik numarası","Bir pasaport kartı","Bir seçmen kayıt kartı","Bir araç tescil belgesi"],"explanation":"Alaska CDL Kılavuzu 2 AAC 90.420(a)'ya atıfta bulunur: Alaska'da daha önce hiç belge almamış başvuru sahipleri için bir CDL almak üzere doğum ve kimlik belgeleriyle birlikte bir Sosyal Güvenlik numarası gereklidir. Alaska ikametinin ve yasal varlığın kanıtı da gereklidir. Kaynak: Alaska DMV CDL Kılavuzu, Test ve Düzenleme Gereksinimleri; 2 AAC 90.420."},"39":{"q":"Alaska'da, hangi kan alkol konsantrasyonunda (BAC) ticari bir motorlu aracı (CMV) kullanmak yasa dışıdır?","options":["%0,04 veya daha fazla","%0,08 veya daha fazla","%0,02 veya daha fazla","%0,10 veya daha fazla"],"explanation":"Alaska CDL Kılavuzu bölüm 1.3.2, BAC'niz %.04 veya daha fazla ise bir CMV kullanmanın yasa dışı olduğunu belirtir; bu, ticari olmayan sürücüler için olan %0,08 limitinin yarısıdır. Kaynak: Alaska DMV Ticari Sürücü Belgesi Kılavuzu, böl. 1.3.2."},"40":{"q":"Alaska'nın zımni rıza yasası uyarınca, eyalette yalnızca bir CMV kullanarak neyi kabul etmiş olursunuz?","options":["Alkol için nefesinizin kimyasal testine tabi olmayı","Yükünüzün herhangi bir zamanda aranmasına izin vermeyi","Olay yerinden ayrılmadan önce tüm cezai para cezalarını ödemeyi","Kabinde taşınabilir bir nefes test cihazı bulundurmayı"],"explanation":"Alaska CDL Kılavuzu, bir CMV kullandığınızda nefesinizin kimyasal testine zaten rıza göstermiş olduğunuzu ve 'alkol testine rıza göstermiş sayıldığınızı' belirtir. Kaynak: Alaska DMV CDL Kılavuzu, Zımni Rıza / böl. 1.3.2."},"41":{"q":"Bir Alaska CDL sahibi, %0,04 veya daha yüksek BAC ile bir CMV kullanmak gibi ilk ciddi suçunu işler. Asgari diskalifiye süresi nedir?","options":["1 yıl","60 gün","6 ay","3 yıl"],"explanation":"Alaska, ilk ciddi suç (DUI, ret, olay yerinden ayrılma vb.) için bir sürücüyü en az 1 yıl diskalifiye eder. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.2 ve Ciddi Diskalifiye Edici Suçlar tablosu (49 CFR 383.51'i yansıtır)."},"42":{"q":"Bir ilk ciddi suç, sürücü tehlikeli maddeler için plakart takılmış bir CMV kullanırken meydana gelirse, Alaska diskalifiye süresi ne kadardır?","options":["3 yıl","1 yıl","5 yıl","Ömür boyu"],"explanation":"Alaska, suç tehlikeli maddeler için plakart takılmış bir CMV'de meydana geldiğinde ilk ciddi suç diskalifiyesini en az 3 yıla çıkarır. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.2 / Ciddi Diskalifiye Edici Suçlar tablosu."},"43":{"q":"İKİNCİ bir ciddi suç (örneğin bir CMV'de ikinci bir DUI) için Alaska diskalifiye süresi nedir?","options":["Ömür boyu","10 yıl","3 yıl","5 yıl"],"explanation":"Alaska, ikinci bir ciddi suç için bir sürücüyü ömür boyu diskalifiye eder. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.2 ve Ciddi Diskalifiye Edici Suçlar tablosu (49 CFR 383.51)."},"44":{"q":"Bir kontrollü maddenin üretimi, dağıtımı veya temini içeren bir suç işlemek için bir CMV kullanmak, ilk suçta bile hangi Alaska diskalifiyesini taşır?","options":["Ömür boyu, geri verme olmaksızın","1 yıl","3 yıl","10 yıl"],"explanation":"Alaska CDL Kılavuzu, kontrollü maddeler içeren bir suç işlemek için bir CMV kullanırsanız CDL'nizi ömür boyu kaybedeceğinizi belirtir. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.2."},"45":{"q":"Aşağıdakilerden hangisi Alaska CDL Kılavuzu'nda CİDDİ diskalifiye edici bir suç olarak listelenmiştir?","options":["Bir CMV'nin karıştığı bir kazanın olay yerinden ayrılmak","Başka bir aracı çok yakından takip etmek","Limitin 15 mph veya daha fazla üzerinde hız yapmak","Uygunsuz veya düzensiz bir şerit değişikliği"],"explanation":"Bir kazanın olay yerinden ayrılmak ciddi bir suçtur (1 yıl / ömür boyu). Diğer üçü ciddi trafik ihlalleridir, ciddi suçlar değil. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.2 ve 1.3.3."},"46":{"q":"Alaska'da alkol testine tabi olmayı reddederseniz, ilk ret için CDL'nize ne olur?","options":["En az 1 yıl diskalifiye (hazmat taşınıyorsa 3 yıl)","90 gün diskalifiye","Yalnızca bir uyarı; diskalifiye yok","Ömür boyu diskalifiye"],"explanation":"Ret, ciddi bir suç olarak değerlendirilir: en az 1 yıl diskalifiye veya tehlikeli madde taşınıyorsa 3 yıl. Kaynak: Alaska DMV CDL Kılavuzu, Zımni Rıza ve böl. 1.3.2."},"47":{"q":"Alaska CDL Kılavuzu'nun zımni rıza hükmüne göre, bir kimyasal teste tabi olmayı ikinci veya sonraki kez reddetme için asgari diskalifiye süresi nedir?","options":["10 yıl","3 yıl","5 yıl","1 yıl"],"explanation":"Alaska CDL Kılavuzu'nun zımni rıza metni, ikinci ve sonraki retlerin asgari 10 yıllık bir diskalifiye taşıdığını belirtir. Kaynak: Alaska DMV CDL Kılavuzu, Zımni Rıza hükmü."},"48":{"q":"%0,04'ün altında tespit edilebilir herhangi bir miktarda alkol bulunan bir Alaska CMV sürücüsüne ne olur?","options":["24 saat hizmet dışı bırakılır","60 gün diskalifiye edilir","1 yıl diskalifiye edilir","Hizmet dışı bırakma süresi olmaksızın 500 dolar ceza"],"explanation":"Alaska CDL Kılavuzu, %.04'ün altında tespit edilebilir herhangi bir miktarda alkolünüz varsa 24 saat hizmet dışı bırakılacağınızı belirtir. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.2."},"49":{"q":"Bir Alaska CDL sahibi için CİDDİ bir trafik ihlali sayılan, belirlenen limitin üzerindeki asgari hız nedir?","options":["Limitin 15 mph veya daha fazla üzeri","Limitin 10 mph veya daha fazla üzeri","Limitin 20 mph veya daha fazla üzeri","Limitin 5 mph veya daha fazla üzeri"],"explanation":"Aşırı hız, belirlenen limitin 15 mph veya daha fazla üzeri demektir; ciddi bir trafik ihlalidir. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.3."},"50":{"q":"Üç yıllık bir süre içinde bir CMV'de İKİ ciddi trafik ihlali işlemek için Alaska diskalifiye süresi ne kadardır?","options":["En az 60 gün","En az 30 gün","En az 120 gün","En az 1 yıl"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, en az 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.3 ve Ciddi Diskalifiye Edici Suçlar tablosu."},"51":{"q":"Üç yıllık bir süre içinde bir CMV'de ÜÇ veya daha fazla ciddi trafik ihlali işlemek için Alaska diskalifiye süresi ne kadardır?","options":["En az 120 gün","En az 60 gün","En az 90 gün","En az 1 yıl"],"explanation":"3 yıl içinde üç veya daha fazla ciddi trafik ihlali, en az 120 günlük bir diskalifiye ile sonuçlanır. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.3 ve Ciddi Diskalifiye Edici Suçlar tablosu."},"52":{"q":"Bunlardan hangisi Alaska CDL Kılavuzu'nda ciddi bir trafik ihlali olarak listelenMEZ?","options":["%0,04 veya daha yüksek BAC ile bir CMV kullanmak","Bir aracı çok yakından takip etmek","Uygunsuz veya düzensiz şerit değişiklikleri","Uygun CDL sınıfı olmadan bir CMV kullanmak"],"explanation":"%0,04 veya daha yüksek BAC ile araç kullanmak, ciddi bir trafik ihlali değil, CİDDİ bir suçtur. Diğer üçü ciddi trafik ihlalleridir. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.2 ve 1.3.3."},"53":{"q":"Alaska yasası (AS 28.33.190) uyarınca, bir CMV kullanırken mesaj atmak veya elde tutulan bir cep telefonu kullanmak ne olarak sınıflandırılır?","options":["Ciddi bir trafik ihlali (elektronik cihaz kullanımı)","Büyük bir diskalifiye edici suç","Bir hizmet dışı bırakma emri ihlali","Bildirilemez bir kabahat"],"explanation":"Alaska, 'araç kullanırken elektronik cihaz kullanımını' (AS 28.33.190(16)(H)) ciddi diskalifiye edici suçlar arasında listeler ve bu, 60 gün/120 gün eşiklerine doğru sayılır. Kaynak: Alaska DMV CDL Kılavuzu, Ciddi Diskalifiye Edici Suçlar; AS 28.33.190."},"54":{"q":"Bir CMV sürücüsünün, Alaska CDL Kılavuzu'nda açıklanan elde tutulan cep telefonu yasağını ihlal etmesi durumunda karşılaşabileceği azami hukuki ceza nedir?","options":["2.750 dolara kadar","11.000 dolara kadar","500 dolara kadar","1.000 dolara kadar"],"explanation":"Her elde tutulan telefon ihlali, sürücüye 2.750 dolara kadar bir hukuki cezaya tabidir; işverenler 11.000 dolara kadar ceza ile karşılaşır. Kaynak: Alaska DMV CDL Kılavuzu, böl. 2.9.4 (elde tutulan cep telefonları)."},"55":{"q":"Bir CMV kullanırken (hazmat veya yolcu olmaksızın) bir hizmet dışı bırakma (OOS) emrinin İLK ihlali için Alaska diskalifiye süresi nedir?","options":["180 günden az ve 1 yıldan fazla olmamak üzere","90 günden az ve 1 yıldan fazla olmamak üzere","Tam olarak 60 gün","2 yıldan az ve 5 yıldan fazla olmamak üzere"],"explanation":"Alaska, ilk OOS emri ihlalini 180 günden az ve 1 yıldan fazla olmamak üzere diskalifiye eder. Kaynak: Alaska DMV CDL Kılavuzu, Hizmet Dışı Bırakma Emirlerini İhlal tablosu (AS 28.33.140(j))."},"56":{"q":"Tehlikeli madde veya yolcu taşırken işlenen bir İLK hizmet dışı bırakma emri ihlali için Alaska diskalifiye süresi ne kadardır?","options":["180 günden az ve 2 yıldan fazla olmamak üzere","180 günden az ve 1 yıldan fazla olmamak üzere","1 yıldan az ve 5 yıldan fazla olmamak üzere","Tam olarak 120 gün"],"explanation":"Hazmat veya yolcu taşırken işlenen ilk OOS emri ihlali, 180 günden az ve 2 yıldan fazla olmamak üzere diskalifiye edilir. Kaynak: Alaska DMV CDL Kılavuzu, Hizmet Dışı Bırakma Emirlerini İhlal tablosu (AS 28.33.140(j))."},"57":{"q":"10 yıllık bir süre içinde İKİNCİ bir hizmet dışı bırakma emri ihlali (hazmat olmayan) için Alaska diskalifiye süresi nedir?","options":["1 yıldan az ve 5 yıldan fazla olmamak üzere","180 günden az ve 1 yıldan fazla olmamak üzere","3 yıldan az ve 5 yıldan fazla olmamak üzere","Ömür boyu"],"explanation":"10 yıl içinde ikinci bir OOS emri ihlali, 1 yıldan az ve 5 yıldan fazla olmamak üzere taşır; hazmat veya yolcu ile 3 ila 5 yıldır. Kaynak: Alaska DMV CDL Kılavuzu, Hizmet Dışı Bırakma Emirlerini İhlal tablosu."},"58":{"q":"Bir CMV kullanırken İLK demiryolu-karayolu hemzemin geçit ihlali için Alaska diskalifiye süresi nedir?","options":["En az 60 gün","En az 15 gün","En az 120 gün","En az 1 yıl"],"explanation":"Alaska, ilk demiryolu-karayolu hemzemin geçit ihlalini en az 60 gün diskalifiye eder; 3 yıl içinde ikincisi 120 gün ve 3 yıl içinde üçüncüsü 1 yıldır. Kaynak: Alaska DMV CDL Kılavuzu, böl. 1.3.5 / Demiryolu-Karayolu Hemzemin Geçit İhlalleri tablosu."},"59":{"q":"Alaska'da, plakartlı tehlikeli madde taşıyan bir otobüs veya araç, demiryolu-karayolu geçidinde en yakın raya ne kadar mesafe içinde durmak zorundadır?","options":["15 ile 50 feet arasında","5 ile 15 feet arasında","50 ile 100 feet arasında","10 ile 25 feet arasında"],"explanation":"Alaska CDL Kılavuzu (Bölüm 4.3.5 ve 9.6.12), otobüslerin ve plakartlı HazMat araçlarının en yakın raya 15 feet'ten daha yakın ve 50 feet'ten daha uzak olmayacak şekilde durmasını, ardından geçmeden önce bakıp dinlemesini gerektirir."},"60":{"q":"Alaska'nın Move Over (Şerit Boşaltma) yasası uyarınca, bir sürücü aynı yönde iki veya daha fazla şeridi olan bir yolda yanıp sönen ışıklar gösteren durağan bir acil durum aracına yaklaştığında, sürücü şunu yapmalıdır:","options":["Güvenli olduğunda acil durum aracına en yakın şeridi boşaltmalı","Acil durum aracı gidene kadar tamamen durmalı","Korna çalıp belirlenen hızda devam etmeli","Banketе çekip üç dakika beklemeli"],"explanation":"Alaska Yasası AS 28.35.185, aynı yönde iki veya daha fazla şeridi olan bir yoldaki sürücülerin, güvenli olması halinde, yanıp sönen ışıkları olan durağan bir acil durum, itfaiye, kolluk kuvveti, çekici, bakım veya hayvan kontrol aracına en yakın şeridi boşaltmasını gerektirir."},"61":{"q":"Kırmızı ışıkları yanıp sönen bir okul otobüsü için dururken, Alaska yasası yaklaşan bir sürücünün otobüsten en az ne kadar mesafede durmasını gerektirir?","options":["30 feet","15 feet","20 feet","50 feet"],"explanation":"Alaska Yasası AS 28.35.145, yanıp sönen kırmızı ışıkları olan bir okul otobüsüne yaklaşan bir sürücünün otobüsten en az 30 feet mesafede durmasını ve ışıklar yanıp sönmeyi bırakana kadar ilerlememesini gerektirir."},"62":{"q":"Bir ara sokak, ticari bölge veya yerleşim bölgesi dışındaki herhangi bir yolda, aksi belirtilmedikçe Alaska'da bir ticari motorlu taşıt için izin verilen azami yasal hız nedir?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"Alaska İdari Kanunu 13 AAC 03.275, ticari motorlu taşıtlar için azami yasal hızı herhangi bir diğer yolda 55 mph olarak belirler (bir ara sokakta 15 mph, ticari bölgede 20 mph, yerleşim bölgesinde 25 mph)."},"63":{"q":"Alaska'nın okul otobüsü için durma yasası, bölünmüş yollar için bir istisna içerir. Yaklaşan bir sürücünün bir okul otobüsü için durması NE ZAMAN gerekli DEĞİLDİR?","options":["Otobüs, ayrı yolları olan bir karayolunun farklı bir yolundayken","Sürücü limitin en az 10 mph altında seyrederken","Otobüs 100 feet'ten daha uzaktayken","Otobüsün yakınında görünür çocuk yokken"],"explanation":"AS 28.35.145 uyarınca, ayrı yolları olan bir karayolundaki bir sürücünün, farklı bir yolda bulunan bir okul otobüsüyle karşılaşırken veya onu geçerken durması gerekli değildir (bölünmüş yol istisnası)."},"64":{"q":"Alaska'da tek yönlü veya bölünmüş bir karayolunda bir ticari aracı durdurduktan sonra, sürücü üç uyarı üçgenini hangi konumlara yerleştirmelidir?","options":["Yaklaşan trafiğe doğru yaklaşık 10 feet, 100 feet ve 200 feet","Yaklaşan trafiğe doğru yaklaşık 10 feet, 50 feet ve 150 feet","Yaklaşan trafiğe doğru yaklaşık 25 feet, 100 feet ve 250 feet","Yaklaşan trafiğe doğru yaklaşık 50 feet, 100 feet ve 500 feet"],"explanation":"Alaska CDL Kılavuzu'na (Bölüm 2.5) göre, tek yönlü veya bölünmüş bir karayolunda uyarı cihazları, araçtan yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet mesafelere yerleştirilir."},"65":{"q":"Alaska'nın Move Over yasasını (AS 28.35.185) ihlal eden ve kişisel yaralanmaya neden olan bir sürücü hangi suçtan suçludur?","options":["A sınıfı kabahat (class A misdemeanor)","Yalnızca bir ihlal (infraction)","B sınıfı ağır suç (class B felony)","Hiçbir ceza puanı taşımayan bir ihlal"],"explanation":"AS 28.35.185(b), şeridi boşaltma veya yavaşlama yükümlülüğünün yerine getirilmemesinden kişisel yaralanma meydana geldiğinde bir Move Over ihlalini A sınıfı kabahat (class A misdemeanor) yapar; aksi takdirde bir ihlaldir (infraction)."},"66":{"q":"Her iki yönde trafik taşıyan iki şeritli bir yolda, Alaska CDL Kılavuzu bir sürücüye durduktan sonra uyarı üçgenlerini nereye yerleştirmesini söyler?","options":["Aracın 10 feet içinde ve arkasında ve önünde 100 feet'te","Aracın 25 feet içinde ve arkasında ve önünde 200 feet'te","Yalnızca aracın 100 feet arkasında","Yalnızca aracın arkasında 10, 100 ve 200 feet'te"],"explanation":"Alaska CDL Kılavuzu (Bölüm 2.5), bölünmemiş iki yönlü bir yolda, bir üçgeni aracın 10 feet içine ve birer üçgeni de arkasında ve önünde 100 feet'e, banket üzerine veya şeride yerleştirmenizi söyler."},"67":{"q":"Alaska CDL kuralları uyarınca, demiryolu raylarını geçmeden önce zorunlu olarak durmak gereken araç listesi hangisidir?","options":["Plakartlı araçlar, klor taşıyan herhangi bir araç ve tehlikeli maddeler için kullanılan kargo tankı araçları","Yalnızca üçlü römork kombinasyonları","Yalnızca 30'dan fazla yolcu taşıyan otobüsler","Brüt ağırlığı 26.000 pound üzerindeki tüm araçlar"],"explanation":"Alaska CDL Kılavuzu Bölüm 9.6.12, demiryolu geçitlerinde durması gereken araçları listeler: plakartlı araçlar, herhangi bir miktarda klor taşıyan herhangi bir araç ve tehlikeli maddeler için kullanılan (yüklü veya boş) kargo tankı araçları."},"68":{"q":"Bir Alaska CDL sürücüsünün yolda durduktan sonra acil durum uyarı cihazlarını yerleştirmek için ne kadar süresi vardır?","options":["10 dakika içinde","5 dakika içinde","15 dakika içinde","Derhal, 1 dakika içinde"],"explanation":"Alaska CDL Kılavuzu (Bölüm 2.5), bir yolda veya yol kenarında durmanız gerekirse, acil durum uyarı cihazlarınızı 10 dakika içinde yerleştirmeniz gerektiğini belirtir."},"69":{"q":"Bir Alaska CDL sürücüsünün bir ticari aracı yol kenarında durdurması gerektiğinde, gerekli olan üç uyarı cihazı nedir?","options":["Üç kırmızı yansıtıcı üçgen, ya da 6 fişek (fusee), ya da 3 sıvı yakıtlı işaret fişeği (flare)","İki kırmızı fener ve bir kırmızı bayrak","Dört kehribar rengi yansıtıcı","Bir yansıtıcı üçgen ve iki yol fişeği"],"explanation":"Alaska CDL Kılavuzu, park edilmiş araçlar için kabul edilebilir uyarı cihazlarını üç kırmızı yansıtıcı üçgen, en az 6 fişek (fusee) veya 3 sıvı yakıtlı işaret fişeği (flare) olarak listeler."},"70":{"q":"Bir demiryolu geçidinde durması gereken bir Alaska okul otobüsü sürücüsü, geçmeden önce aşağıdakilerden hangisini de yapmalıdır?","options":["Yaklaşan bir treni görme veya duyma yeteneğini iyileştiriyorsa ön kapıyı açmalı","Kornayı üç kez çalmalı","Önce tüm yolcuların otobüsten inmesini sağlamalı","Raylardayken daha düşük bir vitese geçmeli"],"explanation":"Alaska CDL Kılavuzu (Bölüm 4.3.5), otobüs sürücülerine geçişten 15 ile 50 feet önce durmalarını, her iki yöne bakıp dinlemelerini ve bir treni görme veya duyma yeteneğini iyileştiriyorsa ön kapıyı açmalarını söyler."},"71":{"q":"Bir ticari araç, diğer sürücülerin görüşünü 500 feet içinde engelleyen bir tepe veya virajın ötesinde yol kenarında durmuşsa, Alaska CDL sürücüsü uyarı üçgenleriyle ne yapmalıdır?","options":["En arkadaki üçgeni yolun gerisine doğru taşımalı ki engelin ötesinde de uyarı sağlansın","Üç üçgenin de doğrudan aracın arkasına yerleştirmeli","Üçgenleri kaldırıp yalnızca dörtlü flaşörlere güvenmeli","Bir üçgeni kabinin üstüne yerleştirmeli"],"explanation":"Alaska CDL Kılavuzu (Bölüm 2.5), bir tepe, viraj veya başka bir engelin görüş hattını 500 feet içinde engellemesi halinde, sürücünün en arkadaki üçgeni yolun gerisine doğru taşıyarak uyarı sağlamasını söyler."},"72":{"q":"Alaska'da bölünmüş bir karayolunda, çocukları bindiren bir okul otobüsü için durmaktan yaklaşan hangi sürücü muaftır?","options":["Otobüsten bir orta refüj veya bariyerle ayrılmış karşı yoldaki bir sürücü","Aynı şeritte otobüsün hemen arkasındaki bir sürücü","Otobüsü sağ banketten geçen bir sürücü","20 mph altında seyreden herhangi bir sürücü"],"explanation":"AS 28.35.145'in ayrı yollar istisnası, bölünmüş bir karayolunun karşı yolundaki sürücüler için geçerlidir; otobüsle aynı yolda bulunan sürücüler, arkasındakiler dahil, yine de durmak zorundadır."},"73":{"q":"Aynı yönde iki şeritten az şeridin trafik taşıdığı bir yolda, bir sürücü yanıp sönen ışıkları olan durağan bir acil durum aracını geçtiğinde Alaska'nın Move Over yasası ne gerektirir?","options":["Trafik, yol ve hava koşullarını göz önünde bulundurarak makul ve ihtiyatlı bir hıza yavaşlamalı","Belirlenen hız limitini tam olarak korumalı","İlerlemek için işaret verilene kadar tamamen durmalı","Tamamen karşı bankete geçmeli"],"explanation":"AS 28.35.185, aynı yönde ikiden az şeridin bulunduğu yerlerde, sürücünün trafik, yol ve hava koşullarını göz önünde bulundurarak makul ve ihtiyatlı bir hıza yavaşlamasını gerektirir."},"74":{"q":"Alaska'da demiryolu raylarını geçerken, bir CDL sürücüsü şunu yapmalıdır:","options":["Rayları geçerken vites değiştirmemeli","Maksimum kontrol için raylarda birinci vitese düşürmeli","Bir tren görünmüyorsa rayların üzerinde durmalı","Sert şekilde hızlanıp geçişin ortasında vites yükseltmeli"],"explanation":"Alaska CDL Kılavuzu (Bölüm 2.15 ve 9.6.12), sürücüleri rayları geçerken asla vites değiştirmemeleri konusunda uyarır, çünkü kaçırılan bir vites aracı geçidin üzerinde stop etmiş halde bırakabilir."},"75":{"q":"Alaska'da bir oversize (büyük boyut) izni olmadan kamuya açık bir karayolunda seyahat edebilecek azami yasal araç/yük genişliği nedir?","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","120 inches (10 feet)","108 inches (9 feet)"],"explanation":"Alaska'nın Oversize/Overweight İzin Kılavuzu, 17 AAC 25'in 102 inç (8 feet 6 inches) yasal genişlik sınırlamasına atıfta bulunur; daha geniş olan herhangi bir şey bir izin ve OVERSIZE/WIDE LOAD tabelaları gerektirir."},"76":{"q":"Alaska'nın oversize-izin kuralları uyarınca, geniş bir yük, genişliği şu değeri aştığında tüm güzergahlarda en az bir pilot/eskort aracı gerektirir:","options":["10 feet 6 inches","8 feet 6 inches","12 feet","9 feet"],"explanation":"Alaska'nın Oversize/Overweight İzin Kılavuzu (Bölüm 6.2.1), bir araç veya yük genişlikte 10 feet 6 inches'ı aştığında tüm güzergahlarda en az bir pilot/eskort aracı gerektirir."},"77":{"q":"Alaska'nın izin kuralları uyarınca, yükseklikte 17 feet'i aşan bir yük, (daha kısıtlayıcı bir faktör olmadığında) hangi azami karayolu hızıyla sınırlıdır?","options":["45 mph","55 mph","35 mph","25 mph"],"explanation":"Alaska'nın Oversize/Overweight İzin Kılavuzu (Bölüm 9.3.1), yükseklikte 17 feet'in üzerindeki yükleri, diğer faktörler daha kısıtlayıcı olmadıkça azami 45 mph karayolu hızıyla sınırlar."},"78":{"q":"Trafiği kontrol eden bir sinyal ışığı veya görevlisi bulunmayan bir Alaska açılır köprüsünde (drawbridge), bir CDL sürücüsü nerede durmalıdır?","options":["Köprünün açılan kısmından en az 50 feet önce","Köprünün açılan kısmından en az 15 feet önce","Köprünün açılan kısmından en az 100 feet önce","Doğrudan açılan kısmın kenarında"],"explanation":"Alaska CDL Kılavuzu (Bölüm 4.3.6), sinyal ışığı veya trafik kontrol görevlisi bulunmayan bir açılır köprünün açılan kısmından en az 50 feet önce durmayı ve geçmeden önce açılan kısmın tamamen kapalı olduğunu doğrulamayı gerektirir."},"79":{"q":"Hangi Alaska eyalet kurumu Ticari Sürücü Belgelerini (CDL) verir?","options":["Alaska Motorlu Taşıtlar Dairesi (DMV)","Alaska Kamu Güvenliği Departmanı","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)","Alaska Ulaştırma ve Kamu Tesisleri Departmanı (DOT&PF)"],"explanation":"Alaska'da, Motorlu Taşıtlar Dairesi (DMV), CDL veren ve bilgi ile beceri testlerini uygulayan Eyalet Sürücü Belgelendirme Kurumudur. FMCSA federal CDL standartlarını belirler ancak belgeyi vermez. Kaynak: Alaska DMV, Commercial Driver's License (CDL) sayfası."},"80":{"q":"Bir başvuru sahibinin her Alaska CDL bilgi testini geçmek için elde etmesi gereken asgari puan nedir?","options":["70%","75%","80%","90%"],"explanation":"Alaska, her CDL bilgi testini (genel bilgi ve herhangi bir onay testi) geçmek için en az 80% puan gerektirir. Kaynak: Alaska DMV CDL Kılavuzu / Alaska DMV CDL gereklilikleri."},"81":{"q":"Alaska CDL beceri testi üç bölüme ayrılır. Hangi grup üçünü de doğru şekilde listeler?","options":["Sefer öncesi muayene, temel araç kontrolü ve yolda sürüş","Görme taraması, yazılı bilgi ve yolda sürüş","Sefer öncesi muayene, hava fren kontrolü ve paralel park","Geri gitme, bağlama/çözme ve süreli manevra kabiliyeti parkuru"],"explanation":"Alaska'nın CDL beceri testi üç bölümden oluşur: sefer öncesi (araç) muayene testi, temel araç kontrol becerileri testi ve yolda sürüş testi. Kaynak: Alaska DMV CDL Kılavuzu."},"82":{"q":"Alaska CDL yolda sürüş beceri testinde kullanılan aracı sağlamaktan kim sorumludur?","options":["Başvuru sahibi, sürmeyi planladığı sınıf ve türü temsil eden bir araç sağlamalıdır","DMV tüm başvuru sahipleri için standart bir test aracı sağlar","FMCSA Eğitim Sağlayıcı Sicili bir araç atar","Alaska DOT&PF kendi motor havuzundan bir araç ödünç verir"],"explanation":"Başvuru sahibi, sürmeyi planladığı aynı sınıf ve türden kendi temsili aracını getirmelidir; DMV ofisi bir test aracı sağlamaz. Kaynak: Alaska DMV CDL Kılavuzu / Alaska DMV CDL gereklilikleri."},"83":{"q":"Bir Ticari Öğrenci İzni (CLP) verildikten sonra, bir Alaska başvuru sahibinin CDL beceri (yol) testine girmeden önce ne kadar beklemesi gerekir?","options":["En az 14 days","En az 7 days","En az 30 days","Bekleme süresi yoktur"],"explanation":"Alaska, bir CLP sahibinin CDL için herhangi bir yol testine girmeden önce CLP verildikten sonra en az 14 days beklemesini gerektiren federal kuralı izler. Kaynak: Alaska DMV CLP sayfası (49 CFR 383.25)."},"84":{"q":"Bir Alaska Ticari Öğrenci İzni (CLP) yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["180 days","30 days","1 year","5 years"],"explanation":"Bir Alaska CLP 180 days geçerlidir ve genel bilgi testini yeniden almadan ek bir 180 days için bir kez yenilenebilir (yeniden verilebilir). Kaynak: Alaska DMV CLP bilgileri (49 CFR 383.25)."},"85":{"q":"Alaska'nın izlediği federal standart uyarınca, bir Alaska CLP ek bir 180 günlük dönem için kaç kez yenilenebilir/yeniden verilebilir?","options":["Bir kez","Hiç yenilenemez","İki kez","Sınırsız sayıda"],"explanation":"Bir CLP 180 days geçerlidir ve ek bir 180 days için bir kez yenilenebilir (toplamda azami 360 days). Kaynak: Alaska DMV CLP bilgileri (49 CFR 383.25)."},"86":{"q":"İlk kez başvuran biri, A Sınıfı veya B Sınıfı bir belge için Alaska CDL beceri testine girmeden önce hangi eğitimi tamamlamış olmalıdır?","options":["FMCSA Eğitim Sağlayıcı Sicili'nde listelenen bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi (ELDT)","Alaska Mahkeme Sistemi tarafından onaylanmış bir savunma sürüş kursu","40 saatlik bir Alaska kış sürüşü sertifikası","Alaska Çalışma Departmanı'na kayıtlı bir çıraklık"],"explanation":"7 Şubat 2022'den bu yana, ilk kez CDL başvurusunda bulunanlar, beceri testine girmeden önce FMCSA Eğitim Sağlayıcı Sicili'ndeki bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi'ni (ELDT) tamamlamalıdır; eyalet kaydın gönderildiğini doğrulamalıdır. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380), Alaska DMV tarafından uygulanır."},"87":{"q":"Alaska'da CDL öz-belgelendirme (self-certification), bir sürücünün yapmayı beklediği faaliyet türünü beyan etmesini gerektirir. Kaç öz-belgelendirme kategorisi vardır?","options":["Dört","İki","Üç","Beş"],"explanation":"Sürücüler, interstate/intrastate ile excepted/non-excepted faaliyetin birleştirilmesiyle oluşturulan dört kategoriden birine öz-belgelendirme yapmalıdır. Kaynak: Alaska DMV CDL Self-Certification Requirement sayfası."},"88":{"q":"Aşağıdakilerden hangisi dört Alaska CDL öz-belgelendirme kategorisinden biridir?","options":["Interstate non-excepted","Interstate seasonal (mevsimlik)","Intrastate hazardous-only (yalnızca tehlikeli)","Federal exempt carrier (federal muaf taşıyıcı)"],"explanation":"Dört kategori şunlardır: interstate non-excepted, interstate excepted, intrastate non-excepted ve intrastate excepted. \"Interstate non-excepted\", federal DOT tıbbi kart gerekliliklerini karşılaması gereken sürücüler için olan kategoridir. Kaynak: Alaska DMV CDL Self-Certification Requirement sayfası."},"89":{"q":"\"Non-excepted\" (interstate veya intrastate) olarak öz-belgelendirme yapan bir Alaska sürücüsünün DMV'ye hangi belgeyi sunması gerekir?","options":["Geçerli bir DOT tıbbi muayene sertifikası (tıbbi kart)","Noter onaylı bir işveren sponsorluk mektubu","Federal tıbbi standartlardan imzalı bir feragatname","Bir Alaska ticari araç muayene çıkartması"],"explanation":"Non-excepted sürücüler, CDL ayrıcalıklarını korumak için geçerli bir DOT tıbbi muayene sertifikasına (tıbbi kart) sahip olmalı ve bunu sunmalıdır; excepted sürücülerin bunu sunmaları gerekmez. Kaynak: Alaska DMV CDL Self-Certification Requirement sayfası."},"90":{"q":"Bir Alaska CDL sahibi öz-belgelendirmesini ve DOT tıbbi muayene sertifikasını DMV'ye nasıl sunabilir?","options":["Form 413'ü doldurarak ve tıbbi kartın okunaklı bir kopyasını DMV'nin CDL e-posta adresine sunarak veya e-postayla göndererek","Kartı yalnızca FMCSA Eğitim Sağlayıcı Sicili'ne yükleyerek","Kartın aslını doğrudan Washington, D.C.'deki FMCSA'ya postalayarak","Alaska Çalışma ve İşgücü Geliştirme Departmanı'na dosyalayarak"],"explanation":"Sürücüler, her başvuruda öz-belgelendirmeyi (Form 413) tamamlar ve tıbbi kartı bir DMV ofisinde sunar veya okunaklı bir kopyasını DMV'nin CDL adresine (doa.dmv.cdl@alaska.gov) e-postayla gönderir. Kaynak: Alaska DMV CDL Self-Certification Requirement sayfası."},"91":{"q":"Bir non-excepted CDL sahibi, güncel bir DOT tıbbi muayene sertifikasını DMV'de dosyada tutmazsa Alaska'da bunun sonucu nedir?","options":["CDL ayrıcalıkları düşürülür veya iptal edilir","Bir defaya mahsus 500 dolarlık federal ceza uygulanır ancak CDL geçerli kalır","Hiçbir şey, çünkü tıbbi kart yalnızca işverende dosyalanır","Sürücü otomatik olarak excepted intrastate sürücü olarak yeniden sınıflandırılır"],"explanation":"Bir non-excepted sürücünün tıbbi belgelendirmesinin süresi dolarsa, Alaska DMV CDL ayrıcalıklarını iptal eder veya düşürür; bundan sonra bir CMV kullanmak, uygun ayrıcalıklar olmadan sürmek demektir. Kaynak: Alaska DMV CDL Self-Certification Requirement sayfası."},"92":{"q":"Bir Alaska CDL yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["5 years","4 years","8 years","2 years"],"explanation":"Bir Alaska CDL 5 years geçerlidir ve sahibinin doğum gününde sona erer. Kaynak: Alaska DMV yenileme bilgileri."},"93":{"q":"Bir Alaska CDL'si genellikle yenileme yılı içinde hangi tarihte sona erer?","options":["Sahibinin doğum gününde","31 Aralık'ta","Doğum gününden bağımsız olarak veriliş tarihinden tam beş yıl sonra","Veriliş ayının son gününde"],"explanation":"Alaska sürücü belgeleri, CDL'ler dahil, 5 years için verilir ve sahibinin doğum gününde sona erer. Kaynak: Alaska DMV yenileme bilgileri."},"94":{"q":"Bir Alaska CDL sahibi yenileme sürecine süre dolmadan ne kadar önce başlayabilir?","options":["Süre dolmadan 1 year öncesine kadar","Süre dolmadan 30 days öncesine kadar","Yalnızca süre dolma tarihinde","Süre dolduktan 6 months sonrasına kadar"],"explanation":"Alaska, CDL yenilemesinin belgenin süresi dolmadan en erken bir yıl önce başlamasına izin verir; eyalet, süresi dolmuş bir belge için hiçbir ek süre (grace period) sunmaz. Kaynak: Alaska DMV yenileme bilgileri."},"95":{"q":"Orijinal bir Alaska CDL'ye başvururken hangi belge seti gereklidir?","options":["ABD vatandaşlığı/yasal varlık kanıtı, bir Alaska ikamet/yerleşim adresi, bir Sosyal Güvenlik Numarası ve uygun olduğunda bir DOT tıbbi kartı","Yalnızca güncel bir eyalet dışı CDL ve bir pasaport fotoğrafı","Bir araç tapusu, sigorta kanıtı ve bir Alaska balıkçılık ruhsatı","Yalnızca bir FMCSA taşıyıcı numarası ve noter onaylı bir beyanname"],"explanation":"Alaska; vatandaşlık/yasal varlık kanıtı, bir Alaska ikamet adresi (yerleşim) kanıtı, bir Sosyal Güvenlik Numarası, güncel bir sürücü belgesi ve uygun olduğunda bir DOT tıbbi kartı gerektirir. Kaynak: Alaska DMV Commercial Driver's License (CDL) sayfası."},"96":{"q":"Intrastate (Alaska içi) faaliyetle sınırlı bir Alaska CDL'si almak için asgari yaş kaçtır?","options":["18 yaşında","16 yaşında","21 yaşında","25 yaşında"],"explanation":"Bir Alaska CDL için asgari yaş, intrastate faaliyet için 18'dir; interstate faaliyet, hazmat ve okul otobüsü onayları 21 yaş gerektirir. Kaynak: Alaska DMV CDL / CLP sayfaları."},"97":{"q":"Eyaletler arası (interstate) ticarette faaliyet göstermek veya tehlikeli maddeler taşımak isteyen bir sürücünün, bu faaliyet için bir Alaska CDL'sine sahip olmak üzere en az kaç yaşında olması gerekir?","options":["21 yaşında","18 yaşında","19 yaşında","25 yaşında"],"explanation":"Alaska, bir sürücünün interstate faaliyet göstermesi veya bir hazmat ya da okul otobüsü onayına sahip olması için en az 21 yaşında olmasını gerektirir; yalnızca intrastate CDL'ler ise 18 yaşında alınabilir. Kaynak: Alaska DMV CDL / CLP sayfaları."},"98":{"q":"Alaska CDL başvuru ücretleriyle ilgili olarak, sürecin nasıl işlediğine dair hangi ifade doğrudur?","options":["Geçerli CDL ve yol testi ücretleri başvuru sırasında DMV'ye ödenir ve tam tutarlar eyalet tarafından belirlenir ve zaman içinde değişebilir","Alaska orijinal bir CDL için hiçbir ücret almaz","Tüm CDL ücretleri DMV'ye değil, doğrudan FMCSA'ya ödenir","Başvuru sahibi başarısız olursa yol testi ücreti tamamen iade edilir"],"explanation":"Alaska CDL başvuru sahipleri, başvuru sırasında geçerli belge ve yol testi ücretlerini DMV'ye öder; belirli dolar tutarları eyalet tarafından belirlenir ve değişikliğe tabidir, bu nedenle güvenilir nokta sabit bir tutar değil, sürecin kendisidir. Kaynak: Alaska DMV CDL sayfası / ücret cetveli."}},"es":{"0":{"q":"En Alaska, ¿cuál es el ancho máximo legal de un vehículo, incluida su carga, en el sistema de carreteras estatales?","options":["102 inches","96 inches","108 inches","114 inches"],"explanation":"Alaska establece el ancho máximo del vehículo, incluida la carga, en 102 inches; el equipo acoplado no puede sobresalir más de 3 inches de ese límite a cada lado. Fuente: 17 AAC 25.012(a) (Alaska DOT&PF, Capítulo 25 Operaciones, Vehículos con Ruedas), conforme al Manual CDL de Alaska."},"1":{"q":"¿Cuál es la altura máxima legal general de un vehículo y su carga en la mayoría de las carreteras de Alaska?","options":["15 feet","13 feet 6 inches","14 feet","16 feet"],"explanation":"Conforme a 17 AAC 25.012(b), un vehículo de Alaska, incluida la carga, no puede exceder los 15 feet de altura, salvo en el corredor de las carreteras Dalton/Elliott entre la Fox Weigh Station y Prudhoe Bay, donde se permiten 17 feet. Fuente: 17 AAC 25.012(b), Alaska DOT&PF."},"2":{"q":"En las carreteras Dalton y Elliott, entre la Fox Weigh Station y Prudhoe Bay, ¿qué altura aumentada se permite para un vehículo y su carga?","options":["15 feet 6 inches","16 feet","17 feet","18 feet"],"explanation":"17 AAC 25.012(b) permite una altura, incluida la carga, de 17 feet para un vehículo que opera entre la Fox Weigh Station y Prudhoe Bay en las carreteras Dalton y Elliott, frente al límite general de 15 feet. Fuente: 17 AAC 25.012(b), Alaska DOT&PF."},"3":{"q":"En las rutas del National Highway System de Alaska, ¿cuál es la longitud máxima de un solo vehículo motriz (el camión o el tractocamión en sí)?","options":["40 feet","48 feet","53 feet","45 feet"],"explanation":"17 AAC 25.012(c)(1) limita la longitud de un vehículo motriz a 45 feet en las rutas del NHS (y 17 AAC 25.012(d)(1) establece el mismo límite de 45 feet en el resto del sistema de carreteras estatales). Fuente: 17 AAC 25.012, Alaska DOT&PF."},"4":{"q":"En Alaska, ¿cuál es la longitud máxima de transporte de carga de un semirremolque o remolque utilizado en una combinación?","options":["48 feet","57 feet","60 feet","53 feet"],"explanation":"17 AAC 25.012(c)(3) y (e)(1) limitan la longitud de transporte de carga de un semirremolque o remolque a 53 feet en todas las rutas. Fuente: 17 AAC 25.012, Alaska DOT&PF."},"5":{"q":"¿Cuál es la longitud total máxima de una combinación estándar formada por un camión y un vehículo de carga, o un tractocamión y dos vehículos de carga, en las carreteras de Alaska?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"17 AAC 25.012(c)(4) y (d)(3) limitan dichas combinaciones a una longitud total de 75 feet; un tractocamión con un solo vehículo de carga no está sujeto a un límite de longitud total. Fuente: 17 AAC 25.012, Alaska DOT&PF."},"6":{"q":"En Alaska, ¿hasta dónde puede sobresalir una carga o equipo más allá del parachoques delantero del vehículo antes de superar el límite legal?","options":["3 feet","4 feet","5 feet","6 feet"],"explanation":"17 AAC 25.012(c)(6) y (d)(4) permiten que una carga o equipo sobresalga no más de 3 feet más allá del parachoques delantero (y no más de 4 feet por la parte trasera). Fuente: 17 AAC 25.012, Alaska DOT&PF."},"7":{"q":"En Alaska, ¿hasta dónde puede sobresalir una carga más allá de la parte trasera de un vehículo antes de superar el límite legal?","options":["3 feet","5 feet","6 feet","4 feet"],"explanation":"17 AAC 25.012(c)(6)(B) y (d)(4)(B) permiten un saliente trasero de no más de 4 feet (el saliente delantero está limitado a 3 feet). Fuente: 17 AAC 25.012, Alaska DOT&PF."},"8":{"q":"¿Cuál es el peso máximo legal permitido en un solo eje en Alaska?","options":["18,000 pounds","22,400 pounds","34,000 pounds","20,000 pounds"],"explanation":"17 AAC 25.013(a)(4) establece el límite de peso de un solo eje en 20,000 pounds, con una separación mínima de 8'1\" para que un eje cuente como un solo eje. Fuente: 17 AAC 25.013, Alaska DOT&PF."},"9":{"q":"Según la tabla de grupos de ejes de Alaska, ¿cuál es el peso máximo permitido en un grupo de 2 ejes (eje tándem)?","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"explanation":"La tabla de pesos por grupo de ejes de Alaska en 17 AAC 25.013(a)(4) permite 38,000 pounds en un grupo de 2 ejes (tándem), lo cual es mayor que el estándar federal de 34,000 pounds para tándem usado en muchos estados. Fuente: 17 AAC 25.013, Alaska DOT&PF."},"10":{"q":"Según la tabla de pesos por grupo de ejes de Alaska, ¿cuál es el peso máximo permitido en un grupo de 3 ejes?","options":["38,000 pounds","46,000 pounds","50,000 pounds","42,000 pounds"],"explanation":"17 AAC 25.013(a)(4) permite 42,000 pounds en un grupo de 3 ejes (con una separación mínima entre ejes de 3'6\"). Fuente: 17 AAC 25.013, Alaska DOT&PF."},"11":{"q":"¿Qué separación mínima entre ejes debe mantenerse para que un eje se considere un 'solo eje' en lugar de parte de un grupo de ejes en Alaska?","options":["8 feet 1 inch","3 feet 6 inches","6 feet","10 feet"],"explanation":"Según la nota a 17 AAC 25.013(a)(4), cualquier eje separado menos de 8 feet 1 inch de otro eje (de centro a centro) se considera parte de un grupo de ejes; el límite de un solo eje se aplica con una separación mínima de 8'1\". Fuente: 17 AAC 25.013, Alaska DOT&PF."},"12":{"q":"¿Cómo determina Alaska el peso bruto máximo del vehículo para una combinación larga?","options":["Un tope fijo de 80,000 pounds en todas las carreteras","Multiplicando la cantidad de ejes por 20,000 pounds","Aplicando la Bridge Gross Weight Formula del estado según la cantidad de ejes y su separación","Por un límite fijo de 105,500 pounds establecido por estatuto"],"explanation":"17 AAC 25.013(a)(6) establece el peso bruto máximo mediante la Bridge Gross Weight Formula W = 500[LN/(N-1) + 12N + 36] (con +3,000 añadidos cuando no hay ejes elevables en el grupo motriz), no mediante un tope fijo de 80,000 pounds. Fuente: 17 AAC 25.013, Alaska DOT&PF."},"13":{"q":"En la Bridge Gross Weight Formula de Alaska W = 500[LN/(N-1) + 12N + 36], ¿qué representa la variable 'L'?","options":["El peso legal de la carga en toneladas","La distancia en feet entre los centros de los ejes extremos","La longitud del remolque más largo","La capacidad del eje elevable"],"explanation":"En 17 AAC 25.013(a)(6), 'L' es la distancia en feet enteros medida entre los centros de los ejes extremos del vehículo o combinación, y 'N' es la cantidad de ejes. Fuente: 17 AAC 25.013, Alaska DOT&PF."},"14":{"q":"¿Cuál es el peso máximo permitido en una llanta en Alaska, según el ancho nominal de llanta del fabricante?","options":["600 pounds por inch de ancho de llanta","500 pounds por inch de ancho de llanta","550 pounds por inch de ancho de llanta","650 pounds por inch de ancho de llanta"],"explanation":"17 AAC 25.013(a)(1) limita el peso por llanta a 600 pounds por inch lineal de ancho de llanta, según la clasificación del ancho nominal de llanta del fabricante. Fuente: 17 AAC 25.013, Alaska DOT&PF."},"15":{"q":"¿Cuándo se requiere un permiso de sobredimensión/sobrepeso del Alaska DOT&PF?","options":["Solo para cargas de más de 100,000 pounds de peso bruto","Cuando un vehículo o carga excede las dimensiones o pesos máximos de 17 AAC 25 y va a circular por una vía pública","Solo al cruzar la frontera estatal hacia Canadá","Solo para vehículos de más de 12 feet de ancho"],"explanation":"Según el Administrative Permit Manual (Sec. 2.2.1) y 17 AAC 25.320, se requiere un permiso siempre que un vehículo o un vehículo con carga exceda las dimensiones o pesos máximos de 17 AAC 25 y solicite circular por una vía pública. Fuente: Alaska DOT&PF Administrative Permit Manual; 17 AAC 25.320."},"16":{"q":"Alaska emite permisos de sobredimensión/sobrepeso únicamente para cargas que cumplen con cuál de las siguientes condiciones?","options":["Cargas divisibles que pueden separarse en porciones legales","Cargas no divisibles que no pueden reducirse a un tamaño o peso legal","Cargas propiedad de agencias gubernamentales","Cargas que transportan materiales peligrosos"],"explanation":"Los permisos de Alaska se emiten para cargas no divisibles (aquellas que no pueden reducirse de forma práctica a dimensiones/peso legales); las cargas divisibles deben desglosarse hasta los límites legales. Fuente: Alaska DOT&PF Administrative Permit Manual Sec. 2.2 y 17 AAC 25.320(a)(1)."},"17":{"q":"En Alaska, ¿cuál es el período de validez estándar de un permiso de sobredimensión/sobrepeso para un solo viaje (para un traslado de 400 miles o menos en un solo sentido)?","options":["1 day","3 days","7 days","30 days"],"explanation":"Según el Administrative Permit Manual Sec. 3.2.1, un permiso de un solo viaje es válido por un período de 3 days (ampliado a 5 days si se viaja más de 400 miles en un solo sentido). Fuente: Alaska DOT&PF Administrative Permit Manual."},"18":{"q":"Durante los meses de invierno en Alaska, ¿qué margen adicional de peso bruto puede otorgarse por la acumulación documentada de nieve y hielo en un vehículo?","options":["500 pounds","1,000 pounds","1,500 pounds","2,000 pounds"],"explanation":"17 AAC 25.335(b)(1) otorga un margen adicional de 1,500 pounds desde el 1 de octubre hasta el 30 de abril cuando hay evidencia de acumulación de nieve y hielo; este es el máximo independientemente del tipo de combinación. Fuente: 17 AAC 25.335, Alaska DOT&PF."},"19":{"q":"¿Qué clase de CDL exige Alaska para operar un solo vehículo con una clasificación de peso bruto vehicular (GVWR) de 26,001 pounds o más, como un camión volquete o un autobús de pasajeros?","options":["Class A","Class B","Class C","Class D"],"explanation":"El Manual CDL de Alaska define la Class B como cualquier vehículo individual con un GVWR superior a 26,001 pounds, o dicho vehículo remolcando una unidad que no pese 10,000 lbs o más (camiones volquete, mezcladoras de cemento, camiones de caja, autobuses de pasajeros). Fuente: Alaska DMV CDL Manual, Sección 1, Clasificaciones de Vehículos."},"20":{"q":"Según el Manual CDL de Alaska, se requiere una CDL Class A para cualquier combinación de vehículos con un GCWR de 26,001 lbs o más, siempre que el GVWR de la(s) unidad(es) remolcada(s) exceda qué peso?","options":["8,000 pounds","10,000 pounds","16,000 pounds","26,001 pounds"],"explanation":"Alaska define la Class A como una combinación con un GCWR de 26,001+ lbs en la que el GVWR del vehículo o vehículos remolcados es superior a 10,000 pounds (por ejemplo, camiones de 18 ruedas, camiones madereros). Fuente: Alaska DMV CDL Manual, Sección 1, definición de Class A."},"21":{"q":"Según las reglas de Alaska, un vehículo con un GVWR inferior a 26,001 lbs aún entra en el programa CDL (Class C) si está diseñado para transportar cuántos pasajeros, incluido el conductor?","options":["8 o más","11 o más","15 o más","16 o más"],"explanation":"El Manual CDL de Alaska incluye un vehículo más pequeño en el programa CDL como Class C si está diseñado para transportar 16 o más pasajeros incluido el conductor, o transporta materiales peligrosos que requieren rótulos. Fuente: Alaska DMV CDL Manual, Sección 1, definición de Class C."},"22":{"q":"En Alaska, ¿qué letra de endoso se coloca en la CDL para transportar materiales peligrosos en cantidades que requieren rótulos?","options":["Endoso H","Endoso N","Endoso X","Endoso T"],"explanation":"Alaska usa el endoso H (HazMat) para cualquier vehículo utilizado para transportar materiales peligrosos en cantidades que requieren rótulos. Fuente: Alaska DMV CDL Manual, Sección 1, tabla de Endosos."},"23":{"q":"¿Qué endoso exige Alaska para cualquier vehículo destinado al transporte de líquidos a granel (camiones cisterna)?","options":["Endoso H","Endoso N","Endoso P","Endoso T"],"explanation":"El Manual CDL de Alaska indica el endoso N (Cisterna) para cualquier vehículo destinado al transporte de líquidos a granel. Tenga en cuenta que la letra de código de Alaska para el endoso de cisterna es N. Fuente: Alaska DMV CDL Manual, Sección 1, tabla de Endosos."},"24":{"q":"¿Qué endoso de CDL de Alaska se requiere para arrastrar remolques dobles o triples?","options":["Endoso N","Endoso P","Endoso T","Endoso X"],"explanation":"Alaska asigna el endoso T (Remolques Dobles o Triples) para combinaciones que arrastran dos o tres remolques; solo se requiere un examen de conocimientos. Fuente: Alaska DMV CDL Manual, Sección 1, tabla de Endosos."},"25":{"q":"Según el Manual CDL de Alaska, ¿qué endoso se requiere para un vehículo diseñado para transportar 16 o más pasajeros (incluido el conductor)?","options":["Endoso S","Endoso P","Endoso N","Endoso H"],"explanation":"Alaska requiere el endoso P (Pasajeros) para cualquier vehículo diseñado para transportar 16 o más pasajeros incluido el conductor, sin importar cuántos se transporten realmente. Requiere un examen de conocimientos y de destrezas de manejo. Fuente: Alaska DMV CDL Manual, Sección 1, tabla de Endosos."},"26":{"q":"En Alaska, ¿qué combinación representa el endoso X en una CDL?","options":["Cisterna y materiales peligrosos combinados","Pasajeros y autobús escolar combinados","Dobles y triples combinados","Frenos de aire y cisterna combinados"],"explanation":"Alaska usa el endoso X para una operación combinada de cisterna/materiales peligrosos: cualquier vehículo cisterna utilizado para transportar cantidades de materiales peligrosos que requieren rótulos. Requiere un examen de conocimientos y una verificación de antecedentes. Fuente: Alaska DMV CDL Manual, Sección 1, tabla de Endosos."},"27":{"q":"Antes de que Alaska emita o renueve una CDL con un endoso de materiales peligrosos (H), el solicitante debe completar primero qué paso?","options":["Un curso de manejo defensivo","Una verificación de antecedentes de la Transportation Security Administration","Un período de espera de 30 days","Un curso de inspección de vehículos comerciales"],"explanation":"El Manual CDL de Alaska establece que todos los solicitantes que obtengan, agreguen o renueven un endoso HazMat deben aprobar una verificación de antecedentes antes de la emisión, tramitada a través de TSA/universalenroll.dhs.gov. Fuente: Alaska DMV CDL Manual, Sección 1, notas del Endoso H."},"28":{"q":"¿Cuál es la edad mínima para que se emita una CDL de Alaska restringida al comercio intraestatal (solo dentro del estado)?","options":["16 years","17 years","18 years","21 years"],"explanation":"El Manual CDL de Alaska establece que un solicitante debe tener al menos 18 years de edad para operar en comercio intraestatal (vigente desde el 11/14/19) al momento de la solicitud, y haber tenido una licencia de conducir válida durante al menos un año. Fuente: Alaska DMV CDL Manual, Sección 1, Requisitos de edad."},"29":{"q":"¿Qué edad mínima exige Alaska para que un titular de CDL opere en comercio interestatal?","options":["18 years","19 years","20 years","21 years"],"explanation":"El Manual CDL de Alaska establece que un solicitante debe tener al menos 21 years de edad para operar en comercio interestatal. Los conductores menores de 21 reciben una restricción K (solo intraestatal). Fuente: Alaska DMV CDL Manual, Sección 1, Requisitos de edad y Restricción K."},"30":{"q":"Según la regla federal y la práctica de Alaska, ¿cuánto tiempo debe poseer un solicitante un Commercial Learner's Permit (CLP) antes de presentar el examen de destrezas de manejo de la CDL?","options":["Al menos 7 days","Al menos 10 days","Al menos 14 days","Al menos 30 days"],"explanation":"El Manual CDL de Alaska establece que un solicitante debe poseer un CLP durante al menos 14 days antes de presentar un examen de destrezas de manejo, incluso al subir de clase o agregar un endoso que requiera un examen de destrezas. Fuente: Alaska DMV CDL Manual, Sección 1, Requisitos de Examen y Emisión."},"31":{"q":"Antes de obtener un Commercial Learner's Permit de Alaska, ¿qué debe poseer ya el solicitante?","options":["Una licencia de conducir no comercial de Alaska válida y vigente","Un número de autoridad operativa federal del DOT","Un certificado de aprendizaje completado","Una CDL previa de otro estado"],"explanation":"La página del CLP del Alaska DMV exige que los solicitantes tengan una licencia de conducir no comercial de Alaska válida y vigente antes de que se les emita un CLP. Fuente: Alaska DMV Commercial Learner's Permit (CLP) page."},"32":{"q":"Al conducir con un CLP de Alaska, el conductor con licencia que acompaña en el asiento contiguo al titular del permiso debe tener la clase/endosos adecuados y tener al menos qué edad?","options":["18 years","19 years","21 years","25 years"],"explanation":"Según la página del CLP del Alaska DMV, un titular de CLP solo puede operar un vehículo de su clase o uno menor, con un conductor con licencia válida en el asiento contiguo que tenga al menos 21 años, posea la clase y los endosos correspondientes, y haya tenido licencia durante un año. Fuente: Alaska DMV Commercial Learner's Permit (CLP) page."},"33":{"q":"Un titular de CLP en Alaska que tiene un endoso de Pasajeros (P) está sujeto a qué restricción?","options":["Solo puede conducir autobuses de pasajeros vacíos en propiedad privada","No puede transportar pasajeros en un autobús CMV salvo examinadores, aprendices y el titular de CDL acompañante especificados","Puede transportar hasta 8 pasajeros durante las horas de luz","Solo puede transportar pasajeros en rutas intraestatales"],"explanation":"La restricción P del Manual CDL de Alaska establece que a un titular de CLP con un endoso P se le prohíbe transportar pasajeros en un autobús CMV, salvo auditores federales/estatales, inspectores, examinadores, otros aprendices y el titular de CDL acompañante (según 49 CFR 383.25). Fuente: Alaska DMV CDL Manual, Restricción P."},"34":{"q":"Un titular de CLP en Alaska con un endoso N (cisterna) está limitado por la restricción X a operar vehículos cisterna en qué condición?","options":["Solo vehículos cisterna vacíos, no aquellos con residuo de hazmat sin purgar","Solo vehículos cisterna de menos de 1,000 gallons","Solo vehículos cisterna de un solo eje","Solo vehículos cisterna en caminos privados"],"explanation":"La restricción X del Manual CDL de Alaska establece que un titular de permiso con un endoso N solo puede operar un vehículo cisterna vacío y tiene prohibido operar cualquier vehículo cisterna que previamente haya contenido materiales peligrosos y no haya sido purgado de residuos. Fuente: Alaska DMV CDL Manual, Restricción X."},"35":{"q":"A partir del 1 de enero de 2012, todos los conductores con CDL de Alaska deben autocertificarse en uno de cuántos tipos de operación de CMV?","options":["Dos","Tres","Cuatro","Cinco"],"explanation":"El Manual CDL de Alaska enumera cuatro categorías de autocertificación: interestatal no exceptuada, interestatal exceptuada, intraestatal no exceptuada e intraestatal exceptuada. Fuente: Alaska DMV CDL Manual, Requisitos de Certificado Médico y Autocertificación (49 CFR 383.71)."},"36":{"q":"Si el certificado del examinador médico que tiene en archivo un titular de CDL de Alaska vence, ¿de cuánto tiempo dispone el estado antes de que deba degradar la CDL?","options":["Dentro de los 15 days del vencimiento","Dentro de los 30 days del vencimiento","Dentro de los 60 days del vencimiento","Dentro de los 90 days del vencimiento"],"explanation":"El Manual CDL de Alaska establece que, a partir del 1 de enero de 2012, el estado debe degradar a cualquier titular de CDL con un certificado médico vencido en archivo dentro de los 60 days del vencimiento. Fuente: Alaska DMV CDL Manual, Requisitos de Certificado Médico y Autocertificación."},"37":{"q":"Según la regla federal ELDT aplicada en Alaska, un solicitante por primera vez debe completar el Entry-Level Driver Training de un proveedor inscrito en dónde antes de presentar el examen de destrezas?","options":["La base de datos interna de capacitación del Alaska DMV","El FMCSA Training Provider Registry","La lista del consejo estatal de aprendizaje","El registro nacional de conductores CDLIS"],"explanation":"Alaska exige el ELDT para los solicitantes por primera vez de Class A o B, ascensos y nuevos endosos H/P/S; la capacitación debe provenir de un proveedor inscrito en el FMCSA Training Provider Registry, que transmite la finalización al DMV antes del examen de destrezas. Fuente: Alaska DMV Entry-Level Driver Training (ELDT) page."},"38":{"q":"Según el estatuto/reglamento de Alaska (2 AAC 90.420), ¿qué documento se requiere específicamente para obtener una CDL, junto con los documentos de nacimiento e identidad, para cualquier persona que nunca antes haya tenido licencia en Alaska?","options":["Un número de Seguro Social","Una tarjeta de pasaporte","Una tarjeta de registro de votante","Un título de vehículo"],"explanation":"El Manual CDL de Alaska cita 2 AAC 90.420(a): se requiere un número de Seguro Social para obtener una CDL, junto con los documentos de nacimiento e identidad, para los solicitantes que nunca antes hayan tenido licencia en Alaska. También se requieren comprobante de domicilio en Alaska y de presencia legal. Fuente: Alaska DMV CDL Manual, Requisitos de Examen y Emisión; 2 AAC 90.420."},"39":{"q":"En Alaska, ¿con qué concentración de alcohol en sangre (BAC) es ilegal operar un vehículo motorizado comercial (CMV)?","options":["0.04% o más","0.08% o más","0.02% o más","0.10% o más"],"explanation":"La sección 1.3.2 del Manual CDL de Alaska establece que es ilegal operar un CMV si su BAC es de .04% o más, la mitad del límite de 0.08% para conductores no comerciales. Fuente: Alaska DMV Commercial Driver License Manual, sec. 1.3.2."},"40":{"q":"Según la ley de consentimiento implícito de Alaska, ¿a qué ha accedido simplemente por operar un CMV en el estado?","options":["A someterse a una prueba química de su aliento para detectar alcohol","A permitir una inspección de su carga en cualquier momento","A pagar todas las multas de la citación antes de retirarse del lugar","A llevar un dispositivo portátil de prueba de aliento en la cabina"],"explanation":"El Manual CDL de Alaska establece que cuando usted opera un CMV ya ha consentido a una prueba química de su aliento, y se 'considera que ha dado su consentimiento para la prueba de alcohol'. Fuente: Alaska DMV CDL Manual, Consentimiento Implícito / sec. 1.3.2."},"41":{"q":"Un titular de CDL de Alaska comete una primera infracción grave, como conducir un CMV con un BAC de 0.04% o más. ¿Cuál es la descalificación mínima?","options":["1 year","60 days","6 months","3 years"],"explanation":"Alaska descalifica a un conductor por al menos 1 year por una primera infracción grave (DUI, negativa, abandono del lugar, etc.). Fuente: Alaska DMV CDL Manual, secs. 1.3.2 y tabla de Infracciones Graves Descalificadoras (refleja 49 CFR 383.51)."},"42":{"q":"Si una primera infracción grave ocurre mientras el conductor opera un CMV con rótulos de materiales peligrosos, ¿cuánto dura la descalificación en Alaska?","options":["3 years","1 year","5 years","De por vida"],"explanation":"Alaska aumenta la descalificación por primera infracción grave a al menos 3 years cuando la infracción ocurre en un CMV con rótulos de materiales peligrosos. Fuente: Alaska DMV CDL Manual, sec. 1.3.2 / tabla de Infracciones Graves Descalificadoras."},"43":{"q":"¿Cuál es la descalificación en Alaska por una SEGUNDA infracción grave (por ejemplo, un segundo DUI en un CMV)?","options":["De por vida","10 years","3 years","5 years"],"explanation":"Alaska descalifica a un conductor de por vida por una segunda infracción grave. Fuente: Alaska DMV CDL Manual, sec. 1.3.2 y tabla de Infracciones Graves Descalificadoras (49 CFR 383.51)."},"44":{"q":"Usar un CMV para cometer un delito grave relacionado con la fabricación, distribución o dispensación de una sustancia controlada conlleva qué descalificación en Alaska, incluso en una primera infracción?","options":["De por vida, sin posibilidad de reinstalación","1 year","3 years","10 years"],"explanation":"El Manual CDL de Alaska establece que perderá su CDL de por vida si usa un CMV para cometer un delito grave relacionado con sustancias controladas. Fuente: Alaska DMV CDL Manual, sec. 1.3.2."},"45":{"q":"¿Cuál de las siguientes figura como una infracción GRAVE descalificadora en el Manual CDL de Alaska?","options":["Abandonar el lugar de un accidente que involucra un CMV","Seguir a otro vehículo demasiado de cerca","Exceso de velocidad de 15 mph o más sobre el límite","Un cambio de carril indebido o errático"],"explanation":"Abandonar el lugar de un accidente es una infracción grave (1 year / de por vida). Las otras tres son infracciones de tránsito serias, no infracciones graves. Fuente: Alaska DMV CDL Manual, secs. 1.3.2 y 1.3.3."},"46":{"q":"Si usted se niega a someterse a una prueba de alcohol en Alaska, ¿qué le ocurre a su CDL por una primera negativa?","options":["Descalificado por al menos 1 year (3 years si transporta hazmat)","Descalificado por 90 days","Solo una advertencia; sin descalificación","Descalificado de por vida"],"explanation":"La negativa se trata como una infracción grave: descalificación de al menos 1 year, o 3 years si transporta materiales peligrosos. Fuente: Alaska DMV CDL Manual, Consentimiento Implícito y sec. 1.3.2."},"47":{"q":"Según la disposición de consentimiento implícito del Manual CDL de Alaska, ¿cuál es la descalificación mínima por una segunda negativa o negativas subsecuentes a someterse a una prueba química?","options":["10 years","3 years","5 years","1 year"],"explanation":"El texto de consentimiento implícito del Manual CDL de Alaska establece que una segunda negativa y las subsecuentes conllevan una descalificación mínima de 10 years. Fuente: Alaska DMV CDL Manual, disposición de Consentimiento Implícito."},"48":{"q":"¿Qué le ocurre a un conductor de CMV de Alaska a quien se le detecta cualquier cantidad detectable de alcohol por debajo de 0.04%?","options":["Puesto fuera de servicio durante 24 hours","Descalificado por 60 days","Descalificado por 1 year","Multado con $500 sin período fuera de servicio"],"explanation":"El Manual CDL de Alaska establece que será puesto fuera de servicio durante 24 hours si tiene cualquier cantidad detectable de alcohol por debajo de .04%. Fuente: Alaska DMV CDL Manual, sec. 1.3.2."},"49":{"q":"¿Cuál es la velocidad mínima por encima del límite establecido que cuenta como una infracción de tránsito SERIA para un titular de CDL de Alaska?","options":["15 mph o más sobre el límite","10 mph o más sobre el límite","20 mph o más sobre el límite","5 mph o más sobre el límite"],"explanation":"El exceso de velocidad significa 15 mph o más por encima del límite establecido, una infracción de tránsito seria. Fuente: Alaska DMV CDL Manual, sec. 1.3.3."},"50":{"q":"¿Cuánto dura la descalificación en Alaska por cometer DOS infracciones de tránsito serias en un CMV dentro de un período de tres años?","options":["Al menos 60 days","Al menos 30 days","Al menos 120 days","Al menos 1 year"],"explanation":"Dos infracciones de tránsito serias dentro de 3 años resultan en una descalificación de al menos 60 days. Fuente: Alaska DMV CDL Manual, sec. 1.3.3 y tabla de Infracciones Serias Descalificadoras."},"51":{"q":"¿Cuánto dura la descalificación en Alaska por TRES o más infracciones de tránsito serias en un CMV dentro de un período de tres años?","options":["Al menos 120 days","Al menos 60 days","Al menos 90 days","Al menos 1 year"],"explanation":"Tres o más infracciones de tránsito serias dentro de 3 años resultan en una descalificación de al menos 120 days. Fuente: Alaska DMV CDL Manual, sec. 1.3.3 y tabla de Infracciones Serias Descalificadoras."},"52":{"q":"¿Cuál de estas NO figura como una infracción de tránsito seria en el Manual CDL de Alaska?","options":["Conducir un CMV con un BAC de 0.04% o más","Seguir a un vehículo demasiado de cerca","Cambios de carril indebidos o erráticos","Conducir un CMV sin la clase de CDL adecuada"],"explanation":"Conducir con un BAC de 0.04% o más es una infracción GRAVE, no una infracción de tránsito seria. Las otras tres son infracciones de tránsito serias. Fuente: Alaska DMV CDL Manual, secs. 1.3.2 y 1.3.3."},"53":{"q":"Según la ley de Alaska (AS 28.33.190), enviar mensajes de texto o usar un teléfono móvil de mano mientras se conduce un CMV se clasifica como qué?","options":["Una infracción de tránsito seria (uso de un dispositivo electrónico)","Una infracción grave descalificadora","Una violación de una orden de fuera de servicio","Una infracción no reportable"],"explanation":"Alaska incluye el 'uso de un dispositivo electrónico mientras se conduce' (AS 28.33.190(16)(H)) entre las infracciones serias descalificadoras, contando para los umbrales de 60 days/120 days. Fuente: Alaska DMV CDL Manual, Infracciones Serias Descalificadoras; AS 28.33.190."},"54":{"q":"¿Cuál es la sanción civil máxima que puede enfrentar un conductor de CMV por violar la prohibición de teléfonos móviles de mano descrita en el Manual CDL de Alaska?","options":["Hasta $2,750","Hasta $11,000","Hasta $500","Hasta $1,000"],"explanation":"Cada violación de teléfono de mano está sujeta a una sanción civil de hasta $2,750 para el conductor; los empleadores enfrentan hasta $11,000. Fuente: Alaska DMV CDL Manual, sec. 2.9.4 (teléfonos móviles de mano)."},"55":{"q":"¿Cuál es la descalificación en Alaska por una PRIMERA violación de una orden de fuera de servicio (OOS) mientras se opera un CMV (sin hazmat ni pasajeros)?","options":["No menos de 180 days y no más de 1 year","No menos de 90 days y no más de 1 year","Exactamente 60 days","No menos de 2 years y no más de 5 years"],"explanation":"Alaska descalifica una primera violación de orden OOS por no menos de 180 days y no más de 1 year. Fuente: Alaska DMV CDL Manual, tabla de Violación de Órdenes de Fuera de Servicio (AS 28.33.140(j))."},"56":{"q":"¿Cuánto dura la descalificación en Alaska por una PRIMERA violación de una orden de fuera de servicio cometida mientras se transportan materiales peligrosos o pasajeros?","options":["No menos de 180 days y no más de 2 years","No menos de 180 days y no más de 1 year","No menos de 1 year y no más de 5 years","Exactamente 120 days"],"explanation":"Una primera violación de orden OOS mientras se transporta hazmat o pasajeros se descalifica por no menos de 180 days y no más de 2 years. Fuente: Alaska DMV CDL Manual, tabla de Violación de Órdenes de Fuera de Servicio (AS 28.33.140(j))."},"57":{"q":"¿Cuál es la descalificación en Alaska por una SEGUNDA violación de una orden de fuera de servicio (sin hazmat) dentro de un período de 10 años?","options":["No menos de 1 year y no más de 5 years","No menos de 180 days y no más de 1 year","No menos de 3 years y no más de 5 years","De por vida"],"explanation":"Una segunda violación de orden OOS dentro de 10 años conlleva no menos de 1 year y no más de 5 years; con hazmat o pasajeros es de 3 a 5 years. Fuente: Alaska DMV CDL Manual, tabla de Violación de Órdenes de Fuera de Servicio."},"58":{"q":"Por una PRIMERA violación de un cruce a nivel de ferrocarril y carretera mientras se opera un CMV, ¿cuál es la descalificación en Alaska?","options":["Al menos 60 days","Al menos 15 days","Al menos 120 days","Al menos 1 year"],"explanation":"Alaska descalifica una primera violación de cruce a nivel de ferrocarril y carretera por al menos 60 days; una segunda dentro de 3 años es de 120 days, y una tercera dentro de 3 años es de 1 year. Fuente: Alaska DMV CDL Manual, sec. 1.3.5 / tabla de Violaciones de Cruce a Nivel de Ferrocarril y Carretera."},"59":{"q":"En Alaska, un autobús o un vehículo que transporta materiales peligrosos con carteles (placards) debe detenerse en un cruce de ferrocarril con la carretera dentro de qué distancia del riel más cercano?","options":["Entre 15 y 50 pies","Entre 5 y 15 pies","Entre 50 y 100 pies","Entre 10 y 25 pies"],"explanation":"El Manual de CDL de Alaska (Secciones 4.3.5 y 9.6.12) exige que los autobuses y los vehículos de HazMat con carteles se detengan no más cerca de 15 pies y no más lejos de 50 pies del riel más cercano, y luego miren y escuchen antes de cruzar."},"60":{"q":"Según la ley de \"Move Over\" (cambio de carril) de Alaska, cuando un conductor se aproxima a un vehículo de emergencia detenido que muestra luces intermitentes en una vía con dos o más carriles en la misma dirección, el conductor debe:","options":["Desocupar el carril más cercano al vehículo de emergencia cuando sea seguro hacerlo","Detenerse por completo hasta que el vehículo de emergencia se retire","Tocar la bocina y continuar a la velocidad señalizada","Orillarse al acotamiento y esperar tres minutos"],"explanation":"El Estatuto de Alaska AS 28.35.185 exige que los conductores en una vía con dos o más carriles en la misma dirección desocupen el carril más cercano a un vehículo de emergencia, de bomberos, policial, de remolque, de mantenimiento o de control de animales que esté detenido con luces intermitentes, si es seguro hacerlo."},"61":{"q":"Al detenerse por un autobús escolar que tiene sus luces rojas intermitentes encendidas, la ley de Alaska exige que un conductor que se aproxima se detenga al menos a qué distancia del autobús?","options":["30 pies","15 pies","20 pies","50 pies"],"explanation":"El Estatuto de Alaska AS 28.35.145 exige que un conductor que se aproxima a un autobús escolar con luces rojas intermitentes se detenga a no menos de 30 pies del autobús y no avance hasta que las luces dejen de destellar."},"62":{"q":"En cualquier vía que no sea un callejón, un distrito comercial o un distrito residencial, ¿cuál es la velocidad máxima legal para un vehículo comercial motorizado en Alaska a menos que se señalice de otra manera?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"El Código Administrativo de Alaska 13 AAC 03.275 establece la velocidad máxima legal para los vehículos comerciales motorizados en 55 mph en cualquier otra vía (15 mph en un callejón, 20 mph en un distrito comercial, 25 mph en un distrito residencial)."},"63":{"q":"La ley de Alaska sobre detenerse ante autobuses escolares contiene una excepción para las carreteras divididas. ¿Cuándo NO está obligado a detenerse un conductor que se aproxima a un autobús escolar?","options":["Cuando el autobús está en una calzada distinta de una carretera con calzadas separadas","Cuando el conductor circula al menos 10 mph por debajo del límite","Cuando el autobús está a más de 100 pies de distancia","Cuando no hay niños visibles cerca del autobús"],"explanation":"Según el AS 28.35.145, un conductor en una carretera con calzadas separadas no está obligado a detenerse cuando se cruza o adelanta a un autobús escolar que está en una calzada distinta (la excepción de la carretera dividida)."},"64":{"q":"Después de detener un vehículo comercial en una carretera de un solo sentido o dividida en Alaska, ¿en qué ubicaciones debe colocar el conductor los tres triángulos de advertencia?","options":["Aproximadamente a 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima","Aproximadamente a 10 pies, 50 pies y 150 pies hacia el tráfico que se aproxima","Aproximadamente a 25 pies, 100 pies y 250 pies hacia el tráfico que se aproxima","Aproximadamente a 50 pies, 100 pies y 500 pies hacia el tráfico que se aproxima"],"explanation":"Según el Manual de CDL de Alaska (Sección 2.5), en una carretera de un solo sentido o dividida los dispositivos de advertencia se colocan a 10 pies, 100 pies y 200 pies del vehículo hacia el tráfico que se aproxima."},"65":{"q":"Un conductor que infringe la ley de \"Move Over\" de Alaska (AS 28.35.185) y causa lesiones personales es culpable de qué delito?","options":["Un delito menor de clase A","Únicamente una infracción","Un delito grave de clase B","Una violación que no acumula puntos"],"explanation":"El AS 28.35.185(b) convierte una infracción de \"Move Over\" en un delito menor de clase A cuando resultan lesiones personales por no desocupar el carril o no reducir la velocidad; de lo contrario, es una infracción."},"66":{"q":"En una vía de dos carriles que lleva tráfico en ambas direcciones, ¿dónde indica el Manual de CDL de Alaska que un conductor debe colocar los triángulos de advertencia después de detenerse?","options":["A no más de 10 pies del vehículo, y a 100 pies detrás y delante de él","A no más de 25 pies del vehículo, y a 200 pies detrás y delante de él","Solo a 100 pies detrás del vehículo","A 10, 100 y 200 pies únicamente detrás del vehículo"],"explanation":"El Manual de CDL de Alaska (Sección 2.5) indica que en una vía de doble sentido sin dividir, se debe colocar un triángulo a no más de 10 pies del vehículo y uno cada 100 pies detrás y delante de él, en el acotamiento o en el carril."},"67":{"q":"¿Cuál lista de vehículos está obligada a hacer una parada obligatoria antes de cruzar las vías del ferrocarril según las reglas del CDL de Alaska?","options":["Vehículos con carteles, cualquier vehículo que transporte cloro y vehículos cisterna de carga utilizados para materiales peligrosos","Solo las combinaciones de triple remolque","Solo los autobuses que transportan más de 30 pasajeros","Todos los vehículos de más de 26,000 libras de peso bruto"],"explanation":"La Sección 9.6.12 del Manual de CDL de Alaska enumera los vehículos que deben detenerse en los cruces de ferrocarril: vehículos con carteles, cualquier vehículo que transporte cualquier cantidad de cloro y los vehículos cisterna de carga (cargados o vacíos) utilizados para materiales peligrosos."},"68":{"q":"¿Cuánto tiempo después de detenerse en la carretera tiene un conductor con CDL de Alaska para colocar los dispositivos de advertencia de emergencia?","options":["Dentro de 10 minutos","Dentro de 5 minutos","Dentro de 15 minutos","De inmediato, dentro de 1 minuto"],"explanation":"El Manual de CDL de Alaska (Sección 2.5) establece que si debe detenerse en la carretera o junto a ella, debe colocar sus dispositivos de advertencia de emergencia dentro de 10 minutos."},"69":{"q":"Cuando un conductor con CDL de Alaska debe detener un vehículo comercial al costado de la carretera, ¿cuáles son los tres dispositivos de advertencia requeridos?","options":["Tres triángulos reflectantes rojos, o 6 bengalas (fusees), o 3 bengalas de combustible líquido","Dos linternas rojas y una bandera roja","Cuatro reflectores ámbar","Un triángulo reflectante y dos bengalas de carretera"],"explanation":"El Manual de CDL de Alaska enumera como dispositivos de advertencia aceptables para vehículos estacionados tres triángulos reflectantes rojos, al menos 6 bengalas (fusees) o 3 bengalas de combustible líquido."},"70":{"q":"Un conductor de autobús escolar en Alaska que debe detenerse en un cruce de ferrocarril también debe hacer cuál de las siguientes acciones antes de cruzar?","options":["Abrir la puerta delantera si eso mejora la capacidad de ver o escuchar un tren que se aproxima","Tocar la bocina tres veces","Hacer que todos los pasajeros bajen del autobús primero","Cambiar a una marcha más baja mientras está sobre las vías"],"explanation":"El Manual de CDL de Alaska (Sección 4.3.5) instruye a los conductores de autobús a detenerse entre 15 y 50 pies antes del cruce, mirar y escuchar en ambas direcciones, y abrir la puerta delantera si eso mejora la capacidad de ver o escuchar un tren."},"71":{"q":"Si un vehículo comercial está detenido al costado de la carretera más allá de una colina o una curva que bloquea la visión de otros conductores dentro de 500 pies, ¿qué debe hacer el conductor con CDL de Alaska con los triángulos de advertencia?","options":["Mover el triángulo trasero más atrás por la carretera para que se proporcione advertencia más allá de la obstrucción","Colocar los tres triángulos directamente detrás del vehículo","Retirar los triángulos y depender únicamente de las luces intermitentes de cuatro vías","Colocar un triángulo encima de la cabina"],"explanation":"El Manual de CDL de Alaska (Sección 2.5) indica que si una colina, una curva u otra obstrucción bloquea la línea de visión dentro de 500 pies, el conductor debe mover el triángulo trasero más atrás por la carretera para que se proporcione advertencia."},"72":{"q":"En una carretera dividida en Alaska, ¿cuál conductor que se aproxima está exento de detenerse por un autobús escolar que está recogiendo niños?","options":["Un conductor en la calzada opuesta separada del autobús por un camellón o barrera","Un conductor directamente detrás del autobús en el mismo carril","Un conductor que adelanta al autobús por el acotamiento derecho","Cualquier conductor que circule a menos de 20 mph"],"explanation":"La excepción de calzadas separadas del AS 28.35.145 aplica a los conductores en la calzada opuesta de una carretera dividida; los conductores en la misma calzada que el autobús, incluidos los que están detrás de él, igualmente deben detenerse."},"73":{"q":"En una vía con menos de dos carriles que circulan en la misma dirección, ¿qué exige la ley de \"Move Over\" de Alaska cuando un conductor pasa junto a un vehículo de emergencia detenido con luces intermitentes?","options":["Reducir a una velocidad razonable y prudente según el tráfico, la vía y el clima","Mantener exactamente el límite de velocidad señalizado","Detenerse por completo hasta que se le indique avanzar","Desplazarse totalmente al acotamiento opuesto"],"explanation":"El AS 28.35.185 exige que, donde hay menos de dos carriles en la misma dirección, el conductor debe reducir a una velocidad razonable y prudente considerando las condiciones del tráfico, la vía y el clima."},"74":{"q":"Al cruzar las vías del ferrocarril en Alaska, un conductor con CDL debe:","options":["No cambiar de marcha mientras cruza las vías","Reducir a primera marcha sobre las vías para tener el máximo control","Detenerse sobre las vías si no hay un tren a la vista","Acelerar con fuerza y subir de marcha a la mitad del cruce"],"explanation":"El Manual de CDL de Alaska (Secciones 2.15 y 9.6.12) advierte a los conductores que nunca cambien de marcha mientras cruzan las vías, porque un cambio fallido podría dejar el vehículo detenido sobre el cruce."},"75":{"q":"¿Cuál es el ancho máximo legal del vehículo/carga en Alaska que puede circular por una carretera pública sin un permiso de sobredimensión?","options":["102 pulgadas (8 pies 6 pulgadas)","96 pulgadas (8 pies)","120 pulgadas (10 pies)","108 pulgadas (9 pies)"],"explanation":"El Manual de Permisos de Sobredimensión/Sobrepeso de Alaska hace referencia a la limitación de ancho legal de 102 pulgadas (8 pies 6 pulgadas) del 17 AAC 25; cualquier cosa más ancha requiere un permiso y letreros de OVERSIZE/WIDE LOAD."},"76":{"q":"Según las reglas de permisos de sobredimensión de Alaska, una carga ancha requiere al menos un vehículo piloto/escolta en todas las rutas una vez que su ancho supera:","options":["10 pies 6 pulgadas","8 pies 6 pulgadas","12 pies","9 pies"],"explanation":"El Manual de Permisos de Sobredimensión/Sobrepeso de Alaska (Sección 6.2.1) requiere al menos un vehículo piloto/escolta en todas las rutas cuando un vehículo o carga supera los 10 pies 6 pulgadas de ancho."},"77":{"q":"Según las reglas de permisos de Alaska, una carga que supera los 17 pies de altura está restringida a qué velocidad máxima en carretera (sin un factor más restrictivo)?","options":["45 mph","55 mph","35 mph","25 mph"],"explanation":"El Manual de Permisos de Sobredimensión/Sobrepeso de Alaska (Sección 9.3.1) limita las cargas de más de 17 pies de altura a una velocidad máxima en carretera de 45 mph a menos que otros factores sean más restrictivos."},"78":{"q":"En un puente levadizo de Alaska sin semáforo ni encargado que controle el tráfico, ¿dónde debe detenerse un conductor con CDL?","options":["Al menos a 50 pies antes del vano levadizo del puente","Al menos a 15 pies antes del vano levadizo del puente","Al menos a 100 pies antes del vano levadizo del puente","Justo en el borde del vano levadizo"],"explanation":"El Manual de CDL de Alaska (Sección 4.3.6) exige detenerse al menos a 50 pies antes del vano levadizo de un puente que no tiene semáforo ni encargado de control de tráfico, y verificar que el vano esté completamente cerrado antes de cruzar."},"79":{"q":"¿Qué agencia estatal de Alaska emite las Licencias de Conducir Comerciales (CDL)?","options":["La División de Vehículos Motorizados de Alaska (DMV)","El Departamento de Seguridad Pública de Alaska","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Transporte e Instalaciones Públicas de Alaska (DOT&PF)"],"explanation":"En Alaska, la División de Vehículos Motorizados (DMV) es la Agencia Estatal de Licencias de Conducir que emite las CDL y administra los exámenes de conocimientos y habilidades. La FMCSA establece los estándares federales del CDL, pero no emite la licencia. Fuente: Alaska DMV, página de Commercial Driver's License (CDL)."},"80":{"q":"¿Qué puntaje mínimo debe obtener un solicitante para aprobar cada examen de conocimientos del CDL de Alaska?","options":["70%","75%","80%","90%"],"explanation":"Alaska exige un puntaje de al menos 80% para aprobar cada examen de conocimientos del CDL (el de conocimientos generales y cualquier examen de endoso). Fuente: Manual de CDL de Alaska DMV / requisitos del CDL de Alaska DMV."},"81":{"q":"El examen de habilidades del CDL de Alaska se divide en tres partes. ¿Cuál conjunto enumera correctamente las tres?","options":["Inspección previaje, control básico del vehículo y manejo en carretera","Examen de la vista, conocimientos por escrito y manejo en carretera","Inspección previaje, verificación de frenos de aire y estacionamiento en paralelo","Retroceso, acoplamiento/desacoplamiento y un circuito de maniobrabilidad cronometrado"],"explanation":"El examen de habilidades del CDL de Alaska tiene tres partes: el examen de inspección previaje (del vehículo), el examen de habilidades de control básico del vehículo y el examen de manejo en carretera. Fuente: Manual de CDL de Alaska DMV."},"82":{"q":"¿Quién es responsable de proporcionar el vehículo utilizado para el examen de habilidades de manejo en carretera del CDL de Alaska?","options":["El solicitante debe proporcionar un vehículo representativo de la clase y el tipo que pretende conducir","El DMV proporciona un vehículo de prueba estándar para todos los solicitantes","El Registro de Proveedores de Capacitación de la FMCSA asigna un vehículo","El DOT&PF de Alaska presta un vehículo de su flota"],"explanation":"El solicitante debe traer su propio vehículo representativo de la misma clase y tipo que planea conducir; la oficina del DMV no proporciona un vehículo de prueba. Fuente: Manual de CDL de Alaska DMV / requisitos del CDL de Alaska DMV."},"83":{"q":"Después de que se le emite un Permiso de Aprendiz Comercial (CLP), ¿cuánto tiempo debe esperar un solicitante de Alaska antes de tomar el examen de habilidades (de manejo) del CDL?","options":["Al menos 14 días","Al menos 7 días","Al menos 30 días","No hay período de espera"],"explanation":"Alaska sigue la regla federal que exige que el titular de un CLP espere al menos 14 días después de que se emite el CLP antes de tomar cualquier examen de manejo para el CDL. Fuente: página del CLP de Alaska DMV (49 CFR 383.25)."},"84":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Alaska antes de que deba renovarse?","options":["180 días","30 días","1 año","5 años"],"explanation":"Un CLP de Alaska es válido por 180 días y puede renovarse (reemitirse) una vez por 180 días adicionales sin volver a tomar el examen de conocimientos generales. Fuente: información del CLP de Alaska DMV (49 CFR 383.25)."},"85":{"q":"¿Cuántas veces puede renovarse/reemitirse un CLP de Alaska por un período adicional de 180 días bajo el estándar federal que sigue Alaska?","options":["Una vez","No puede renovarse en absoluto","Dos veces","Un número ilimitado de veces"],"explanation":"Un CLP es válido por 180 días y puede renovarse una vez por 180 días adicionales (un máximo de 360 días en total). Fuente: información del CLP de Alaska DMV (49 CFR 383.25)."},"86":{"q":"Antes de que un solicitante por primera vez pueda tomar el examen de habilidades del CDL de Alaska para una licencia de Clase A o Clase B, ¿qué capacitación debe completar?","options":["Capacitación para Conductores Principiantes (ELDT) de un proveedor que figure en el Registro de Proveedores de Capacitación de la FMCSA","Un curso de manejo defensivo aprobado por el Sistema Judicial de Alaska","Una certificación de manejo invernal de Alaska de 40 horas","Un aprendizaje registrado ante el Departamento de Trabajo de Alaska"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes de CDL por primera vez deben completar la Capacitación para Conductores Principiantes (ELDT) de un proveedor del Registro de Proveedores de Capacitación de la FMCSA antes de tomar el examen de habilidades; el estado debe verificar que el registro fue presentado. Fuente: regla ELDT de la FMCSA (49 CFR Part 380), aplicada por Alaska DMV."},"87":{"q":"La autocertificación del CDL en Alaska exige que un conductor declare qué tipo de operación espera realizar. ¿Cuántas categorías de autocertificación hay?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Los conductores deben autocertificarse en una de cuatro categorías formadas al combinar interestatal/intraestatal con operación exceptuada/no exceptuada. Fuente: página de Requisito de Autocertificación del CDL de Alaska DMV."},"88":{"q":"¿Cuál de las siguientes es una de las cuatro categorías de autocertificación del CDL de Alaska?","options":["Interestatal no exceptuada","Interestatal de temporada","Intraestatal solo de materiales peligrosos","Transportista exento federal"],"explanation":"Las cuatro categorías son interestatal no exceptuada, interestatal exceptuada, intraestatal no exceptuada e intraestatal exceptuada. \"Interestatal no exceptuada\" es la categoría para los conductores que deben cumplir con los requisitos federales de la tarjeta médica del DOT. Fuente: página de Requisito de Autocertificación del CDL de Alaska DMV."},"89":{"q":"Un conductor de Alaska que se autocertifica como \"no exceptuado\" (interestatal o intraestatal) debe proporcionar cuál documento al DMV?","options":["Un certificado válido del examinador médico del DOT (tarjeta médica)","Una carta de patrocinio del empleador notariada","Una renuncia firmada a los estándares médicos federales","Una calcomanía de inspección de vehículos comerciales de Alaska"],"explanation":"Los conductores no exceptuados deben tener y presentar un certificado válido del examinador médico del DOT (tarjeta médica) para conservar los privilegios del CDL; los conductores exceptuados no están obligados a presentar uno. Fuente: página de Requisito de Autocertificación del CDL de Alaska DMV."},"90":{"q":"¿Cómo puede un titular de CDL de Alaska presentar su autocertificación y el certificado del examinador médico del DOT al DMV?","options":["Completar el Formulario 413 y presentar o enviar por correo electrónico una copia legible de la tarjeta médica a la dirección de correo electrónico de CDL del DMV","Subir la tarjeta únicamente al Registro de Proveedores de Capacitación de la FMCSA","Enviar la tarjeta original directamente por correo a la FMCSA en Washington, D.C.","Presentarla ante el Departamento de Trabajo y Desarrollo Laboral de Alaska"],"explanation":"Los conductores completan la autocertificación (Formulario 413) con cada solicitud y presentan la tarjeta médica en una oficina del DMV o envían por correo electrónico una copia legible a la dirección de CDL del DMV (doa.dmv.cdl@alaska.gov). Fuente: página de Requisito de Autocertificación del CDL de Alaska DMV."},"91":{"q":"¿Cuál es la consecuencia en Alaska si un titular de CDL no exceptuado no mantiene un certificado vigente del examinador médico del DOT en archivo con el DMV?","options":["Los privilegios del CDL se degradan o se cancelan","Se impone una multa federal única de $500, pero el CDL sigue siendo válido","Nada, porque la tarjeta médica se archiva únicamente con el empleador","El conductor se reclasifica automáticamente como conductor intraestatal exceptuado"],"explanation":"Si la certificación médica de un conductor no exceptuado vence, el DMV de Alaska cancela o degrada los privilegios del CDL; operar un CMV después de eso es conducir sin los privilegios adecuados. Fuente: página de Requisito de Autocertificación del CDL de Alaska DMV."},"92":{"q":"¿Por cuánto tiempo es válido un CDL de Alaska antes de que deba renovarse?","options":["5 años","4 años","8 años","2 años"],"explanation":"Un CDL de Alaska es válido por 5 años y vence en el cumpleaños del titular. Fuente: información de renovación de Alaska DMV."},"93":{"q":"¿En qué fecha vence típicamente un CDL de Alaska dentro de su año de renovación?","options":["En el cumpleaños del titular","El 31 de diciembre","Exactamente cinco años desde la fecha de emisión sin importar el cumpleaños","El último día del mes de emisión"],"explanation":"Las licencias de conducir de Alaska, incluidos los CDL, se emiten por 5 años y vencen en el cumpleaños del titular. Fuente: información de renovación de Alaska DMV."},"94":{"q":"¿Con cuánta anticipación antes del vencimiento puede un titular de CDL de Alaska comenzar el proceso de renovación?","options":["Hasta 1 año antes del vencimiento","Hasta 30 días antes del vencimiento","Solo en la fecha de vencimiento","Hasta 6 meses después del vencimiento"],"explanation":"Alaska permite comenzar la renovación del CDL hasta un año antes de que la licencia venza; el estado no ofrece período de gracia para una licencia ya vencida. Fuente: información de renovación de Alaska DMV."},"95":{"q":"¿Qué conjunto de documentos se requiere al solicitar un CDL original de Alaska?","options":["Prueba de ciudadanía estadounidense/presencia legal, una dirección de residencia/domicilio en Alaska, un Número de Seguro Social y una tarjeta médica del DOT cuando corresponda","Solo un CDL vigente de otro estado y una foto tipo pasaporte","Un título de vehículo, comprobante de seguro y una licencia de pesca de Alaska","Únicamente un número de transportista de la FMCSA y una declaración jurada notariada"],"explanation":"Alaska requiere prueba de ciudadanía/presencia legal, prueba de una dirección de residencia en Alaska (domicilio), un Número de Seguro Social, una licencia de conducir vigente y una tarjeta médica del DOT cuando corresponda. Fuente: página de Commercial Driver's License (CDL) de Alaska DMV."},"96":{"q":"¿Cuál es la edad mínima para obtener un CDL de Alaska restringido a operación intraestatal (dentro de Alaska)?","options":["18 años","16 años","21 años","25 años"],"explanation":"La edad mínima para un CDL de Alaska es 18 para operación intraestatal; la operación interestatal, los materiales peligrosos y los endosos de autobús escolar requieren tener 21 años. Fuente: páginas de CDL / CLP de Alaska DMV."},"97":{"q":"Un conductor que desea operar en el comercio interestatal o transportar materiales peligrosos debe tener al menos qué edad para poseer un CDL de Alaska para esa operación?","options":["21 años","18 años","19 años","25 años"],"explanation":"Alaska exige que un conductor tenga al menos 21 años para operar de manera interestatal o para poseer un endoso de materiales peligrosos o de autobús escolar, mientras que los CDL solo intraestatales están disponibles a los 18 años. Fuente: páginas de CDL / CLP de Alaska DMV."},"98":{"q":"Con respecto a las tarifas de solicitud del CDL de Alaska, ¿cuál afirmación es precisa sobre cómo funciona el proceso?","options":["Las tarifas aplicables del CDL y del examen de manejo se pagan al DMV al momento de la solicitud, y los montos exactos los establece el estado y pueden cambiar con el tiempo","Alaska no cobra ninguna tarifa por un CDL original","Todas las tarifas del CDL se pagan directamente a la FMCSA, no al DMV","La tarifa del examen de manejo es totalmente reembolsable si el solicitante no aprueba"],"explanation":"Los solicitantes del CDL de Alaska pagan las tarifas aplicables de la licencia y del examen de manejo al DMV al momento de la solicitud; los montos específicos en dólares los establece el estado y están sujetos a cambios, por lo que el proceso (y no un monto fijo) es el punto confiable. Fuente: página del CDL de Alaska DMV / lista de tarifas."}},"hi":{"0":{"q":"अलास्का में, राज्य राजमार्ग प्रणाली पर किसी वाहन की, उसके भार सहित, अधिकतम कानूनी चौड़ाई कितनी है?","options":["102 inches","96 inches","108 inches","114 inches"],"explanation":"अलास्का वाहन की अधिकतम चौड़ाई, भार सहित, 102 inches निर्धारित करता है; उससे जुड़े उपकरण प्रत्येक तरफ उससे 3 inches से अधिक आगे नहीं बढ़ सकते। स्रोत: 17 AAC 25.012(a) (Alaska DOT&PF, Chapter 25 Operations, Wheeled Vehicles), जो Alaska CDL Manual के अनुरूप है।"},"1":{"q":"अधिकांश अलास्का राजमार्गों पर किसी वाहन और भार की सामान्य अधिकतम कानूनी ऊंचाई कितनी है?","options":["15 feet","13 feet 6 inches","14 feet","16 feet"],"explanation":"17 AAC 25.012(b) के तहत, अलास्का में कोई वाहन, भार सहित, ऊंचाई में 15 feet से अधिक नहीं हो सकता, सिवाय Fox Weigh Station और Prudhoe Bay के बीच के Dalton/Elliott Highway गलियारे के, जहां 17 feet की अनुमति है। स्रोत: 17 AAC 25.012(b), Alaska DOT&PF।"},"2":{"q":"Fox Weigh Station और Prudhoe Bay के बीच Dalton और Elliott Highways पर, किसी वाहन और भार के लिए कितनी बढ़ी हुई ऊंचाई की अनुमति है?","options":["15 feet 6 inches","16 feet","17 feet","18 feet"],"explanation":"17 AAC 25.012(b) Dalton और Elliott Highways पर Fox Weigh Station और Prudhoe Bay के बीच संचालित होने वाले वाहन के लिए, भार सहित, 17 feet की ऊंचाई की अनुमति देता है, जबकि सामान्य सीमा 15 feet है। स्रोत: 17 AAC 25.012(b), Alaska DOT&PF।"},"3":{"q":"अलास्का के National Highway System मार्गों पर, एक एकल पावर वाहन (ट्रक या ट्रक ट्रैक्टर स्वयं) की अधिकतम लंबाई कितनी है?","options":["40 feet","48 feet","53 feet","45 feet"],"explanation":"17 AAC 25.012(c)(1) NHS मार्गों पर पावर वाहन की लंबाई 45 feet तक सीमित करता है (और 17 AAC 25.012(d)(1) शेष राज्य राजमार्ग प्रणाली पर वही 45-foot सीमा निर्धारित करता है)। स्रोत: 17 AAC 25.012, Alaska DOT&PF।"},"4":{"q":"अलास्का में, किसी संयोजन में उपयोग किए जाने वाले अर्ध-ट्रेलर या ट्रेलर की अधिकतम कार्गो-वहन लंबाई कितनी है?","options":["48 feet","57 feet","60 feet","53 feet"],"explanation":"17 AAC 25.012(c)(3) और (e)(1) सभी मार्गों पर अर्ध-ट्रेलर या ट्रेलर की कार्गो-वहन लंबाई 53 feet तक सीमित करते हैं। स्रोत: 17 AAC 25.012, Alaska DOT&PF।"},"5":{"q":"अलास्का राजमार्गों पर एक ट्रक और एक कार्गो-वहन वाहन, या एक ट्रक ट्रैक्टर और दो कार्गो-वहन वाहनों से बने एक मानक संयोजन की अधिकतम कुल लंबाई कितनी है?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"17 AAC 25.012(c)(4) और (d)(3) ऐसे संयोजनों को 75 feet की कुल लंबाई तक सीमित करते हैं; एकल कार्गो-वहन वाहन वाला ट्रक ट्रैक्टर कुल लंबाई सीमा के अधीन नहीं है। स्रोत: 17 AAC 25.012, Alaska DOT&PF।"},"6":{"q":"अलास्का में, कानूनी सीमा को पार करने से पहले कोई भार या उपकरण वाहन के सामने वाले बम्पर से कितना आगे बढ़ सकता है?","options":["3 feet","4 feet","5 feet","6 feet"],"explanation":"17 AAC 25.012(c)(6) और (d)(4) किसी भार या उपकरण को सामने वाले बम्पर से 3 feet से अधिक आगे नहीं निकलने (और पीछे से 4 feet से अधिक नहीं) की अनुमति देते हैं। स्रोत: 17 AAC 25.012, Alaska DOT&PF।"},"7":{"q":"अलास्का में, कानूनी सीमा को पार करने से पहले कोई भार वाहन के पीछे से कितना आगे बढ़ सकता है?","options":["3 feet","5 feet","6 feet","4 feet"],"explanation":"17 AAC 25.012(c)(6)(B) और (d)(4)(B) पीछे की ओर 4 feet से अधिक नहीं निकलने की अनुमति देते हैं (सामने की ओर निकलना 3 feet तक सीमित है)। स्रोत: 17 AAC 25.012, Alaska DOT&PF।"},"8":{"q":"अलास्का में एक एकल एक्सल पर अनुमत अधिकतम कानूनी भार कितना है?","options":["18,000 pounds","22,400 pounds","34,000 pounds","20,000 pounds"],"explanation":"17 AAC 25.013(a)(4) एकल-एक्सल भार सीमा 20,000 pounds निर्धारित करता है, जिसमें किसी एक्सल को एकल एक्सल के रूप में गिने जाने के लिए न्यूनतम 8'1\" की दूरी होनी चाहिए। स्रोत: 17 AAC 25.013, Alaska DOT&PF।"},"9":{"q":"अलास्का की एक्सल-समूह तालिका के तहत, एक 2-एक्सल समूह (टैंडम एक्सल) पर अनुमत अधिकतम भार कितना है?","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"explanation":"17 AAC 25.013(a)(4) में अलास्का की एक्सल-समूह भार तालिका एक 2-एक्सल समूह (टैंडम) पर 38,000 pounds की अनुमति देती है, जो कई राज्यों में उपयोग किए जाने वाले 34,000-pound संघीय टैंडम मानक से अधिक है। स्रोत: 17 AAC 25.013, Alaska DOT&PF।"},"10":{"q":"अलास्का की एक्सल-समूह भार तालिका के तहत, एक 3-एक्सल समूह पर अनुमत अधिकतम भार कितना है?","options":["38,000 pounds","46,000 pounds","50,000 pounds","42,000 pounds"],"explanation":"17 AAC 25.013(a)(4) एक 3-एक्सल समूह पर 42,000 pounds की अनुमति देता है (न्यूनतम 3'6\" एक्सल दूरी के साथ)। स्रोत: 17 AAC 25.013, Alaska DOT&PF।"},"11":{"q":"अलास्का में किसी एक्सल को एक्सल समूह के हिस्से के बजाय 'एकल एक्सल' माने जाने के लिए न्यूनतम कितनी एक्सल दूरी बनाए रखी जानी चाहिए?","options":["8 feet 1 inch","3 feet 6 inches","6 feet","10 feet"],"explanation":"17 AAC 25.013(a)(4) की टिप्पणी के अनुसार, किसी अन्य एक्सल से (केंद्र से केंद्र तक) 8 feet 1 inch से कम दूरी पर रखे गए किसी भी एक्सल को एक्सल समूह का हिस्सा माना जाता है; एकल-एक्सल सीमा न्यूनतम 8'1\" दूरी पर लागू होती है। स्रोत: 17 AAC 25.013, Alaska DOT&PF।"},"12":{"q":"अलास्का एक लंबे संयोजन के लिए अधिकतम सकल वाहन भार कैसे निर्धारित करता है?","options":["सभी राजमार्गों पर एक निश्चित 80,000-pound की सीमा","एक्सल संख्या को 20,000 pounds से गुणा करके","एक्सल संख्या और दूरी के आधार पर राज्य के Bridge Gross Weight Formula को लागू करके","क़ानून द्वारा निर्धारित एक निश्चित 105,500-pound सीमा द्वारा"],"explanation":"17 AAC 25.013(a)(6) अधिकतम सकल भार को Bridge Gross Weight Formula W = 500[LN/(N-1) + 12N + 36] द्वारा निर्धारित करता है (ड्राइव समूह में कोई लिफ्ट एक्सल न होने पर +3,000 जोड़ा जाता है), न कि एक निश्चित 80,000-pound सीमा द्वारा। स्रोत: 17 AAC 25.013, Alaska DOT&PF।"},"13":{"q":"अलास्का के Bridge Gross Weight Formula W = 500[LN/(N-1) + 12N + 36] में, चर 'L' किसका प्रतिनिधित्व करता है?","options":["टन में कानूनी भार वजन","वाहन के सबसे बाहरी एक्सलों के केंद्रों के बीच की दूरी फीट में","सबसे लंबे ट्रेलर की लंबाई","लिफ्ट-एक्सल क्षमता"],"explanation":"17 AAC 25.013(a)(6) में, 'L' वाहन या संयोजन के सबसे बाहरी एक्सलों के केंद्रों के बीच मापी गई पूरे फीट में दूरी है, और 'N' एक्सलों की संख्या है। स्रोत: 17 AAC 25.013, Alaska DOT&PF।"},"14":{"q":"निर्माता की नाममात्र टायर चौड़ाई के आधार पर, अलास्का में एक टायर पर अनुमत अधिकतम भार कितना है?","options":["600 pounds per inch of tire width","500 pounds per inch of tire width","550 pounds per inch of tire width","650 pounds per inch of tire width"],"explanation":"17 AAC 25.013(a)(1) टायर निर्माता की नाममात्र टायर चौड़ाई की रेटिंग के आधार पर, टायर भार को 600 pounds per linear inch of tire width तक सीमित करता है। स्रोत: 17 AAC 25.013, Alaska DOT&PF।"},"15":{"q":"Alaska DOT&PF का ओवरसाइज़/ओवरवेट परमिट कब आवश्यक होता है?","options":["केवल 100,000 pounds सकल भार से अधिक भार के लिए","जब कोई वाहन या भार 17 AAC 25 में दी गई अधिकतम आयामों या भार से अधिक हो और किसी सार्वजनिक सड़क पर यात्रा करेगा","केवल कनाडा में राज्य सीमा पार करते समय","केवल 12 feet से अधिक चौड़े वाहनों के लिए"],"explanation":"Administrative Permit Manual (Sec. 2.2.1) और 17 AAC 25.320 के अनुसार, परमिट तब आवश्यक होता है जब कोई वाहन या भार-सहित-वाहन 17 AAC 25 में दी गई अधिकतम आयामों या भार से अधिक हो और किसी सार्वजनिक सड़क पर यात्रा करने का अनुरोध करे। स्रोत: Alaska DOT&PF Administrative Permit Manual; 17 AAC 25.320।"},"16":{"q":"अलास्का ओवरसाइज़/ओवरवेट परमिट केवल निम्नलिखित में से किस प्रकार के भार के लिए जारी करता है?","options":["विभाज्य भार जिन्हें कानूनी हिस्सों में विभाजित किया जा सकता है","अविभाज्य भार जिन्हें कानूनी आकार या वजन तक कम नहीं किया जा सकता","सरकारी एजेंसियों के स्वामित्व वाले भार","खतरनाक सामग्री ले जाने वाले भार"],"explanation":"अलास्का परमिट अविभाज्य भार (जिन्हें व्यावहारिक रूप से कानूनी आयामों/वजन तक कम नहीं किया जा सकता) के लिए जारी किए जाते हैं; विभाज्य भार को कानूनी सीमाओं तक तोड़ा जाना चाहिए। स्रोत: Alaska DOT&PF Administrative Permit Manual Sec. 2.2 और 17 AAC 25.320(a)(1)।"},"17":{"q":"अलास्का में, एकल-यात्रा ओवरसाइज़/ओवरवेट परमिट की मानक वैधता अवधि (एक तरफ 400 miles या उससे कम की आवाजाही के लिए) कितनी है?","options":["1 day","3 days","7 days","30 days"],"explanation":"Administrative Permit Manual Sec. 3.2.1 के अनुसार, एक एकल-यात्रा परमिट 3-day अवधि के लिए वैध होता है (यदि एक तरफ 400 miles से अधिक यात्रा हो तो 5 days तक बढ़ाया जाता है)। स्रोत: Alaska DOT&PF Administrative Permit Manual।"},"18":{"q":"अलास्का में सर्दियों के महीनों के दौरान, किसी वाहन पर बर्फ और हिम जमाव के प्रलेखित होने के लिए कितना अतिरिक्त सकल-भार भत्ता दिया जा सकता है?","options":["500 pounds","1,000 pounds","1,500 pounds","2,000 pounds"],"explanation":"17 AAC 25.335(b)(1) बर्फ और हिम जमाव का प्रमाण होने पर October 1 से April 30 तक एक अतिरिक्त 1,500-pound भत्ता देता है; संयोजन प्रकार की परवाह किए बिना यह अधिकतम है। स्रोत: 17 AAC 25.335, Alaska DOT&PF।"},"19":{"q":"26,001 pounds या उससे अधिक के सकल वाहन भार रेटिंग (GVWR) वाले एकल वाहन, जैसे डंप ट्रक या मोटर कोच, को संचालित करने के लिए अलास्का को किस CDL श्रेणी की आवश्यकता होती है?","options":["Class A","Class B","Class C","Class D"],"explanation":"Alaska CDL Manual Class B को 26,001 pounds से अधिक GVWR वाले किसी भी एकल वाहन, या ऐसे वाहन के रूप में परिभाषित करता है जो 10,000 lbs या उससे अधिक वजन न रखने वाली इकाई को खींचता हो (डंप ट्रक, सीमेंट मिक्सर, बॉक्स ट्रक, मोटर कोच)। स्रोत: Alaska DMV CDL Manual, Section 1, Vehicle Classifications।"},"20":{"q":"Alaska CDL Manual के अनुसार, 26,001 lbs या उससे अधिक GCWR वाले वाहनों के किसी भी संयोजन के लिए Class A CDL आवश्यक है, बशर्ते खींची गई इकाई(यों) का GVWR किस वजन से अधिक हो?","options":["8,000 pounds","10,000 pounds","16,000 pounds","26,001 pounds"],"explanation":"अलास्का Class A को 26,001+ lbs के GCWR वाले एक संयोजन के रूप में परिभाषित करता है जहां खींचे जा रहे वाहन(नों) का GVWR 10,000 pounds से अधिक हो (जैसे 18-wheelers, लॉगिंग ट्रक)। स्रोत: Alaska DMV CDL Manual, Section 1, Class A definition।"},"21":{"q":"अलास्का नियमों के तहत, 26,001 lbs से कम GVWR वाला वाहन भी CDL कार्यक्रम (Class C) में आता है यदि इसे चालक सहित कितने यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो?","options":["8 या अधिक","11 या अधिक","15 या अधिक","16 या अधिक"],"explanation":"Alaska CDL Manual एक छोटे वाहन को Class C के रूप में CDL कार्यक्रम में शामिल करता है यदि इसे चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो, या यह प्लेकार्ड-योग्य खतरनाक सामग्री ले जाता हो। स्रोत: Alaska DMV CDL Manual, Section 1, Class C definition।"},"22":{"q":"अलास्का में, प्लेकार्ड-योग्य मात्रा में खतरनाक सामग्री के परिवहन के लिए CDL पर कौन सा समर्थन (endorsement) अक्षर लगाया जाता है?","options":["Endorsement H","Endorsement N","Endorsement X","Endorsement T"],"explanation":"अलास्का प्लेकार्ड-योग्य मात्रा में खतरनाक सामग्री के परिवहन के लिए उपयोग किए जाने वाले किसी भी वाहन के लिए endorsement H (Hazardous Materials) का उपयोग करता है। स्रोत: Alaska DMV CDL Manual, Section 1, Endorsements table।"},"23":{"q":"थोक में तरल पदार्थ ढोने (टैंक ट्रक) के लिए इच्छित किसी भी वाहन के लिए अलास्का को किस समर्थन की आवश्यकता होती है?","options":["Endorsement H","Endorsement N","Endorsement P","Endorsement T"],"explanation":"Alaska CDL Manual थोक में तरल पदार्थ ढोने के लिए इच्छित किसी भी वाहन के लिए endorsement N (Tanker) सूचीबद्ध करता है। ध्यान दें कि टैंक समर्थन के लिए अलास्का का कोड अक्षर N है। स्रोत: Alaska DMV CDL Manual, Section 1, Endorsements table।"},"24":{"q":"डबल या ट्रिपल ट्रेलरों को खींचने के लिए किस अलास्का CDL समर्थन की आवश्यकता होती है?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement X"],"explanation":"अलास्का दो या तीन ट्रेलरों को खींचने वाले संयोजनों के लिए endorsement T (Double or Triple Trailers) निर्धारित करता है; केवल एक ज्ञान परीक्षा आवश्यक है। स्रोत: Alaska DMV CDL Manual, Section 1, Endorsements table।"},"25":{"q":"Alaska CDL Manual के अनुसार, 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए वाहन के लिए कौन सा समर्थन आवश्यक है?","options":["Endorsement S","Endorsement P","Endorsement N","Endorsement H"],"explanation":"अलास्का चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए किसी भी वाहन के लिए endorsement P (Passenger) की आवश्यकता रखता है, चाहे वास्तव में कितने यात्री ले जाए जाएं। इसके लिए एक ज्ञान और सड़क कौशल परीक्षा आवश्यक है। स्रोत: Alaska DMV CDL Manual, Section 1, Endorsements table।"},"26":{"q":"अलास्का में, CDL पर X समर्थन किस संयोजन का प्रतिनिधित्व करता है?","options":["संयुक्त टैंकर और खतरनाक सामग्री","संयुक्त यात्री और स्कूल बस","संयुक्त डबल्स और ट्रिपल्स","संयुक्त एयर ब्रेक और टैंकर"],"explanation":"अलास्का संयुक्त टैंकर/खतरनाक सामग्री संचालन के लिए endorsement X का उपयोग करता है: कोई भी टैंक वाहन जो प्लेकार्ड-योग्य मात्रा में खतरनाक सामग्री के परिवहन के लिए उपयोग किया जाता है। इसके लिए एक ज्ञान परीक्षा और एक पृष्ठभूमि जांच आवश्यक है। स्रोत: Alaska DMV CDL Manual, Section 1, Endorsements table।"},"27":{"q":"इससे पहले कि अलास्का खतरनाक सामग्री (H) समर्थन वाला CDL जारी या नवीनीकृत करे, आवेदक को पहले कौन सा चरण पूरा करना होगा?","options":["एक रक्षात्मक ड्राइविंग पाठ्यक्रम","एक Transportation Security Administration पृष्ठभूमि जांच","एक 30-day प्रतीक्षा अवधि","एक वाणिज्यिक वाहन निरीक्षण पाठ्यक्रम"],"explanation":"Alaska CDL Manual में कहा गया है कि HazMat समर्थन प्राप्त करने, जोड़ने या नवीनीकृत करने वाले सभी आवेदकों को जारी करने से पहले एक पृष्ठभूमि जांच पास करनी होगी, जिसे TSA/universalenroll.dhs.gov के माध्यम से संसाधित किया जाता है। स्रोत: Alaska DMV CDL Manual, Section 1, Endorsement H notes।"},"28":{"q":"अंतर्राज्यीय (केवल राज्य के भीतर) वाणिज्य तक सीमित अलास्का CDL जारी किए जाने के लिए न्यूनतम आयु कितनी है?","options":["16 years","17 years","18 years","21 years"],"explanation":"Alaska CDL Manual में कहा गया है कि आवेदन के समय आवेदक को अंतर्राज्यीय वाणिज्य में संचालन के लिए कम से कम 18 years का होना चाहिए (11/14/19 से प्रभावी), और कम से कम एक वर्ष के लिए एक वैध चालक लाइसेंस धारण किया हो। स्रोत: Alaska DMV CDL Manual, Section 1, Age requirements।"},"29":{"q":"अलास्का को CDL धारक द्वारा अंतरराज्यीय वाणिज्य में संचालन के लिए न्यूनतम कितनी आयु की आवश्यकता है?","options":["18 years","19 years","20 years","21 years"],"explanation":"Alaska CDL Manual में कहा गया है कि आवेदक को अंतरराज्यीय वाणिज्य में संचालन के लिए कम से कम 21 years का होना चाहिए। 21 से कम आयु के चालकों को K (केवल अंतर्राज्यीय) प्रतिबंध मिलता है। स्रोत: Alaska DMV CDL Manual, Section 1, Age requirements and Restriction K।"},"30":{"q":"संघीय नियम और अलास्का अभ्यास दोनों के तहत, CDL सड़क कौशल परीक्षा देने से पहले किसी आवेदक को कितने समय तक एक Commercial Learner's Permit (CLP) धारण करना होगा?","options":["कम से कम 7 days","कम से कम 10 days","कम से कम 14 days","कम से कम 30 days"],"explanation":"Alaska CDL Manual में कहा गया है कि आवेदक को सड़क कौशल परीक्षा देने से पहले कम से कम 14 days तक एक CLP धारण करना होगा, जिसमें श्रेणी को उन्नत करते समय या कौशल परीक्षा की आवश्यकता वाला समर्थन जोड़ते समय भी शामिल है। स्रोत: Alaska DMV CDL Manual, Section 1, Testing and Issuance Requirements।"},"31":{"q":"अलास्का Commercial Learner's Permit प्राप्त करने से पहले, आवेदक के पास पहले से क्या होना चाहिए?","options":["एक वर्तमान वैध अलास्का गैर-वाणिज्यिक चालक लाइसेंस","एक संघीय DOT परिचालन प्राधिकरण संख्या","एक पूर्ण प्रशिक्षुता प्रमाणपत्र","किसी अन्य राज्य से पूर्व CDL"],"explanation":"Alaska DMV CLP पृष्ठ के अनुसार आवेदकों को CLP जारी किए जाने से पहले एक वर्तमान वैध अलास्का गैर-वाणिज्यिक चालक लाइसेंस होना आवश्यक है। स्रोत: Alaska DMV Commercial Learner's Permit (CLP) page।"},"32":{"q":"अलास्का CLP पर गाड़ी चलाते समय, परमिट धारक के बगल की सीट में साथ बैठे लाइसेंस प्राप्त चालक के पास उचित श्रेणी/समर्थन होने चाहिए और उसकी आयु कम से कम कितनी होनी चाहिए?","options":["18 years old","19 years old","21 years old","25 years old"],"explanation":"Alaska DMV CLP पृष्ठ के अनुसार, एक CLP धारक केवल अपनी श्रेणी या उससे छोटे वाहन का संचालन कर सकता है, जिसमें बगल की सीट में एक वैध लाइसेंस प्राप्त चालक हो जो कम से कम 21 वर्ष का हो, उचित श्रेणी और समर्थन रखता हो, और एक वर्ष से लाइसेंस प्राप्त हो। स्रोत: Alaska DMV Commercial Learner's Permit (CLP) page।"},"33":{"q":"अलास्का में एक CLP धारक जिसके पास यात्री (P) समर्थन है, किस प्रतिबंध के अधीन है?","options":["केवल निजी संपत्ति पर खाली यात्री बसें चला सकता है","निर्दिष्ट परीक्षकों, प्रशिक्षुओं और साथ में CDL धारक को छोड़कर किसी CMV बस में कोई यात्री नहीं ले जा सकता","दिन के उजाले के घंटों के दौरान 8 तक यात्री ले जा सकता है","केवल अंतर्राज्यीय मार्गों पर यात्री ले जा सकता है"],"explanation":"Alaska CDL Manual के P प्रतिबंध में कहा गया है कि P समर्थन वाले CLP धारक को संघीय/राज्य लेखा परीक्षकों, निरीक्षकों, परीक्षा परीक्षकों, अन्य प्रशिक्षुओं और साथ में CDL धारक के अलावा CMV बस में यात्रियों को ले जाने से प्रतिबंधित किया गया है (49 CFR 383.25 के अनुसार)। स्रोत: Alaska DMV CDL Manual, Restriction P।"},"34":{"q":"अलास्का में N (टैंकर) समर्थन वाला एक CLP धारक X प्रतिबंध द्वारा टैंक वाहनों को किस स्थिति में संचालित करने तक सीमित है?","options":["केवल खाली टैंक वाहन, न कि वे जिनमें बिना शुद्ध किया गया हैज़मैट अवशेष हो","केवल 1,000 gallons से कम टैंक वाहन","केवल एकल-एक्सल टैंक वाहन","केवल निजी सड़कों पर टैंक वाहन"],"explanation":"Alaska CDL Manual के X प्रतिबंध में कहा गया है कि N समर्थन वाला परमिट धारक केवल एक खाली टैंक वाहन का संचालन कर सकता है और किसी भी ऐसे टैंक वाहन का संचालन करने से प्रतिबंधित है जिसमें पहले खतरनाक सामग्री थी और जिसके अवशेष को शुद्ध नहीं किया गया है। स्रोत: Alaska DMV CDL Manual, Restriction X।"},"35":{"q":"January 1, 2012 से प्रभावी, सभी अलास्का CDL चालकों को कितने प्रकार के CMV संचालन में से एक के लिए स्व-प्रमाणन करना होगा?","options":["दो","तीन","चार","पांच"],"explanation":"Alaska CDL Manual चार स्व-प्रमाणन श्रेणियां सूचीबद्ध करता है: non-excepted interstate, excepted interstate, non-excepted intrastate, और excepted intrastate। स्रोत: Alaska DMV CDL Manual, Medical Certificate and Self-Certification Requirements (49 CFR 383.71)।"},"36":{"q":"यदि किसी अलास्का CDL धारक का फ़ाइल पर मौजूद चिकित्सा परीक्षक प्रमाणपत्र समाप्त हो जाता है, तो CDL को डाउनग्रेड करने से पहले राज्य के पास कितना समय होता है?","options":["समाप्ति के 15 days के भीतर","समाप्ति के 30 days के भीतर","समाप्ति के 60 days के भीतर","समाप्ति के 90 days के भीतर"],"explanation":"Alaska CDL Manual में कहा गया है कि, January 1, 2012 से प्रभावी, राज्य को फ़ाइल पर समाप्त चिकित्सा प्रमाणपत्र वाले किसी भी CDL धारक को समाप्ति के 60 days के भीतर डाउनग्रेड करना आवश्यक है। स्रोत: Alaska DMV CDL Manual, Medical Certificate and Self-Certification Requirements।"},"37":{"q":"अलास्का में लागू संघीय ELDT नियम के तहत, एक पहली बार आवेदन करने वाले को कौशल परीक्षा देने से पहले कहां सूचीबद्ध प्रदाता से Entry-Level Driver Training पूरा करना होगा?","options":["Alaska DMV का आंतरिक प्रशिक्षण डेटाबेस","FMCSA Training Provider Registry","राज्य प्रशिक्षुता परिषद सूची","CDLIS राष्ट्रीय चालक रजिस्ट्री"],"explanation":"अलास्का को पहली बार Class A या B आवेदकों, अपग्रेड, और नए H/P/S समर्थनों के लिए ELDT की आवश्यकता है; प्रशिक्षण FMCSA Training Provider Registry पर सूचीबद्ध प्रदाता से आना चाहिए, जो कौशल परीक्षा से पहले DMV को पूर्णता प्रेषित करता है। स्रोत: Alaska DMV Entry-Level Driver Training (ELDT) page।"},"38":{"q":"अलास्का क़ानून/विनियमन (2 AAC 90.420) के अनुसार, अलास्का में पहले कभी लाइसेंस प्राप्त न करने वाले किसी भी व्यक्ति के लिए जन्म और पहचान दस्तावेजों के साथ CDL प्राप्त करने के लिए कौन सा दस्तावेज़ विशेष रूप से आवश्यक है?","options":["एक Social Security number","एक पासपोर्ट कार्ड","एक मतदाता पंजीकरण कार्ड","एक वाहन शीर्षक"],"explanation":"Alaska CDL Manual 2 AAC 90.420(a) का हवाला देता है: अलास्का में पहले कभी लाइसेंस प्राप्त न करने वाले आवेदकों के लिए, जन्म और पहचान दस्तावेजों के साथ, CDL प्राप्त करने के लिए एक Social Security number आवश्यक है। अलास्का अधिवास और वैध उपस्थिति का प्रमाण भी आवश्यक है। स्रोत: Alaska DMV CDL Manual, Testing and Issuance Requirements; 2 AAC 90.420।"},"39":{"q":"अलास्का में, किस रक्त अल्कोहल सांद्रता (BAC) पर वाणिज्यिक मोटर वाहन (CMV) चलाना अवैध है?","options":["0.04% या अधिक","0.08% या अधिक","0.02% या अधिक","0.10% या अधिक"],"explanation":"Alaska CDL Manual section 1.3.2 में कहा गया है कि यदि आपका BAC .04% या अधिक है तो CMV चलाना अवैध है, जो गैर-वाणिज्यिक चालकों के लिए 0.08% सीमा का आधा है। स्रोत: Alaska DMV Commercial Driver License Manual, sec. 1.3.2।"},"40":{"q":"अलास्का के निहित सहमति कानून के तहत, राज्य में केवल एक CMV संचालित करके आप किस बात के लिए सहमत हो गए हैं?","options":["अल्कोहल के लिए अपनी सांस की रासायनिक जांच के लिए प्रस्तुत होना","किसी भी समय अपने कार्गो की तलाशी की अनुमति देना","घटनास्थल छोड़ने से पहले सभी चालान जुर्माने का भुगतान करना","कैब में एक पोर्टेबल सांस परीक्षण उपकरण रखना"],"explanation":"Alaska CDL Manual में कहा गया है कि जब आप एक CMV संचालित करते हैं तो आप पहले से ही अपनी सांस की रासायनिक जांच के लिए सहमत हो चुके हैं, और आपको 'अल्कोहल परीक्षण के लिए अपनी सहमति देने वाला माना जाता है।' स्रोत: Alaska DMV CDL Manual, Implied Consent / sec. 1.3.2।"},"41":{"q":"एक अलास्का CDL धारक पहला बड़ा अपराध करता है, जैसे 0.04% या अधिक BAC के साथ CMV चलाना। न्यूनतम अयोग्यता क्या है?","options":["1 year","60 days","6 months","3 years"],"explanation":"अलास्का पहले बड़े अपराध (DUI, इनकार, घटनास्थल छोड़ना, आदि) के लिए चालक को कम से कम 1 year के लिए अयोग्य ठहराता है। स्रोत: Alaska DMV CDL Manual, secs. 1.3.2 और Major Disqualifying Offenses table (49 CFR 383.51 का अनुसरण करता है)।"},"42":{"q":"यदि चालक खतरनाक सामग्री के लिए प्लेकार्ड किए गए CMV को संचालित करते समय पहला बड़ा अपराध करता है, तो अलास्का अयोग्यता कितनी लंबी होती है?","options":["3 years","1 year","5 years","आजीवन"],"explanation":"अलास्का खतरनाक सामग्री के लिए प्लेकार्ड किए गए CMV में अपराध होने पर पहले-बड़े-अपराध की अयोग्यता को कम से कम 3 years तक बढ़ा देता है। स्रोत: Alaska DMV CDL Manual, sec. 1.3.2 / Major Disqualifying Offenses table।"},"43":{"q":"दूसरे बड़े अपराध (उदाहरण के लिए, CMV में दूसरा DUI) के लिए अलास्का अयोग्यता क्या है?","options":["आजीवन","10 years","3 years","5 years"],"explanation":"अलास्का दूसरे बड़े अपराध के लिए चालक को जीवन भर के लिए अयोग्य ठहराता है। स्रोत: Alaska DMV CDL Manual, sec. 1.3.2 और Major Disqualifying Offenses table (49 CFR 383.51)।"},"44":{"q":"किसी नियंत्रित पदार्थ के निर्माण, वितरण या वितरण से जुड़े अपराध करने के लिए CMV का उपयोग करने पर पहले अपराध पर भी कौन सी अलास्का अयोग्यता लगती है?","options":["आजीवन, बिना किसी पुनर्बहाली के","1 year","3 years","10 years"],"explanation":"Alaska CDL Manual में कहा गया है कि यदि आप नियंत्रित पदार्थों से जुड़े अपराध करने के लिए CMV का उपयोग करते हैं तो आप अपना CDL जीवन भर के लिए खो देंगे। स्रोत: Alaska DMV CDL Manual, sec. 1.3.2।"},"45":{"q":"Alaska CDL Manual में निम्नलिखित में से किसे एक बड़े (MAJOR) अयोग्यता वाले अपराध के रूप में सूचीबद्ध किया गया है?","options":["किसी CMV से जुड़ी दुर्घटना का घटनास्थल छोड़ना","किसी अन्य वाहन का बहुत करीब से पीछा करना","सीमा से 15 mph या अधिक की गति","एक अनुचित या अनियमित लेन परिवर्तन"],"explanation":"किसी दुर्घटना का घटनास्थल छोड़ना एक बड़ा अपराध है (1 year / आजीवन)। अन्य तीन गंभीर यातायात उल्लंघन हैं, बड़े अपराध नहीं। स्रोत: Alaska DMV CDL Manual, sec. 1.3.2 और 1.3.3।"},"46":{"q":"यदि आप अलास्का में अल्कोहल परीक्षण के लिए प्रस्तुत होने से इनकार करते हैं, तो पहले इनकार के लिए आपके CDL का क्या होता है?","options":["कम से कम 1 year के लिए अयोग्य (हैज़मैट ढोने पर 3 years)","90 days के लिए अयोग्य","केवल एक चेतावनी; कोई अयोग्यता नहीं","जीवन भर के लिए अयोग्य"],"explanation":"इनकार को एक बड़े अपराध के रूप में माना जाता है: कम से कम 1 year की अयोग्यता, या खतरनाक सामग्री के परिवहन के मामले में 3 years। स्रोत: Alaska DMV CDL Manual, Implied Consent और sec. 1.3.2।"},"47":{"q":"Alaska CDL Manual के निहित-सहमति प्रावधान के अनुसार, रासायनिक परीक्षण के लिए प्रस्तुत होने से दूसरे या बाद के इनकार के लिए न्यूनतम अयोग्यता क्या है?","options":["10 years","3 years","5 years","1 year"],"explanation":"Alaska CDL Manual के निहित-सहमति पाठ में कहा गया है कि दूसरे और बाद के इनकार पर न्यूनतम 10-year अयोग्यता लगती है। स्रोत: Alaska DMV CDL Manual, Implied Consent provision।"},"48":{"q":"0.04% से कम किसी भी पता लगाने योग्य मात्रा में अल्कोहल पाए जाने वाले अलास्का CMV चालक का क्या होता है?","options":["24 hours के लिए सेवा से बाहर (out-of-service) रखा जाता है","60 days के लिए अयोग्य","1 year के लिए अयोग्य","बिना किसी सेवा-से-बाहर अवधि के $500 का जुर्माना"],"explanation":"Alaska CDL Manual में कहा गया है कि यदि आपके पास .04% से कम किसी भी पता लगाने योग्य मात्रा में अल्कोहल है तो आपको 24 hours के लिए सेवा से बाहर कर दिया जाएगा। स्रोत: Alaska DMV CDL Manual, sec. 1.3.2।"},"49":{"q":"अलास्का CDL धारक के लिए एक गंभीर (SERIOUS) यातायात उल्लंघन के रूप में गिने जाने वाली, निर्धारित सीमा से ऊपर न्यूनतम गति क्या है?","options":["सीमा से 15 mph या अधिक","सीमा से 10 mph या अधिक","सीमा से 20 mph या अधिक","सीमा से 5 mph या अधिक"],"explanation":"अत्यधिक गति का अर्थ है निर्धारित सीमा से 15 mph या अधिक, जो एक गंभीर यातायात उल्लंघन है। स्रोत: Alaska DMV CDL Manual, sec. 1.3.3।"},"50":{"q":"तीन-वर्ष की अवधि के भीतर किसी CMV में दो गंभीर यातायात उल्लंघन करने के लिए अलास्का अयोग्यता कितनी लंबी होती है?","options":["कम से कम 60 days","कम से कम 30 days","कम से कम 120 days","कम से कम 1 year"],"explanation":"3 years के भीतर दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप कम से कम 60 days की अयोग्यता होती है। स्रोत: Alaska DMV CDL Manual, sec. 1.3.3 और Serious Disqualifying Offenses table।"},"51":{"q":"तीन-वर्ष की अवधि के भीतर किसी CMV में तीन या अधिक गंभीर यातायात उल्लंघन करने के लिए अलास्का अयोग्यता कितनी लंबी होती है?","options":["कम से कम 120 days","कम से कम 60 days","कम से कम 90 days","कम से कम 1 year"],"explanation":"3 years के भीतर तीन या अधिक गंभीर यातायात उल्लंघनों के परिणामस्वरूप कम से कम 120 days की अयोग्यता होती है। स्रोत: Alaska DMV CDL Manual, sec. 1.3.3 और Serious Disqualifying Offenses table।"},"52":{"q":"इनमें से किसे Alaska CDL Manual में एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध नहीं किया गया है?","options":["0.04% या अधिक BAC के साथ CMV चलाना","किसी वाहन का बहुत करीब से पीछा करना","अनुचित या अनियमित लेन परिवर्तन","उचित श्रेणी के CDL के बिना CMV चलाना"],"explanation":"0.04% या अधिक BAC के साथ गाड़ी चलाना एक बड़ा (MAJOR) अपराध है, गंभीर यातायात उल्लंघन नहीं। अन्य तीन गंभीर यातायात उल्लंघन हैं। स्रोत: Alaska DMV CDL Manual, secs. 1.3.2 और 1.3.3।"},"53":{"q":"अलास्का कानून (AS 28.33.190) के तहत, CMV चलाते समय टेक्स्टिंग या हाथ में पकड़े मोबाइल फोन का उपयोग करना किस रूप में वर्गीकृत है?","options":["एक गंभीर यातायात उल्लंघन (इलेक्ट्रॉनिक उपकरण का उपयोग)","एक बड़ा अयोग्यता वाला अपराध","एक सेवा-से-बाहर आदेश का उल्लंघन","एक गैर-रिपोर्ट योग्य उल्लंघन"],"explanation":"अलास्का गंभीर अयोग्यता वाले अपराधों में 'गाड़ी चलाते समय इलेक्ट्रॉनिक उपकरण का उपयोग' (AS 28.33.190(16)(H)) को सूचीबद्ध करता है, जो 60-day/120-day सीमाओं की ओर गिना जाता है। स्रोत: Alaska DMV CDL Manual, Serious Disqualifying Offenses; AS 28.33.190।"},"54":{"q":"Alaska CDL Manual में वर्णित हाथ में पकड़े मोबाइल फोन प्रतिबंध का उल्लंघन करने के लिए एक CMV चालक को अधिकतम कितना नागरिक दंड भुगतना पड़ सकता है?","options":["$2,750 तक","$11,000 तक","$500 तक","$1,000 तक"],"explanation":"हाथ में पकड़े फोन के प्रत्येक उल्लंघन पर चालक को $2,750 तक का नागरिक दंड लगता है; नियोक्ताओं को $11,000 तक का सामना करना पड़ता है। स्रोत: Alaska DMV CDL Manual, sec. 2.9.4 (hand-held mobile telephones)।"},"55":{"q":"CMV संचालित करते समय एक सेवा-से-बाहर (OOS) आदेश के पहले उल्लंघन (कोई हैज़मैट या यात्री नहीं) के लिए अलास्का अयोग्यता क्या है?","options":["180 days से कम नहीं और 1 year से अधिक नहीं","90 days से कम नहीं और 1 year से अधिक नहीं","ठीक 60 days","2 years से कम नहीं और 5 years से अधिक नहीं"],"explanation":"अलास्का पहले OOS-आदेश उल्लंघन के लिए 180 days से कम नहीं और 1 year से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: Alaska DMV CDL Manual, Violating Out-of-Service Orders table (AS 28.33.140(j))।"},"56":{"q":"खतरनाक सामग्री या यात्रियों के परिवहन के दौरान किए गए पहले सेवा-से-बाहर आदेश के उल्लंघन के लिए अलास्का अयोग्यता कितनी लंबी होती है?","options":["180 days से कम नहीं और 2 years से अधिक नहीं","180 days से कम नहीं और 1 year से अधिक नहीं","1 year से कम नहीं और 5 years से अधिक नहीं","ठीक 120 days"],"explanation":"हैज़मैट या यात्रियों को ढोते समय पहला OOS-आदेश उल्लंघन 180 days से कम नहीं और 2 years से अधिक नहीं के लिए अयोग्य ठहराया जाता है। स्रोत: Alaska DMV CDL Manual, Violating Out-of-Service Orders table (AS 28.33.140(j))।"},"57":{"q":"10-वर्ष की अवधि के भीतर दूसरे सेवा-से-बाहर आदेश के उल्लंघन (गैर-हैज़मैट) के लिए अलास्का अयोग्यता क्या है?","options":["1 year से कम नहीं और 5 years से अधिक नहीं","180 days से कम नहीं और 1 year से अधिक नहीं","3 years से कम नहीं और 5 years से अधिक नहीं","आजीवन"],"explanation":"10 years के भीतर दूसरे OOS-आदेश उल्लंघन पर 1 year से कम नहीं और 5 years से अधिक नहीं लगता है; हैज़मैट या यात्रियों के साथ यह 3 से 5 years है। स्रोत: Alaska DMV CDL Manual, Violating Out-of-Service Orders table।"},"58":{"q":"CMV संचालित करते समय पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए, अलास्का अयोग्यता क्या है?","options":["कम से कम 60 days","कम से कम 15 days","कम से कम 120 days","कम से कम 1 year"],"explanation":"अलास्का पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए कम से कम 60 days के लिए अयोग्य ठहराता है; 3 years के भीतर दूसरा 120 days है, और 3 years के भीतर तीसरा 1 year है। स्रोत: Alaska DMV CDL Manual, sec. 1.3.5 / Railroad-Highway Grade Crossing Violations table।"},"59":{"q":"अलास्का में, खतरनाक सामग्री (placarded hazardous materials) ले जाने वाली बस या वाहन को रेलरोड-हाईवे क्रॉसिंग पर निकटतम रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["15 और 50 feet के बीच","5 और 15 feet के बीच","50 और 100 feet के बीच","10 और 25 feet के बीच"],"explanation":"Alaska CDL Manual (Sections 4.3.5 और 9.6.12) के अनुसार बसों और placarded HazMat वाहनों को निकटतम रेल से 15 feet से अधिक पास नहीं और 50 feet से अधिक दूर नहीं रुकना चाहिए, फिर क्रॉसिंग से पहले देखना और सुनना चाहिए।"},"60":{"q":"अलास्का के Move Over कानून के तहत, जब कोई चालक एक ही दिशा में दो या अधिक लेन वाली सड़क पर फ्लैशिंग लाइट दिखाने वाले रुके हुए आपातकालीन वाहन के पास पहुंचता है, तो चालक को क्या करना चाहिए:","options":["जब ऐसा करना सुरक्षित हो तो आपातकालीन वाहन के सबसे निकट की लेन खाली कर देनी चाहिए","आपातकालीन वाहन के जाने तक पूरी तरह रुक जाना चाहिए","हॉर्न बजाकर निर्धारित गति पर चलते रहना चाहिए","किनारे (shoulder) पर खींचकर तीन मिनट प्रतीक्षा करनी चाहिए"],"explanation":"Alaska Statute AS 28.35.185 के अनुसार एक ही दिशा में दो या अधिक लेन वाली सड़क पर चालकों को, यदि ऐसा करना सुरक्षित हो, फ्लैशिंग लाइट वाले रुके हुए आपातकालीन, अग्निशमन, कानून प्रवर्तन, टो, रखरखाव, या पशु-नियंत्रण वाहन के सबसे निकट की लेन खाली करनी होती है।"},"61":{"q":"जब किसी स्कूल बस के लिए रुकना हो जिसकी लाल बत्तियाँ फ्लैश कर रही हों, तो अलास्का का कानून पास आ रहे चालक से बस से कम से कम कितनी दूरी पर रुकने की मांग करता है?","options":["30 feet","15 feet","20 feet","50 feet"],"explanation":"Alaska Statute AS 28.35.145 के अनुसार फ्लैशिंग लाल बत्तियों वाली स्कूल बस के पास आ रहे चालक को बस से कम से कम 30 feet की दूरी पर रुकना चाहिए और बत्तियाँ फ्लैश करना बंद होने तक आगे नहीं बढ़ना चाहिए।"},"62":{"q":"गली (alley), व्यावसायिक जिले (business district), या आवासीय जिले (residential district) के अलावा किसी भी सड़क पर, जब तक अन्यथा निर्दिष्ट न हो, अलास्का में किसी वाणिज्यिक मोटर वाहन के लिए अधिकतम वैध गति क्या है?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"Alaska Administrative Code 13 AAC 03.275 किसी भी अन्य सड़क पर वाणिज्यिक मोटर वाहनों के लिए अधिकतम वैध गति 55 mph निर्धारित करता है (गली में 15 mph, व्यावसायिक जिले में 20 mph, आवासीय जिले में 25 mph)।"},"63":{"q":"अलास्का के स्कूल-बस रुकने के कानून में विभाजित राजमार्गों (divided highways) के लिए एक अपवाद है। पास आ रहे चालक को स्कूल बस के लिए रुकने की आवश्यकता कब नहीं होती?","options":["जब बस अलग-अलग सड़कों वाले राजमार्ग की किसी भिन्न सड़क पर हो","जब चालक सीमा से कम से कम 10 mph नीचे की गति से चल रहा हो","जब बस 100 feet से अधिक दूर हो","जब बस के पास कोई बच्चा दिखाई न दे"],"explanation":"AS 28.35.145 के तहत, अलग-अलग सड़कों वाले राजमार्ग पर चालक को किसी भिन्न सड़क पर मौजूद स्कूल बस से मिलते या उसे पास करते समय रुकने की आवश्यकता नहीं होती (विभाजित-राजमार्ग अपवाद)।"},"64":{"q":"अलास्का में एक-तरफा या विभाजित राजमार्ग पर वाणिज्यिक वाहन रोकने के बाद, चालक को तीन चेतावनी त्रिकोण (warning triangles) किन स्थानों पर रखने चाहिए?","options":["पास आ रहे यातायात की ओर लगभग 10 feet, 100 feet, और 200 feet पर","पास आ रहे यातायात की ओर लगभग 10 feet, 50 feet, और 150 feet पर","पास आ रहे यातायात की ओर लगभग 25 feet, 100 feet, और 250 feet पर","पास आ रहे यातायात की ओर लगभग 50 feet, 100 feet, और 500 feet पर"],"explanation":"Alaska CDL Manual (Section 2.5) के अनुसार, एक-तरफा या विभाजित राजमार्ग पर चेतावनी उपकरण वाहन से पास आ रहे यातायात की ओर 10 feet, 100 feet, और 200 feet पर रखे जाते हैं।"},"65":{"q":"एक चालक जो अलास्का के Move Over कानून (AS 28.35.185) का उल्लंघन करता है और शारीरिक चोट पहुंचाता है, वह किस अपराध का दोषी है?","options":["एक class A misdemeanor","केवल एक infraction","एक class B felony","एक ऐसा उल्लंघन जिसमें कोई अंक नहीं लगते"],"explanation":"AS 28.35.185(b) के अनुसार जब लेन खाली करने या गति धीमी करने में विफलता से शारीरिक चोट होती है, तो Move Over उल्लंघन एक class A misdemeanor होता है; अन्यथा यह एक infraction है।"},"66":{"q":"दोनों दिशाओं में यातायात ले जाने वाली दो-लेन वाली सड़क पर, Alaska CDL Manual चालक को रुकने के बाद चेतावनी त्रिकोण कहाँ रखने का निर्देश देता है?","options":["वाहन के 10 feet के भीतर, और इसके 100 feet पीछे और आगे","वाहन के 25 feet के भीतर, और इसके 200 feet पीछे और आगे","केवल वाहन के 100 feet पीछे","केवल वाहन के 10, 100, और 200 feet पीछे"],"explanation":"Alaska CDL Manual (Section 2.5) के अनुसार एक अविभाजित दो-तरफा सड़क पर, एक त्रिकोण वाहन के 10 feet के भीतर रखें और एक-एक इसके 100 feet पीछे और आगे किनारे (shoulder) पर या लेन में रखें।"},"67":{"q":"अलास्का CDL नियमों के तहत रेलरोड पटरियों को पार करने से पहले अनिवार्य रूप से रुकना आवश्यक वाहनों की कौन सी सूची सही है?","options":["Placarded वाहन, क्लोरीन ले जाने वाला कोई भी वाहन, और खतरनाक सामग्री के लिए उपयोग किए जाने वाले cargo-tank वाहन","केवल triple-trailer संयोजन","केवल 30 से अधिक यात्री ले जाने वाली बसें","26,000 pounds सकल वजन से अधिक के सभी वाहन"],"explanation":"Alaska CDL Manual Section 9.6.12 उन वाहनों की सूची देता है जिन्हें रेलरोड क्रॉसिंग पर रुकना चाहिए: placarded वाहन, किसी भी मात्रा में क्लोरीन ले जाने वाला कोई भी वाहन, और खतरनाक सामग्री के लिए उपयोग किए जाने वाले cargo-tank वाहन (भरे हुए या खाली)।"},"68":{"q":"सड़क पर रुकने के बाद अलास्का CDL चालक को आपातकालीन चेतावनी उपकरण लगाने के लिए कितना समय मिलता है?","options":["10 मिनट के भीतर","5 मिनट के भीतर","15 मिनट के भीतर","तुरंत, 1 मिनट के भीतर"],"explanation":"Alaska CDL Manual (Section 2.5) में कहा गया है कि यदि आपको सड़क पर या उसके किनारे रुकना पड़े, तो आपको अपने आपातकालीन चेतावनी उपकरण 10 मिनट के भीतर लगाने होंगे।"},"69":{"q":"जब किसी अलास्का CDL चालक को सड़क के किनारे वाणिज्यिक वाहन रोकना पड़े, तो तीन आवश्यक चेतावनी उपकरण कौन से हैं?","options":["तीन लाल परावर्तक त्रिकोण, या 6 fusees, या 3 तरल-दहन फ्लेयर (liquid-burning flares)","दो लाल लालटेन और एक लाल झंडा","चार amber परावर्तक","एक परावर्तक त्रिकोण और दो road flares"],"explanation":"Alaska CDL Manual खड़े वाहनों के लिए स्वीकार्य चेतावनी उपकरणों के रूप में तीन लाल परावर्तक त्रिकोण, कम से कम 6 fusees, या 3 तरल-दहन फ्लेयर सूचीबद्ध करता है।"},"70":{"q":"अलास्का में एक स्कूल-बस चालक जिसे रेलरोड क्रॉसिंग पर रुकना पड़े, उसे पार करने से पहले निम्नलिखित में से कौन सा कार्य भी करना चाहिए?","options":["यदि इससे पास आ रही ट्रेन को देखने या सुनने की क्षमता बढ़ती है तो आगे का दरवाजा खोलें","हॉर्न तीन बार बजाएं","पहले सभी यात्रियों को बस से बाहर निकालें","पटरियों पर रहते हुए निचले गियर में शिफ्ट करें"],"explanation":"Alaska CDL Manual (Section 4.3.5) बस चालकों को निर्देश देता है कि वे क्रॉसिंग से 15 से 50 feet पहले रुकें, दोनों दिशाओं में देखें और सुनें, और यदि इससे ट्रेन को देखने या सुनने की क्षमता बढ़ती है तो आगे का दरवाजा खोलें।"},"71":{"q":"यदि कोई वाणिज्यिक वाहन किसी पहाड़ी या मोड़ के आगे सड़क के किनारे रुका हुआ है जो अन्य चालकों के दृश्य को 500 feet के भीतर अवरुद्ध करता है, तो अलास्का CDL चालक को चेतावनी त्रिकोणों के साथ क्या करना चाहिए?","options":["सबसे पीछे वाले त्रिकोण को सड़क पर और पीछे ले जाएं ताकि अवरोध से परे चेतावनी प्रदान हो","सभी तीन त्रिकोण सीधे वाहन के पीछे रखें","त्रिकोण हटा दें और केवल four-way flashers पर निर्भर रहें","एक त्रिकोण cab के ऊपर रखें"],"explanation":"Alaska CDL Manual (Section 2.5) निर्देश देता है कि यदि कोई पहाड़ी, मोड़, या अन्य अवरोध 500 feet के भीतर दृष्टि रेखा को अवरुद्ध करता है, तो चालक को सबसे पीछे वाले त्रिकोण को सड़क पर और पीछे ले जाना चाहिए ताकि चेतावनी प्रदान हो।"},"72":{"q":"अलास्का में एक विभाजित राजमार्ग पर, बच्चों को चढ़ाने वाली स्कूल बस के लिए रुकने से कौन सा पास आ रहा चालक छूट प्राप्त है?","options":["विपरीत सड़क पर एक चालक जो बस से median या barrier द्वारा अलग है","उसी लेन में बस के ठीक पीछे एक चालक","बस को दाहिने किनारे (right shoulder) से पास करने वाला एक चालक","20 mph से कम गति से चलने वाला कोई भी चालक"],"explanation":"AS 28.35.145 का अलग-सड़क अपवाद विभाजित राजमार्ग की विपरीत सड़क पर चालकों पर लागू होता है; बस वाली उसी सड़क पर चालकों को, जिनमें उसके पीछे वाले भी शामिल हैं, फिर भी रुकना होगा।"},"73":{"q":"एक ही दिशा में दो से कम लेन वाली सड़क पर, जब कोई चालक फ्लैशिंग लाइट वाले रुके हुए आपातकालीन वाहन को पास करता है तो अलास्का का Move Over कानून क्या मांग करता है?","options":["यातायात, सड़क, और मौसम को देखते हुए एक उचित और विवेकपूर्ण गति तक धीमा करें","निर्धारित गति सीमा को ठीक-ठीक बनाए रखें","आगे बढ़ने का संकेत मिलने तक पूरी तरह रुकें","पूरी तरह विपरीत किनारे (opposite shoulder) पर चले जाएं"],"explanation":"AS 28.35.185 के अनुसार जहाँ एक ही दिशा में दो से कम लेन हों, चालक को यातायात, सड़क, और मौसम की स्थितियों को ध्यान में रखते हुए एक उचित और विवेकपूर्ण गति तक धीमा करना होगा।"},"74":{"q":"अलास्का में रेलरोड पटरियों को पार करते समय, एक CDL चालक को क्या करना चाहिए:","options":["पटरियों को पार करते समय गियर न बदलें","अधिकतम नियंत्रण के लिए पटरियों पर पहले गियर में डाउनशिफ्ट करें","यदि कोई ट्रेन दिखाई न दे तो पटरियों पर रुकें","तेजी से गति बढ़ाएं और बीच में अपशिफ्ट करें"],"explanation":"Alaska CDL Manual (Sections 2.15 और 9.6.12) चालकों को चेतावनी देता है कि पटरियों को पार करते समय कभी गियर न बदलें, क्योंकि गियर चूक जाने से वाहन क्रॉसिंग पर रुक (stall) सकता है।"},"75":{"q":"अलास्का में बिना किसी ओवरसाइज़ परमिट के सार्वजनिक राजमार्ग पर चल सकने वाली अधिकतम वैध वाहन/लोड चौड़ाई क्या है?","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","120 inches (10 feet)","108 inches (9 feet)"],"explanation":"अलास्का का Oversize/Overweight Permit Manual 17 AAC 25 की 102-inch (8 feet 6 inches) वैध चौड़ाई सीमा का संदर्भ देता है; इससे अधिक चौड़ी किसी भी चीज़ के लिए परमिट और OVERSIZE/WIDE LOAD संकेतों की आवश्यकता होती है।"},"76":{"q":"अलास्का के ओवरसाइज़-परमिट नियमों के तहत, एक चौड़े लोड (wide load) को उसकी चौड़ाई के इससे अधिक होने पर सभी मार्गों पर कम से कम एक pilot/escort वाहन की आवश्यकता होती है:","options":["10 feet 6 inches","8 feet 6 inches","12 feet","9 feet"],"explanation":"अलास्का का Oversize/Overweight Permit Manual (Section 6.2.1) तब सभी मार्गों पर कम से कम एक pilot/escort वाहन की मांग करता है जब कोई वाहन या लोड चौड़ाई में 10 feet 6 inches से अधिक हो।"},"77":{"q":"अलास्का के परमिट नियमों के तहत, एक लोड जो 17 feet की ऊंचाई से अधिक है, उसे किस अधिकतम राजमार्ग गति तक सीमित किया जाता है (किसी अधिक प्रतिबंधात्मक कारक की अनुपस्थिति में)?","options":["45 mph","55 mph","35 mph","25 mph"],"explanation":"अलास्का का Oversize/Overweight Permit Manual (Section 9.3.1) 17 feet की ऊंचाई से अधिक लोड को अधिकतम राजमार्ग गति 45 mph तक सीमित करता है जब तक कि अन्य कारक अधिक प्रतिबंधात्मक न हों।"},"78":{"q":"अलास्का के एक drawbridge पर जहाँ यातायात को नियंत्रित करने वाली कोई सिग्नल लाइट या परिचारक (attendant) न हो, वहाँ CDL चालक को कहाँ रुकना चाहिए?","options":["पुल के draw से कम से कम 50 feet पहले","पुल के draw से कम से कम 15 feet पहले","पुल के draw से कम से कम 100 feet पहले","सीधे draw के किनारे पर"],"explanation":"Alaska CDL Manual (Section 4.3.6) के अनुसार ऐसे drawbridge से जिसमें कोई सिग्नल लाइट या यातायात-नियंत्रण परिचारक न हो, उसके draw से कम से कम 50 feet पहले रुकना और पार करने से पहले यह सत्यापित करना आवश्यक है कि draw पूरी तरह बंद है।"},"79":{"q":"कौन सी अलास्का राज्य एजेंसी वाणिज्यिक चालक लाइसेंस (CDLs) जारी करती है?","options":["Alaska Division of Motor Vehicles (DMV)","Alaska Department of Public Safety","Federal Motor Carrier Safety Administration (FMCSA)","Alaska Department of Transportation and Public Facilities (DOT&PF)"],"explanation":"अलास्का में, Division of Motor Vehicles (DMV) राज्य चालक लाइसेंसिंग एजेंसी है जो CDLs जारी करती है और ज्ञान एवं कौशल परीक्षण आयोजित करती है। FMCSA संघीय CDL मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता। स्रोत: Alaska DMV, Commercial Driver's License (CDL) पेज।"},"80":{"q":"प्रत्येक अलास्का CDL ज्ञान परीक्षण पास करने के लिए किसी आवेदक को न्यूनतम कितने अंक प्राप्त करने होंगे?","options":["70%","75%","80%","90%"],"explanation":"अलास्का प्रत्येक CDL ज्ञान परीक्षण (सामान्य ज्ञान और किसी भी एंडोर्समेंट परीक्षण) को पास करने के लिए कम से कम 80% का स्कोर आवश्यक करता है। स्रोत: Alaska DMV CDL Manual / Alaska DMV CDL आवश्यकताएं।"},"81":{"q":"अलास्का CDL कौशल परीक्षण तीन भागों में विभाजित है। कौन सा सेट तीनों को सही ढंग से सूचीबद्ध करता है?","options":["Pre-trip निरीक्षण, बुनियादी वाहन नियंत्रण, और on-road ड्राइविंग","दृष्टि जांच, लिखित ज्ञान, और on-road ड्राइविंग","Pre-trip निरीक्षण, air brake जांच, और parallel parking","Backing, coupling/uncoupling, और एक समयबद्ध maneuverability कोर्स"],"explanation":"अलास्का के CDL कौशल परीक्षण के तीन भाग होते हैं: pre-trip (वाहन) निरीक्षण परीक्षण, बुनियादी वाहन नियंत्रण कौशल परीक्षण, और on-road ड्राइविंग परीक्षण। स्रोत: Alaska DMV CDL Manual।"},"82":{"q":"अलास्का CDL on-road कौशल परीक्षण के लिए उपयोग किए जाने वाले वाहन की आपूर्ति के लिए कौन जिम्मेदार है?","options":["आवेदक को उस वर्ग और प्रकार का एक प्रतिनिधि वाहन उपलब्ध कराना होगा जिसे वह चलाने का इरादा रखता है","DMV सभी आवेदकों के लिए एक मानक परीक्षण वाहन प्रदान करता है","FMCSA Training Provider Registry एक वाहन आवंटित करता है","Alaska DOT&PF अपने मोटर पूल से एक वाहन उधार देता है"],"explanation":"आवेदक को उसी वर्ग और प्रकार का अपना प्रतिनिधि वाहन लाना होगा जिसे वह चलाने की योजना बना रहा है; DMV कार्यालय परीक्षण वाहन प्रदान नहीं करता। स्रोत: Alaska DMV CDL Manual / Alaska DMV CDL आवश्यकताएं।"},"83":{"q":"Commercial Learner's Permit (CLP) जारी होने के बाद, किसी अलास्का आवेदक को CDL कौशल (सड़क) परीक्षण देने से पहले कितने समय प्रतीक्षा करनी चाहिए?","options":["कम से कम 14 days","कम से कम 7 days","कम से कम 30 days","कोई प्रतीक्षा अवधि नहीं है"],"explanation":"अलास्का उस संघीय नियम का पालन करता है जिसके अनुसार CLP धारक को CDL के लिए कोई भी सड़क परीक्षण देने से पहले CLP जारी होने के बाद कम से कम 14 days प्रतीक्षा करनी होती है। स्रोत: Alaska DMV CLP पेज (49 CFR 383.25)।"},"84":{"q":"अलास्का Commercial Learner's Permit (CLP) को नवीनीकृत करने से पहले कितने समय तक वैध रहता है?","options":["180 days","30 days","1 year","5 years"],"explanation":"एक अलास्का CLP 180 days के लिए वैध होता है और सामान्य ज्ञान परीक्षण दोबारा दिए बिना अतिरिक्त 180 days के लिए एक बार नवीनीकृत (पुनः जारी) किया जा सकता है। स्रोत: Alaska DMV CLP जानकारी (49 CFR 383.25)।"},"85":{"q":"अलास्का जिस संघीय मानक का पालन करता है उसके तहत एक अलास्का CLP को अतिरिक्त 180-day अवधि के लिए कितनी बार नवीनीकृत/पुनः जारी किया जा सकता है?","options":["एक बार","इसे बिल्कुल नवीनीकृत नहीं किया जा सकता","दो बार","असीमित बार"],"explanation":"एक CLP 180 days के लिए वैध होता है और इसे अतिरिक्त 180 days के लिए एक बार नवीनीकृत किया जा सकता है (कुल अधिकतम 360 days)। स्रोत: Alaska DMV CLP जानकारी (49 CFR 383.25)।"},"86":{"q":"किसी पहली बार के आवेदक के Class A या Class B लाइसेंस के लिए अलास्का CDL कौशल परीक्षण देने से पहले, कौन सा प्रशिक्षण पूरा किया जाना चाहिए?","options":["FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से Entry-Level Driver Training (ELDT)","Alaska Court System द्वारा अनुमोदित एक defensive-driving कोर्स","एक 40-घंटे का अलास्का शीतकालीन-ड्राइविंग प्रमाणन","Alaska Department of Labor के साथ पंजीकृत एक apprenticeship"],"explanation":"February 7, 2022 से, पहली बार के CDL आवेदकों को कौशल परीक्षण देने से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना होगा; राज्य को यह सत्यापित करना होगा कि रिकॉर्ड जमा किया गया था। स्रोत: FMCSA ELDT नियम (49 CFR Part 380), Alaska DMV द्वारा लागू।"},"87":{"q":"अलास्का में CDL स्व-प्रमाणन (self-certification) के लिए चालक को यह घोषित करना होता है कि वह किस प्रकार का संचालन करने की अपेक्षा करता है। स्व-प्रमाणन की कितनी श्रेणियाँ हैं?","options":["चार","दो","तीन","पांच"],"explanation":"चालकों को interstate/intrastate को excepted/non-excepted संचालन के साथ संयोजित करके बनाई गई चार श्रेणियों में से एक में स्व-प्रमाणित होना चाहिए। स्रोत: Alaska DMV CDL Self-Certification Requirement पेज।"},"88":{"q":"निम्नलिखित में से कौन सी चार अलास्का CDL स्व-प्रमाणन श्रेणियों में से एक है?","options":["Interstate non-excepted","Interstate seasonal","Intrastate hazardous-only","Federal exempt carrier"],"explanation":"चार श्रेणियाँ हैं interstate non-excepted, interstate excepted, intrastate non-excepted, और intrastate excepted। \"Interstate non-excepted\" उन चालकों के लिए श्रेणी है जिन्हें संघीय DOT चिकित्सा-कार्ड आवश्यकताओं को पूरा करना होगा। स्रोत: Alaska DMV CDL Self-Certification Requirement पेज।"},"89":{"q":"एक अलास्का चालक जो \"non-excepted\" (interstate या intrastate) के रूप में स्व-प्रमाणित होता है, उसे DMV को कौन सा दस्तावेज़ प्रदान करना होगा?","options":["एक वैध DOT medical examiner's certificate (medical card)","एक notarized नियोक्ता प्रायोजन पत्र","संघीय चिकित्सा मानकों का एक हस्ताक्षरित waiver","एक अलास्का वाणिज्यिक वाहन निरीक्षण स्टिकर"],"explanation":"Non-excepted चालकों को CDL विशेषाधिकार बनाए रखने के लिए एक वैध DOT medical examiner's certificate (medical card) रखना और जमा करना होगा; excepted चालकों को इसे जमा करने की आवश्यकता नहीं है। स्रोत: Alaska DMV CDL Self-Certification Requirement पेज।"},"90":{"q":"एक अलास्का CDL धारक अपना स्व-प्रमाणन और DOT medical examiner's certificate DMV को कैसे जमा कर सकता है?","options":["Form 413 पूरा करें और medical card की एक सुपाठ्य प्रति DMV के CDL ईमेल पते पर प्रस्तुत करें या ईमेल करें","कार्ड को केवल FMCSA Training Provider Registry पर अपलोड करें","मूल कार्ड को सीधे Washington, D.C. में FMCSA को मेल करें","इसे Alaska Department of Labor and Workforce Development के साथ दाखिल करें"],"explanation":"चालक प्रत्येक आवेदन के साथ स्व-प्रमाणन (Form 413) पूरा करते हैं और medical card को DMV कार्यालय में प्रस्तुत करते हैं या एक सुपाठ्य प्रति DMV के CDL पते (doa.dmv.cdl@alaska.gov) पर ईमेल करते हैं। स्रोत: Alaska DMV CDL Self-Certification Requirement पेज।"},"91":{"q":"अलास्का में इसका क्या परिणाम होता है यदि कोई non-excepted CDL धारक DMV के पास एक वर्तमान DOT medical examiner's certificate बनाए रखने में विफल रहता है?","options":["CDL विशेषाधिकार downgrade या रद्द कर दिए जाते हैं","एक बार $500 का संघीय जुर्माना लगाया जाता है लेकिन CDL वैध रहता है","कुछ नहीं, क्योंकि medical card केवल नियोक्ता के पास दाखिल होता है","चालक को स्वतः ही एक excepted intrastate चालक के रूप में पुनर्वर्गीकृत कर दिया जाता है"],"explanation":"यदि किसी non-excepted चालक का चिकित्सा प्रमाणन समाप्त हो जाता है, तो Alaska DMV CDL विशेषाधिकार रद्द या downgrade कर देता है; इसके बाद CMV चलाना उचित विशेषाधिकार के बिना ड्राइविंग है। स्रोत: Alaska DMV CDL Self-Certification Requirement पेज।"},"92":{"q":"अलास्का CDL को नवीनीकृत करने से पहले कितने समय तक वैध रहता है?","options":["5 years","4 years","8 years","2 years"],"explanation":"एक अलास्का CDL 5 years के लिए वैध होता है और धारक के जन्मदिन पर समाप्त हो जाता है। स्रोत: Alaska DMV नवीनीकरण जानकारी।"},"93":{"q":"एक अलास्का CDL आमतौर पर अपने नवीनीकरण वर्ष में किस तारीख को समाप्त होता है?","options":["धारक के जन्मदिन पर","December 31 को","जन्मदिन की परवाह किए बिना जारी करने की तारीख से ठीक पांच साल बाद","जारी करने वाले महीने के अंतिम दिन"],"explanation":"अलास्का चालक लाइसेंस, जिसमें CDLs शामिल हैं, 5 years के लिए जारी किए जाते हैं और धारक के जन्मदिन पर समाप्त होते हैं। स्रोत: Alaska DMV नवीनीकरण जानकारी।"},"94":{"q":"एक अलास्का CDL धारक समाप्ति से कितना पहले नवीनीकरण प्रक्रिया शुरू कर सकता है?","options":["समाप्ति से 1 year पहले तक","समाप्ति से 30 days पहले तक","केवल समाप्ति की तारीख पर","समाप्ति के 6 months बाद तक"],"explanation":"अलास्का CDL नवीनीकरण को लाइसेंस समाप्त होने से एक साल पहले तक शुरू करने की अनुमति देता है; राज्य पहले से समाप्त हो चुके लाइसेंस के लिए कोई छूट अवधि (grace period) प्रदान नहीं करता। स्रोत: Alaska DMV नवीनीकरण जानकारी।"},"95":{"q":"एक मूल अलास्का CDL के लिए आवेदन करते समय कौन सा दस्तावेज़ समूह आवश्यक है?","options":["U.S. नागरिकता/कानूनी उपस्थिति का प्रमाण, एक अलास्का निवास/अधिवास (domicile) पता, एक Social Security Number, और लागू होने पर एक DOT medical card","केवल एक वर्तमान आउट-ऑफ-स्टेट CDL और एक पासपोर्ट फोटो","एक वाहन शीर्षक (title), बीमा का प्रमाण, और एक अलास्का मछली पकड़ने का लाइसेंस","केवल एक FMCSA carrier नंबर और एक notarized हलफनामा"],"explanation":"अलास्का को नागरिकता/कानूनी उपस्थिति का प्रमाण, एक अलास्का निवास पते (अधिवास) का प्रमाण, एक Social Security Number, एक वर्तमान चालक लाइसेंस, और लागू होने पर एक DOT medical card की आवश्यकता होती है। स्रोत: Alaska DMV Commercial Driver's License (CDL) पेज।"},"96":{"q":"intrastate (अलास्का-के-भीतर) संचालन तक सीमित अलास्का CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 years old","16 years old","21 years old","25 years old"],"explanation":"अलास्का CDL के लिए न्यूनतम आयु intrastate संचालन के लिए 18 है; interstate संचालन, hazmat, और स्कूल बस एंडोर्समेंट के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Alaska DMV CDL / CLP पेज।"},"97":{"q":"एक चालक जो interstate वाणिज्य में संचालन करना चाहता है या खतरनाक सामग्री ले जाना चाहता है, उस संचालन के लिए अलास्का CDL रखने हेतु कम से कम किस आयु का होना चाहिए?","options":["21 years old","18 years old","19 years old","25 years old"],"explanation":"अलास्का के अनुसार interstate संचालन करने या hazmat या स्कूल बस एंडोर्समेंट रखने के लिए चालक को कम से कम 21 वर्ष का होना चाहिए, जबकि केवल-intrastate CDLs 18 वर्ष की आयु पर उपलब्ध हैं। स्रोत: Alaska DMV CDL / CLP पेज।"},"98":{"q":"अलास्का CDL आवेदन शुल्क के संबंध में, प्रक्रिया कैसे काम करती है इसके बारे में कौन सा कथन सटीक है?","options":["लागू CDL और road-test शुल्क आवेदन के समय DMV को भुगतान किए जाते हैं, और सटीक राशियाँ राज्य द्वारा निर्धारित की जाती हैं तथा समय के साथ बदल सकती हैं","अलास्का एक मूल CDL के लिए कोई शुल्क नहीं लेता","सभी CDL शुल्क सीधे FMCSA को भुगतान किए जाते हैं, DMV को नहीं","यदि आवेदक असफल हो जाता है तो road-test शुल्क पूरी तरह वापसी योग्य है"],"explanation":"अलास्का CDL आवेदक आवेदन के समय लागू लाइसेंस और road-test शुल्क DMV को भुगतान करते हैं; विशिष्ट डॉलर राशियाँ राज्य द्वारा निर्धारित की जाती हैं और परिवर्तन के अधीन हैं, इसलिए प्रक्रिया (किसी निश्चित राशि के बजाय) ही विश्वसनीय बिंदु है। स्रोत: Alaska DMV CDL पेज / शुल्क अनुसूची।"}},"ar":{"0":{"q":"في ألاسكا، ما هو الحد الأقصى القانوني لعرض المركبة، بما في ذلك حمولتها، على شبكة الطرق السريعة للولاية؟","options":["102 inches","96 inches","108 inches","114 inches"],"explanation":"تحدد ألاسكا الحد الأقصى لعرض المركبة، بما في ذلك الحمولة، بـ 102 inches؛ ويجوز أن تمتد المعدات المثبتة بما لا يزيد عن 3 inches خارج ذلك على كل جانب. المصدر: 17 AAC 25.012(a) (Alaska DOT&PF، الفصل 25 العمليات، المركبات ذات العجلات)، بما يتوافق مع دليل CDL لألاسكا."},"1":{"q":"ما هو الحد الأقصى القانوني العام لارتفاع المركبة والحمولة على معظم الطرق السريعة في ألاسكا؟","options":["15 feet","13 feet 6 inches","14 feet","16 feet"],"explanation":"بموجب 17 AAC 25.012(b)، لا يجوز أن يتجاوز ارتفاع المركبة في ألاسكا بما في ذلك الحمولة 15 feet، باستثناء ممر طريق Dalton/Elliott بين محطة وزن Fox ومنطقة Prudhoe Bay، حيث يُسمح بـ 17 feet. المصدر: 17 AAC 25.012(b)، Alaska DOT&PF."},"2":{"q":"على طريقي Dalton وElliott السريعين بين محطة وزن Fox ومنطقة Prudhoe Bay، ما هو الارتفاع المتزايد المسموح به للمركبة والحمولة؟","options":["15 feet 6 inches","16 feet","17 feet","18 feet"],"explanation":"تسمح 17 AAC 25.012(b) بارتفاع، بما في ذلك الحمولة، قدره 17 feet للمركبة التي تعمل بين محطة وزن Fox ومنطقة Prudhoe Bay على طريقي Dalton وElliott السريعين، مقابل الحد العام البالغ 15-foot. المصدر: 17 AAC 25.012(b)، Alaska DOT&PF."},"3":{"q":"على مسارات نظام الطرق السريعة الوطني National Highway System في ألاسكا، ما هو الحد الأقصى لطول مركبة القوة المفردة (الشاحنة أو رأس القاطرة نفسها)؟","options":["40 feet","48 feet","53 feet","45 feet"],"explanation":"تحدد 17 AAC 25.012(c)(1) طول مركبة القوة بـ 45 feet على مسارات NHS (وتحدد 17 AAC 25.012(d)(1) نفس الحد البالغ 45-foot على باقي شبكة الطرق السريعة للولاية). المصدر: 17 AAC 25.012، Alaska DOT&PF."},"4":{"q":"في ألاسكا، ما هو الحد الأقصى لطول حمل البضائع لمقطورة نصفية أو مقطورة تُستخدم في تركيبة؟","options":["48 feet","57 feet","60 feet","53 feet"],"explanation":"تحدد 17 AAC 25.012(c)(3) و(e)(1) سقف طول حمل البضائع لمقطورة نصفية أو مقطورة بـ 53 feet على جميع المسارات. المصدر: 17 AAC 25.012، Alaska DOT&PF."},"5":{"q":"ما هو الحد الأقصى للطول الإجمالي لتركيبة قياسية تتكون من شاحنة ومركبة واحدة حاملة للبضائع، أو رأس قاطرة ومركبتين حاملتين للبضائع، على الطرق السريعة في ألاسكا؟","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"تحدد 17 AAC 25.012(c)(4) و(d)(3) هذه التركيبات بطول إجمالي قدره 75 feet؛ أما رأس القاطرة مع مركبة واحدة حاملة للبضائع فلا يخضع لحد طول إجمالي. المصدر: 17 AAC 25.012، Alaska DOT&PF."},"6":{"q":"في ألاسكا، إلى أي مدى يجوز أن تمتد الحمولة أو المعدات خارج المصد الأمامي للمركبة قبل أن تتجاوز الحد القانوني؟","options":["3 feet","4 feet","5 feet","6 feet"],"explanation":"تسمح 17 AAC 25.012(c)(6) و(d)(4) بأن تبرز الحمولة أو المعدات بما لا يزيد عن 3 feet خارج المصد الأمامي (وبما لا يزيد عن 4 feet خارج المؤخرة). المصدر: 17 AAC 25.012، Alaska DOT&PF."},"7":{"q":"في ألاسكا، إلى أي مدى يجوز أن تمتد الحمولة خارج مؤخرة المركبة قبل أن تتجاوز الحد القانوني؟","options":["3 feet","5 feet","6 feet","4 feet"],"explanation":"تسمح 17 AAC 25.012(c)(6)(B) و(d)(4)(B) ببروز خلفي لا يزيد عن 4 feet (يقتصر البروز الأمامي على 3 feet). المصدر: 17 AAC 25.012، Alaska DOT&PF."},"8":{"q":"ما هو الحد الأقصى القانوني للوزن المسموح به على محور مفرد في ألاسكا؟","options":["18,000 pounds","22,400 pounds","34,000 pounds","20,000 pounds"],"explanation":"تحدد 17 AAC 25.013(a)(4) حد وزن المحور المفرد بـ 20,000 pounds، مع تباعد أدنى قدره 8'1\" لكي يُحتسب المحور كمحور مفرد. المصدر: 17 AAC 25.013، Alaska DOT&PF."},"9":{"q":"بموجب جدول مجموعة المحاور في ألاسكا، ما هو الحد الأقصى للوزن المسموح به على مجموعة محورين (محور ترادفي tandem)؟","options":["34,000 pounds","36,000 pounds","38,000 pounds","40,000 pounds"],"explanation":"يسمح جدول أوزان مجموعة المحاور في ألاسكا في 17 AAC 25.013(a)(4) بـ 38,000 pounds على مجموعة محورين (ترادفي)، وهو أعلى من المعيار الفيدرالي الترادفي البالغ 34,000-pound المستخدم في كثير من الولايات. المصدر: 17 AAC 25.013، Alaska DOT&PF."},"10":{"q":"بموجب جدول أوزان مجموعة المحاور في ألاسكا، ما هو الحد الأقصى للوزن المسموح به على مجموعة من ثلاثة محاور؟","options":["38,000 pounds","46,000 pounds","50,000 pounds","42,000 pounds"],"explanation":"تسمح 17 AAC 25.013(a)(4) بـ 42,000 pounds على مجموعة من ثلاثة محاور (مع تباعد أدنى بين المحاور قدره 3'6\"). المصدر: 17 AAC 25.013، Alaska DOT&PF."},"11":{"q":"ما هو الحد الأدنى للتباعد بين المحاور الذي يجب الحفاظ عليه لكي يُعامَل المحور باعتباره 'محوراً مفرداً' وليس جزءاً من مجموعة محاور في ألاسكا؟","options":["8 feet 1 inch","3 feet 6 inches","6 feet","10 feet"],"explanation":"وفقاً للملاحظة المرفقة بـ 17 AAC 25.013(a)(4)، يُعتبر أي محور يبعد أقل من 8 feet 1 inch عن محور آخر (من المركز إلى المركز) جزءاً من مجموعة محاور؛ ويُطبَّق حد المحور المفرد عند تباعد أدنى قدره 8'1\". المصدر: 17 AAC 25.013، Alaska DOT&PF."},"12":{"q":"كيف تحدد ألاسكا الحد الأقصى للوزن الإجمالي للمركبة بالنسبة لتركيبة طويلة؟","options":["سقف ثابت قدره 80,000-pound على جميع الطرق السريعة","بضرب عدد المحاور في 20,000 pounds","بتطبيق صيغة الوزن الإجمالي للجسر Bridge Gross Weight Formula الخاصة بالولاية بناءً على عدد المحاور والتباعد","بحد ثابت قدره 105,500-pound محدد بموجب القانون"],"explanation":"تحدد 17 AAC 25.013(a)(6) الحد الأقصى للوزن الإجمالي بواسطة صيغة الوزن الإجمالي للجسر W = 500[LN/(N-1) + 12N + 36] (مع إضافة +3,000 عند عدم وجود محاور رافعة في مجموعة الدفع)، وليس بسقف ثابت قدره 80,000-pound. المصدر: 17 AAC 25.013، Alaska DOT&PF."},"13":{"q":"في صيغة الوزن الإجمالي للجسر في ألاسكا W = 500[LN/(N-1) + 12N + 36]، ماذا يمثل المتغير 'L'؟","options":["وزن الحمولة القانوني بالأطنان","المسافة بالأقدام بين مراكز المحورين الطرفيين","طول أطول مقطورة","سعة المحور الرافع"],"explanation":"في 17 AAC 25.013(a)(6)، 'L' هي المسافة بالأقدام الكاملة المقاسة بين مراكز المحورين الطرفيين للمركبة أو التركيبة، و'N' هو عدد المحاور. المصدر: 17 AAC 25.013، Alaska DOT&PF."},"14":{"q":"ما هو الحد الأقصى للوزن المسموح به على الإطار في ألاسكا، بناءً على العرض الاسمي للإطار حسب الشركة المصنّعة؟","options":["600 pounds لكل بوصة من عرض الإطار","500 pounds لكل بوصة من عرض الإطار","550 pounds لكل بوصة من عرض الإطار","650 pounds لكل بوصة من عرض الإطار"],"explanation":"تحدد 17 AAC 25.013(a)(1) وزن الإطار بـ 600 pounds لكل بوصة طولية من عرض الإطار، بناءً على تصنيف الشركة المصنّعة للإطار للعرض الاسمي للإطار. المصدر: 17 AAC 25.013، Alaska DOT&PF."},"15":{"q":"متى يُطلب تصريح الحجم/الوزن الزائد من Alaska DOT&PF؟","options":["فقط للحمولات التي يزيد وزنها الإجمالي عن 100,000 pounds","عندما تتجاوز المركبة أو الحمولة الأبعاد أو الأوزان القصوى الواردة في 17 AAC 25 وستسير على طريق عام","فقط عند عبور حدود الولاية إلى كندا","فقط للمركبات التي يزيد عرضها عن 12 feet"],"explanation":"وفقاً لدليل التصاريح الإداري (القسم 2.2.1) و17 AAC 25.320، يُطلب تصريح كلما تجاوزت المركبة أو المركبة مع الحمولة الأبعاد أو الأوزان القصوى الواردة في 17 AAC 25 وطلبت السير على طريق عام. المصدر: دليل التصاريح الإداري لـ Alaska DOT&PF؛ 17 AAC 25.320."},"16":{"q":"تُصدر ألاسكا تصاريح الحجم/الوزن الزائد فقط للحمولات التي تكون أيٌّ مما يلي؟","options":["حمولات قابلة للتقسيم يمكن تقسيمها إلى أجزاء قانونية","حمولات غير قابلة للتقسيم لا يمكن تقليصها إلى الحجم أو الوزن القانوني","حمولات مملوكة لجهات حكومية","حمولات تحمل مواد خطرة"],"explanation":"تُصدر تصاريح ألاسكا للحمولات غير القابلة للتقسيم (تلك التي لا يمكن عملياً تقليصها إلى الأبعاد/الوزن القانوني)؛ أما الحمولات القابلة للتقسيم فيجب تجزئتها إلى الحدود القانونية. المصدر: دليل التصاريح الإداري لـ Alaska DOT&PF القسم 2.2 و17 AAC 25.320(a)(1)."},"17":{"q":"في ألاسكا، ما هي مدة الصلاحية القياسية لتصريح الحجم/الوزن الزائد لرحلة واحدة (لنقلة تبلغ 400 miles أو أقل في اتجاه واحد)؟","options":["1 day","3 days","7 days","30 days"],"explanation":"وفقاً لدليل التصاريح الإداري القسم 3.2.1، يكون تصريح الرحلة الواحدة صالحاً لمدة 3 days (تُمدَّد إلى 5 days إذا كانت المسافة تزيد عن 400 miles في اتجاه واحد). المصدر: دليل التصاريح الإداري لـ Alaska DOT&PF."},"18":{"q":"خلال أشهر الشتاء في ألاسكا، ما هو السماح الإضافي بالوزن الإجمالي الذي قد يُمنح لتراكم الثلج والجليد الموثّق على المركبة؟","options":["500 pounds","1,000 pounds","1,500 pounds","2,000 pounds"],"explanation":"تمنح 17 AAC 25.335(b)(1) سماحاً إضافياً قدره 1,500-pound من 1 أكتوبر حتى 30 أبريل عند وجود دليل على تراكم الثلج والجليد؛ وهذا هو الحد الأقصى بغض النظر عن نوع التركيبة. المصدر: 17 AAC 25.335، Alaska DOT&PF."},"19":{"q":"أي فئة من CDL تشترطها ألاسكا لتشغيل مركبة مفردة بتصنيف وزن إجمالي للمركبة (GVWR) قدره 26,001 pounds أو أكثر، مثل شاحنة قلابة أو حافلة ركاب؟","options":["Class A","Class B","Class C","Class D"],"explanation":"يُعرّف دليل CDL لألاسكا Class B بأنها أي مركبة مفردة بتصنيف GVWR يزيد عن 26,001 pounds، أو مثل هذه المركبة وهي تقطر وحدة لا يبلغ وزنها 10,000 lbs أو أكثر (شاحنات قلابة، خلاطات إسمنت، شاحنات صندوقية، حافلات ركاب). المصدر: دليل CDL لـ Alaska DMV، القسم 1، تصنيفات المركبات."},"20":{"q":"وفقاً لدليل CDL لألاسكا، تُطلب رخصة Class A CDL لأي تركيبة مركبات بتصنيف GCWR قدره 26,001 lbs أو أكثر، شريطة أن يتجاوز تصنيف GVWR للوحدة (الوحدات) المقطورة أي وزن؟","options":["8,000 pounds","10,000 pounds","16,000 pounds","26,001 pounds"],"explanation":"تُعرّف ألاسكا Class A بأنها تركيبة بتصنيف GCWR قدره 26,001+ lbs حيث يزيد تصنيف GVWR للمركبة (المركبات) المقطورة عن 10,000 pounds (مثل شاحنات الـ 18 عجلة، وشاحنات نقل الأخشاب). المصدر: دليل CDL لـ Alaska DMV، القسم 1، تعريف Class A."},"21":{"q":"بموجب قواعد ألاسكا، تظل المركبة التي يقل تصنيف GVWR لها عن 26,001 lbs ضمن برنامج CDL (Class C) إذا كانت مصممة لنقل كم عدد من الركاب، بما في ذلك السائق؟","options":["8 أو أكثر","11 أو أكثر","15 أو أكثر","16 أو أكثر"],"explanation":"يُدرج دليل CDL لألاسكا مركبة أصغر ضمن برنامج CDL باعتبارها Class C إذا كانت مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق، أو تنقل مواد خطرة تستلزم لافتات. المصدر: دليل CDL لـ Alaska DMV، القسم 1، تعريف Class C."},"22":{"q":"في ألاسكا، أي حرف تظهير يوضع على رخصة CDL لنقل المواد الخطرة بكميات تستلزم لافتات؟","options":["التظهير H","التظهير N","التظهير X","التظهير T"],"explanation":"تستخدم ألاسكا التظهير H (المواد الخطرة HazMat) لأي مركبة تُستخدم لنقل مواد خطرة بكميات تستلزم لافتات. المصدر: دليل CDL لـ Alaska DMV، القسم 1، جدول التظهيرات."},"23":{"q":"أي تظهير تشترطه ألاسكا لأي مركبة مخصصة لنقل السوائل بالجملة (شاحنات الصهاريج)؟","options":["التظهير H","التظهير N","التظهير P","التظهير T"],"explanation":"يُدرج دليل CDL لألاسكا التظهير N (الصهريج Tanker) لأي مركبة مخصصة لنقل السوائل بالجملة. لاحظ أن حرف رمز ألاسكا لتظهير الصهريج هو N. المصدر: دليل CDL لـ Alaska DMV، القسم 1، جدول التظهيرات."},"24":{"q":"أي تظهير CDL في ألاسكا مطلوب لقطر مقطورات مزدوجة أو ثلاثية؟","options":["التظهير N","التظهير P","التظهير T","التظهير X"],"explanation":"تخصص ألاسكا التظهير T (المقطورات المزدوجة أو الثلاثية) للتركيبات التي تقطر مقطورتين أو ثلاث مقطورات؛ ويُطلب اختبار معرفي فقط. المصدر: دليل CDL لـ Alaska DMV، القسم 1، جدول التظهيرات."},"25":{"q":"وفقاً لدليل CDL لألاسكا، أي تظهير مطلوب لمركبة مصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق)؟","options":["التظهير S","التظهير P","التظهير N","التظهير H"],"explanation":"تشترط ألاسكا التظهير P (الركاب Passenger) لأي مركبة مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق، بغض النظر عن العدد المنقول فعلياً. ويتطلب اختباراً معرفياً واختبار مهارات على الطريق. المصدر: دليل CDL لـ Alaska DMV، القسم 1، جدول التظهيرات."},"26":{"q":"في ألاسكا، ماذا يمثل التظهير X على رخصة CDL من تركيبة؟","options":["جمع بين الصهريج والمواد الخطرة","جمع بين الركاب والحافلة المدرسية","جمع بين المقطورات المزدوجة والثلاثية","جمع بين الفرامل الهوائية والصهريج"],"explanation":"تستخدم ألاسكا التظهير X لعملية مشتركة بين الصهريج/المواد الخطرة: أي مركبة صهريجية تُستخدم لنقل كميات من المواد الخطرة تستلزم لافتات. ويتطلب اختباراً معرفياً والتحقق من الخلفية. المصدر: دليل CDL لـ Alaska DMV، القسم 1، جدول التظهيرات."},"27":{"q":"قبل أن تُصدر ألاسكا رخصة CDL بتظهير المواد الخطرة (H) أو تجددها، يجب على المتقدم أولاً إكمال أي خطوة؟","options":["دورة قيادة دفاعية","التحقق من الخلفية لدى إدارة أمن النقل Transportation Security Administration","فترة انتظار قدرها 30 يوماً","دورة فحص المركبات التجارية"],"explanation":"ينص دليل CDL لألاسكا على أن جميع المتقدمين للحصول على تظهير HazMat أو إضافته أو تجديده يجب أن يجتازوا التحقق من الخلفية قبل الإصدار، ويُعالَج عبر TSA/universalenroll.dhs.gov. المصدر: دليل CDL لـ Alaska DMV، القسم 1، ملاحظات التظهير H."},"28":{"q":"ما هو الحد الأدنى للسن لإصدار رخصة CDL في ألاسكا مقيدة بالتجارة داخل الولاية (داخل الولاية فقط)؟","options":["16 years","17 years","18 years","21 years"],"explanation":"ينص دليل CDL لألاسكا على أنه يجب أن يكون عمر المتقدم 18 years على الأقل للعمل في التجارة داخل الولاية (سارٍ اعتباراً من 11/14/19) وقت التقديم، وأن يكون قد حمل رخصة قيادة سارية لمدة سنة واحدة على الأقل. المصدر: دليل CDL لـ Alaska DMV، القسم 1، متطلبات السن."},"29":{"q":"ما هو الحد الأدنى للسن الذي تشترطه ألاسكا لحامل رخصة CDL للعمل في التجارة بين الولايات؟","options":["18 years","19 years","20 years","21 years"],"explanation":"ينص دليل CDL لألاسكا على أنه يجب أن يكون عمر المتقدم 21 years على الأقل للعمل في التجارة بين الولايات. ويحصل السائقون دون 21 على قيد K (داخل الولاية فقط). المصدر: دليل CDL لـ Alaska DMV، القسم 1، متطلبات السن والقيد K."},"30":{"q":"بموجب القاعدة الفيدرالية وممارسة ألاسكا على حد سواء، كم يجب أن يحمل المتقدم تصريح المتعلم التجاري (CLP) قبل إجراء اختبار مهارات الطريق لـ CDL؟","options":["7 days على الأقل","10 days على الأقل","14 days على الأقل","30 days على الأقل"],"explanation":"ينص دليل CDL لألاسكا على أنه يجب أن يحمل المتقدم رخصة CLP لمدة 14 days على الأقل قبل إجراء اختبار مهارات الطريق، بما في ذلك عند ترقية الفئة أو إضافة تظهير يتطلب اختبار مهارات. المصدر: دليل CDL لـ Alaska DMV، القسم 1، متطلبات الاختبار والإصدار."},"31":{"q":"قبل الحصول على تصريح المتعلم التجاري CLP في ألاسكا، ماذا يجب أن يحمل المتقدم بالفعل؟","options":["رخصة قيادة غير تجارية سارية حالية من ألاسكا","رقم سلطة تشغيل فيدرالي من DOT","شهادة تدريب مهني مكتملة","رخصة CDL سابقة من ولاية أخرى"],"explanation":"تشترط صفحة CLP الخاصة بـ Alaska DMV أن يكون لدى المتقدمين رخصة قيادة غير تجارية سارية حالية من ألاسكا قبل إصدار رخصة CLP. المصدر: صفحة تصريح المتعلم التجاري (CLP) لـ Alaska DMV."},"32":{"q":"أثناء القيادة برخصة CLP في ألاسكا، يجب على السائق المرخّص المرافق الجالس في المقعد المجاور لحامل التصريح أن يحمل الفئة/التظهيرات المناسبة وأن يكون عمره على الأقل كم؟","options":["18 years","19 years","21 years","25 years"],"explanation":"وفقاً لصفحة CLP الخاصة بـ Alaska DMV، يجوز لحامل CLP تشغيل مركبة من فئته أو أصغر فقط، مع وجود سائق مرخّص ساري المفعول في المقعد المجاور لا يقل عمره عن 21، ويحمل الفئة والتظهيرات المناسبة، وقد كان مرخّصاً لمدة سنة واحدة. المصدر: صفحة تصريح المتعلم التجاري (CLP) لـ Alaska DMV."},"33":{"q":"حامل CLP في ألاسكا الذي لديه تظهير الركاب (P) يخضع لأي قيد؟","options":["يجوز له قيادة حافلات ركاب فارغة فقط على ملكية خاصة","لا يجوز له نقل أي ركاب في حافلة CMV باستثناء فاحصين متخصصين ومتدربين وحامل CDL المرافق المحددين","يجوز له نقل ما يصل إلى 8 ركاب أثناء ساعات النهار","يجوز له نقل الركاب فقط على المسارات داخل الولاية"],"explanation":"ينص قيد P في دليل CDL لألاسكا على أنه يُحظر على حامل CLP الذي لديه تظهير P نقل الركاب في حافلة CMV، باستثناء المدققين الفيدراليين/الولائيين، والمفتشين، وفاحصي الاختبارات، والمتدربين الآخرين، وحامل CDL المرافق (بموجب 49 CFR 383.25). المصدر: دليل CDL لـ Alaska DMV، القيد P."},"34":{"q":"حامل CLP في ألاسكا الذي لديه تظهير N (الصهريج) يكون مقيداً بالقيد X بتشغيل المركبات الصهريجية في أي حالة؟","options":["المركبات الصهريجية الفارغة فقط، وليس تلك التي بها بقايا مواد خطرة غير منظّفة","المركبات الصهريجية التي تقل سعتها عن 1,000 gallons فقط","المركبات الصهريجية أحادية المحور فقط","المركبات الصهريجية على الطرق الخاصة فقط"],"explanation":"ينص قيد X في دليل CDL لألاسكا على أنه يجوز لحامل التصريح الذي لديه تظهير N تشغيل مركبة صهريجية فارغة فقط، ويُحظر عليه تشغيل أي مركبة صهريجية كانت تحتوي سابقاً على مواد خطرة ولم تُنظَّف من البقايا. المصدر: دليل CDL لـ Alaska DMV، القيد X."},"35":{"q":"اعتباراً من 1 يناير 2012، يجب على جميع سائقي CDL في ألاسكا أن يقدموا إقراراً ذاتياً بأحد كم نوع من تشغيل CMV؟","options":["اثنان","ثلاثة","أربعة","خمسة"],"explanation":"يدرج دليل CDL لألاسكا أربع فئات للإقرار الذاتي: التجارة بين الولايات غير المستثناة، والتجارة بين الولايات المستثناة، والتجارة داخل الولاية غير المستثناة، والتجارة داخل الولاية المستثناة. المصدر: دليل CDL لـ Alaska DMV، متطلبات الشهادة الطبية والإقرار الذاتي (49 CFR 383.71)."},"36":{"q":"إذا انتهت صلاحية شهادة الفاحص الطبي المسجلة لحامل رخصة CDL في ألاسكا، فكم من الوقت أمام الولاية قبل أن يجب عليها خفض درجة رخصة CDL؟","options":["خلال 15 days من انتهاء الصلاحية","خلال 30 days من انتهاء الصلاحية","خلال 60 days من انتهاء الصلاحية","خلال 90 days من انتهاء الصلاحية"],"explanation":"ينص دليل CDL لألاسكا على أنه، اعتباراً من 1 يناير 2012، يُطلب من الولاية خفض درجة أي حامل رخصة CDL لديه شهادة طبية منتهية الصلاحية مسجلة خلال 60 days من انتهاء الصلاحية. المصدر: دليل CDL لـ Alaska DMV، متطلبات الشهادة الطبية والإقرار الذاتي."},"37":{"q":"بموجب قاعدة ELDT الفيدرالية المطبَّقة في ألاسكا، يجب على المتقدم لأول مرة إكمال تدريب السائقين المبتدئين Entry-Level Driver Training من مزوّد مُدرج أين قبل إجراء اختبار المهارات؟","options":["قاعدة بيانات التدريب الداخلية لـ Alaska DMV","سجل مزوّدي التدريب لدى FMCSA","قائمة مجلس التدريب المهني للولاية","سجل السائقين الوطني CDLIS"],"explanation":"تشترط ألاسكا ELDT للمتقدمين لأول مرة للفئتين Class A أو B، والترقيات، والتظهيرات الجديدة H/P/S؛ ويجب أن يأتي التدريب من مزوّد مُدرج في سجل مزوّدي التدريب لدى FMCSA، الذي ينقل إتمام التدريب إلى DMV قبل اختبار المهارات. المصدر: صفحة تدريب السائقين المبتدئين (ELDT) لـ Alaska DMV."},"38":{"q":"وفقاً لقانون/لائحة ألاسكا (2 AAC 90.420)، أي مستند مطلوب تحديداً للحصول على رخصة CDL إلى جانب مستندات الميلاد والهوية لأي شخص لم يسبق له الترخيص في ألاسكا؟","options":["رقم الضمان الاجتماعي Social Security","بطاقة جواز السفر","بطاقة تسجيل الناخبين","سند ملكية المركبة"],"explanation":"يستشهد دليل CDL لألاسكا بـ 2 AAC 90.420(a): يُطلب رقم الضمان الاجتماعي Social Security للحصول على رخصة CDL، إلى جانب مستندات الميلاد والهوية، للمتقدمين الذين لم يسبق لهم الترخيص في ألاسكا. كما يُطلب إثبات الإقامة في ألاسكا والوجود القانوني. المصدر: دليل CDL لـ Alaska DMV، متطلبات الاختبار والإصدار؛ 2 AAC 90.420."},"39":{"q":"في ألاسكا، عند أي تركيز للكحول في الدم (BAC) يكون من غير القانوني تشغيل مركبة تجارية آلية (CMV)؟","options":["0.04% أو أكثر","0.08% أو أكثر","0.02% أو أكثر","0.10% أو أكثر"],"explanation":"ينص القسم 1.3.2 من دليل CDL لألاسكا على أنه من غير القانوني تشغيل CMV إذا كان تركيز BAC لديك .04% أو أكثر، أي نصف الحد البالغ 0.08% للسائقين غير التجاريين. المصدر: دليل رخصة القيادة التجارية لـ Alaska DMV، القسم 1.3.2."},"40":{"q":"بموجب قانون الموافقة الضمنية في ألاسكا، ما الذي وافقت عليه بمجرد تشغيل مركبة CMV في الولاية؟","options":["الخضوع لفحص كيميائي لنفَسك للكشف عن الكحول","السماح بتفتيش حمولتك في أي وقت","دفع جميع غرامات المخالفات قبل مغادرة الموقع","حمل جهاز اختبار نفَس محمول في المقصورة"],"explanation":"ينص دليل CDL لألاسكا على أنك عند تشغيل CMV تكون قد وافقت بالفعل على فحص كيميائي لنفَسك، وأنك 'تُعتبر قد منحت موافقتك على فحص الكحول'. المصدر: دليل CDL لـ Alaska DMV، الموافقة الضمنية / القسم 1.3.2."},"41":{"q":"يرتكب حامل رخصة CDL في ألاسكا مخالفة كبرى أولى، مثل قيادة CMV بتركيز BAC قدره 0.04% أو أعلى. ما هو الحد الأدنى للإيقاف عن الأهلية؟","options":["1 year","60 days","6 months","3 years"],"explanation":"تُوقف ألاسكا السائق عن الأهلية لمدة 1 year على الأقل عن مخالفة كبرى أولى (القيادة تحت تأثير الكحول، الرفض، مغادرة الموقع، إلخ). المصدر: دليل CDL لـ Alaska DMV، القسمان 1.3.2 وجدول المخالفات الكبرى الموجبة للإيقاف (يطابق 49 CFR 383.51)."},"42":{"q":"إذا وقعت مخالفة كبرى أولى أثناء تشغيل السائق لمركبة CMV تحمل لافتة مواد خطرة، فكم مدة الإيقاف عن الأهلية في ألاسكا؟","options":["3 years","1 year","5 years","مدى الحياة"],"explanation":"تزيد ألاسكا مدة الإيقاف عن الأهلية للمخالفة الكبرى الأولى إلى 3 years على الأقل عندما تقع المخالفة في مركبة CMV تحمل لافتة مواد خطرة. المصدر: دليل CDL لـ Alaska DMV، القسم 1.3.2 / جدول المخالفات الكبرى الموجبة للإيقاف."},"43":{"q":"ما هو الإيقاف عن الأهلية في ألاسكا عن مخالفة كبرى ثانية (على سبيل المثال، قيادة ثانية تحت تأثير الكحول في CMV)؟","options":["مدى الحياة","10 years","3 years","5 years"],"explanation":"تُوقف ألاسكا السائق عن الأهلية مدى الحياة عن مخالفة كبرى ثانية. المصدر: دليل CDL لـ Alaska DMV، القسم 1.3.2 وجدول المخالفات الكبرى الموجبة للإيقاف (49 CFR 383.51)."},"44":{"q":"استخدام مركبة CMV لارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة يحمل أي إيقاف عن الأهلية في ألاسكا، حتى عند المخالفة الأولى؟","options":["مدى الحياة، دون إعادة تأهيل","1 year","3 years","10 years"],"explanation":"ينص دليل CDL لألاسكا على أنك ستفقد رخصة CDL مدى الحياة إذا استخدمت CMV لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة. المصدر: دليل CDL لـ Alaska DMV، القسم 1.3.2."},"45":{"q":"أي مما يلي مُدرج كمخالفة كبرى موجبة للإيقاف عن الأهلية في دليل CDL لألاسكا؟","options":["مغادرة موقع حادث يشمل مركبة CMV","اتباع مركبة أخرى عن قرب شديد","تجاوز السرعة بـ 15 mph أو أكثر فوق الحد","تغيير المسار بشكل غير سليم أو متقطع"],"explanation":"مغادرة موقع الحادث مخالفة كبرى (1 year / مدى الحياة). أما الثلاث الأخرى فهي مخالفات مرورية خطيرة، وليست مخالفات كبرى. المصدر: دليل CDL لـ Alaska DMV، القسمان 1.3.2 و1.3.3."},"46":{"q":"إذا رفضت الخضوع لفحص الكحول في ألاسكا، فماذا يحدث لرخصة CDL الخاصة بك عند رفض أول؟","options":["الإيقاف عن الأهلية لمدة 1 year على الأقل (3 years إذا كنت تنقل مواد خطرة)","الإيقاف عن الأهلية لمدة 90 days","تحذير فقط؛ دون إيقاف عن الأهلية","الإيقاف عن الأهلية مدى الحياة"],"explanation":"يُعامَل الرفض كمخالفة كبرى: إيقاف عن الأهلية لمدة 1 year على الأقل، أو 3 years إذا كنت تنقل مواد خطرة. المصدر: دليل CDL لـ Alaska DMV، الموافقة الضمنية والقسم 1.3.2."},"47":{"q":"وفقاً لحكم الموافقة الضمنية في دليل CDL لألاسكا، ما هو الحد الأدنى للإيقاف عن الأهلية عن رفض ثانٍ أو لاحق للخضوع لفحص كيميائي؟","options":["10 years","3 years","5 years","1 year"],"explanation":"ينص نص الموافقة الضمنية في دليل CDL لألاسكا على أن الرفض الثاني واللاحق يحمل حداً أدنى للإيقاف عن الأهلية قدره 10 years. المصدر: دليل CDL لـ Alaska DMV، حكم الموافقة الضمنية."},"48":{"q":"ماذا يحدث لسائق CMV في ألاسكا يُكتشف لديه أي كمية قابلة للكشف من الكحول دون 0.04%؟","options":["يُوضع خارج الخدمة لمدة 24 hours","يُوقف عن الأهلية لمدة 60 days","يُوقف عن الأهلية لمدة 1 year","يُغرَّم $500 دون فترة إيقاف عن الخدمة"],"explanation":"ينص دليل CDL لألاسكا على أنك ستُوضع خارج الخدمة لمدة 24 hours إذا كان لديك أي كمية قابلة للكشف من الكحول دون .04%. المصدر: دليل CDL لـ Alaska DMV، القسم 1.3.2."},"49":{"q":"ما هو الحد الأدنى للسرعة فوق الحد المعلن الذي يُحتسب كمخالفة مرورية خطيرة لحامل رخصة CDL في ألاسكا؟","options":["15 mph أو أكثر فوق الحد","10 mph أو أكثر فوق الحد","20 mph أو أكثر فوق الحد","5 mph أو أكثر فوق الحد"],"explanation":"السرعة المفرطة تعني 15 mph أو أكثر فوق الحد المعلن، وهي مخالفة مرورية خطيرة. المصدر: دليل CDL لـ Alaska DMV، القسم 1.3.3."},"50":{"q":"كم مدة الإيقاف عن الأهلية في ألاسكا عن ارتكاب مخالفتين مروريتين خطيرتين في مركبة CMV خلال فترة ثلاث سنوات؟","options":["60 days على الأقل","30 days على الأقل","120 days على الأقل","1 year على الأقل"],"explanation":"ينتج عن مخالفتين مروريتين خطيرتين خلال 3 سنوات إيقاف عن الأهلية لمدة 60 days على الأقل. المصدر: دليل CDL لـ Alaska DMV، القسم 1.3.3 وجدول المخالفات الخطيرة الموجبة للإيقاف."},"51":{"q":"كم مدة الإيقاف عن الأهلية في ألاسكا عن ثلاث مخالفات مرورية خطيرة أو أكثر في مركبة CMV خلال فترة ثلاث سنوات؟","options":["120 days على الأقل","60 days على الأقل","90 days على الأقل","1 year على الأقل"],"explanation":"ينتج عن ثلاث مخالفات مرورية خطيرة أو أكثر خلال 3 سنوات إيقاف عن الأهلية لمدة 120 days على الأقل. المصدر: دليل CDL لـ Alaska DMV، القسم 1.3.3 وجدول المخالفات الخطيرة الموجبة للإيقاف."},"52":{"q":"أي من هذه ليست مُدرجة كمخالفة مرورية خطيرة في دليل CDL لألاسكا؟","options":["قيادة مركبة CMV بتركيز BAC قدره 0.04% أو أعلى","اتباع مركبة عن قرب شديد","تغييرات مسار غير سليمة أو متقطعة","قيادة مركبة CMV دون الفئة المناسبة من CDL"],"explanation":"القيادة بتركيز BAC قدره 0.04% أو أعلى هي مخالفة كبرى، وليست مخالفة مرورية خطيرة. أما الثلاث الأخرى فهي مخالفات مرورية خطيرة. المصدر: دليل CDL لـ Alaska DMV، القسمان 1.3.2 و1.3.3."},"53":{"q":"بموجب قانون ألاسكا (AS 28.33.190)، تُصنَّف الرسائل النصية أو استخدام هاتف محمول باليد أثناء قيادة مركبة CMV على أنها ماذا؟","options":["مخالفة مرورية خطيرة (استخدام جهاز إلكتروني)","مخالفة كبرى موجبة للإيقاف عن الأهلية","انتهاك أمر إيقاف عن الخدمة","مخالفة غير واجبة الإبلاغ"],"explanation":"تدرج ألاسكا 'استخدام جهاز إلكتروني أثناء القيادة' (AS 28.33.190(16)(H)) ضمن المخالفات الخطيرة الموجبة للإيقاف عن الأهلية، وتُحتسب ضمن عتبتي 60-day/120-day. المصدر: دليل CDL لـ Alaska DMV، المخالفات الخطيرة الموجبة للإيقاف؛ AS 28.33.190."},"54":{"q":"ما هو الحد الأقصى للعقوبة المدنية التي قد يواجهها سائق CMV لانتهاك حظر الهاتف المحمول باليد الموصوف في دليل CDL لألاسكا؟","options":["حتى $2,750","حتى $11,000","حتى $500","حتى $1,000"],"explanation":"يخضع كل انتهاك للهاتف المحمول باليد لعقوبة مدنية تصل إلى $2,750 على السائق؛ ويواجه أصحاب العمل ما يصل إلى $11,000. المصدر: دليل CDL لـ Alaska DMV، القسم 2.9.4 (الهواتف المحمولة باليد)."},"55":{"q":"ما هو الإيقاف عن الأهلية في ألاسكا عن انتهاك أول لأمر إيقاف عن الخدمة (OOS) أثناء تشغيل مركبة CMV (دون مواد خطرة أو ركاب)؟","options":["لا تقل عن 180 days ولا تزيد عن 1 year","لا تقل عن 90 days ولا تزيد عن 1 year","60 days بالضبط","لا تقل عن 2 years ولا تزيد عن 5 years"],"explanation":"تُوقف ألاسكا عن الأهلية عن انتهاك أول لأمر OOS لمدة لا تقل عن 180 days ولا تزيد عن 1 year. المصدر: دليل CDL لـ Alaska DMV، جدول انتهاك أوامر الإيقاف عن الخدمة (AS 28.33.140(j))."},"56":{"q":"كم مدة الإيقاف عن الأهلية في ألاسكا عن انتهاك أول لأمر الإيقاف عن الخدمة يُرتكب أثناء نقل مواد خطرة أو ركاب؟","options":["لا تقل عن 180 days ولا تزيد عن 2 years","لا تقل عن 180 days ولا تزيد عن 1 year","لا تقل عن 1 year ولا تزيد عن 5 years","120 days بالضبط"],"explanation":"يُوقَف انتهاك أول لأمر OOS أثناء نقل مواد خطرة أو ركاب عن الأهلية لمدة لا تقل عن 180 days ولا تزيد عن 2 years. المصدر: دليل CDL لـ Alaska DMV، جدول انتهاك أوامر الإيقاف عن الخدمة (AS 28.33.140(j))."},"57":{"q":"ما هو الإيقاف عن الأهلية في ألاسكا عن انتهاك ثانٍ لأمر الإيقاف عن الخدمة (دون مواد خطرة) خلال فترة 10 سنوات؟","options":["لا تقل عن 1 year ولا تزيد عن 5 years","لا تقل عن 180 days ولا تزيد عن 1 year","لا تقل عن 3 years ولا تزيد عن 5 years","مدى الحياة"],"explanation":"يحمل انتهاك ثانٍ لأمر OOS خلال 10 سنوات مدة لا تقل عن 1 year ولا تزيد عن 5 years؛ ومع مواد خطرة أو ركاب تكون 3 to 5 years. المصدر: دليل CDL لـ Alaska DMV، جدول انتهاك أوامر الإيقاف عن الخدمة."},"58":{"q":"عن انتهاك أول لمعبر السكك الحديدية مع الطريق السريع أثناء تشغيل مركبة CMV، ما هو الإيقاف عن الأهلية في ألاسكا؟","options":["60 days على الأقل","15 days على الأقل","120 days على الأقل","1 year على الأقل"],"explanation":"تُوقف ألاسكا عن الأهلية عن انتهاك أول لمعبر السكك الحديدية مع الطريق السريع لمدة 60 days على الأقل؛ والثاني خلال 3 سنوات يكون 120 days، والثالث خلال 3 سنوات يكون 1 year. المصدر: دليل CDL لـ Alaska DMV، القسم 1.3.5 / جدول انتهاكات معبر السكك الحديدية مع الطريق السريع."},"59":{"q":"في ألاسكا، يجب على الحافلة أو المركبة التي تنقل مواد خطرة تحمل لافتات تحذيرية أن تتوقف عند تقاطع السكة الحديدية مع الطريق ضمن أي مسافة من أقرب قضيب حديدي؟","options":["بين 15 و50 قدمًا","بين 5 و15 قدمًا","بين 50 و100 قدم","بين 10 و25 قدمًا"],"explanation":"يشترط دليل CDL في ألاسكا (القسمان 4.3.5 و9.6.12) على الحافلات ومركبات HazMat التي تحمل لافتات تحذيرية أن تتوقف على مسافة لا تقل عن 15 قدمًا ولا تزيد عن 50 قدمًا من أقرب قضيب حديدي، ثم تنظر وتُصغي قبل العبور."},"60":{"q":"بموجب قانون التنحّي جانبًا (Move Over) في ألاسكا، عندما يقترب السائق من مركبة طوارئ متوقفة تُظهر أضواءً وامضة على طريق به مساران أو أكثر في الاتجاه نفسه، يجب على السائق أن:","options":["يُخلي المسار الأقرب إلى مركبة الطوارئ عندما يكون من الآمن القيام بذلك","يتوقف توقفًا تامًا حتى تغادر مركبة الطوارئ","يُطلق البوق ويواصل السير بالسرعة المحددة","يتوقف على الكتف وينتظر ثلاث دقائق"],"explanation":"يشترط قانون ألاسكا AS 28.35.185 على السائقين على طريق به مساران أو أكثر في الاتجاه نفسه إخلاء المسار الأقرب إلى مركبة طوارئ أو إطفاء أو إنفاذ قانون أو قطر أو صيانة أو مكافحة حيوانات متوقفة تُظهر أضواءً وامضة، إذا كان من الآمن القيام بذلك."},"61":{"q":"عند التوقف لحافلة مدرسية تومض أضواؤها الحمراء، يشترط قانون ألاسكا على السائق المقترب أن يتوقف على مسافة لا تقل عن أي مقدار من الحافلة؟","options":["30 قدمًا","15 قدمًا","20 قدمًا","50 قدمًا"],"explanation":"يشترط قانون ألاسكا AS 28.35.145 على السائق المقترب من حافلة مدرسية تومض أضواؤها الحمراء أن يتوقف على مسافة لا تقل عن 30 قدمًا من الحافلة وألا يتابع السير حتى تتوقف الأضواء عن الوميض."},"62":{"q":"على أي طريق غير الزقاق أو المنطقة التجارية أو المنطقة السكنية، ما هي السرعة القصوى القانونية لمركبة تجارية في ألاسكا ما لم يُحدَّد خلاف ذلك بلافتة؟","options":["55 ميلًا في الساعة","65 ميلًا في الساعة","60 ميلًا في الساعة","70 ميلًا في الساعة"],"explanation":"تحدد المدونة الإدارية لألاسكا 13 AAC 03.275 السرعة القصوى القانونية للمركبات التجارية عند 55 ميلًا في الساعة على أي طريق آخر (15 ميلًا في الساعة في الزقاق، و20 ميلًا في الساعة في المنطقة التجارية، و25 ميلًا في الساعة في المنطقة السكنية)."},"63":{"q":"يتضمن قانون التوقف للحافلات المدرسية في ألاسكا استثناءً للطرق المقسّمة. متى لا يكون السائق المقترب مُلزمًا بالتوقف للحافلة المدرسية؟","options":["عندما تكون الحافلة على مسلك مختلف من طريق ذي مسالك منفصلة","عندما يسير السائق بسرعة أقل من الحد بمقدار 10 أميال في الساعة على الأقل","عندما تكون الحافلة على بُعد أكثر من 100 قدم","عندما لا يكون هناك أطفال مرئيون بالقرب من الحافلة"],"explanation":"بموجب AS 28.35.145، لا يكون السائق على طريق ذي مسالك منفصلة مُلزمًا بالتوقف عند ملاقاة أو تجاوز حافلة مدرسية تكون على مسلك مختلف (استثناء الطريق المقسّم)."},"64":{"q":"بعد توقف مركبة تجارية على طريق ذي اتجاه واحد أو طريق مقسّم في ألاسكا، في أي مواقع يجب على السائق وضع المثلثات التحذيرية الثلاثة؟","options":["نحو 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المقتربة","نحو 10 أقدام و50 قدمًا و150 قدمًا باتجاه حركة المرور المقتربة","نحو 25 قدمًا و100 قدم و250 قدمًا باتجاه حركة المرور المقتربة","نحو 50 قدمًا و100 قدم و500 قدم باتجاه حركة المرور المقتربة"],"explanation":"وفقًا لدليل CDL في ألاسكا (القسم 2.5)، على الطريق ذي الاتجاه الواحد أو الطريق المقسّم تُوضع أجهزة التحذير على مسافات 10 أقدام و100 قدم و200 قدم من المركبة باتجاه حركة المرور المقتربة."},"65":{"q":"السائق الذي يخالف قانون التنحّي جانبًا في ألاسكا (AS 28.35.185) ويتسبب في إصابة شخصية يكون مذنبًا بأي جُرم؟","options":["جُنحة من الفئة A","مخالفة فقط","جناية من الفئة B","مخالفة لا تترتب عليها نقاط"],"explanation":"تجعل المادة AS 28.35.185(b) مخالفة قانون التنحّي جانبًا جُنحة من الفئة A عندما تنتج إصابة شخصية عن عدم إخلاء المسار أو التباطؤ؛ وإلا فهي مخالفة."},"66":{"q":"على طريق ذي مسارين يحمل حركة المرور في الاتجاهين، أين يوجّه دليل CDL في ألاسكا السائق إلى وضع المثلثات التحذيرية بعد التوقف؟","options":["ضمن 10 أقدام من المركبة، و100 قدم خلفها وأمامها","ضمن 25 قدمًا من المركبة، و200 قدم خلفها وأمامها","100 قدم خلف المركبة فقط","على مسافات 10 و100 و200 قدم خلف المركبة فقط"],"explanation":"يقول دليل CDL في ألاسكا (القسم 2.5) إنه على طريق غير مقسّم ثنائي الاتجاه، ضع مثلثًا ضمن 10 أقدام من المركبة وواحدًا على بُعد 100 قدم خلفها وآخر 100 قدم أمامها على الكتف أو في المسار."},"67":{"q":"أي قائمة من المركبات يُطلب منها التوقف الإلزامي قبل عبور قضبان السكة الحديدية بموجب قواعد CDL في ألاسكا؟","options":["المركبات التي تحمل لافتات تحذيرية، وأي مركبة تنقل الكلور، ومركبات صهاريج الشحن المستخدمة للمواد الخطرة","التركيبات ثلاثية المقطورات فقط","الحافلات التي تنقل أكثر من 30 راكبًا فقط","جميع المركبات التي يزيد وزنها الإجمالي عن 26,000 رطل"],"explanation":"يسرد القسم 9.6.12 من دليل CDL في ألاسكا المركبات التي يجب أن تتوقف عند تقاطعات السكة الحديدية: المركبات التي تحمل لافتات تحذيرية، وأي مركبة تنقل أي كمية من الكلور، ومركبات صهاريج الشحن (المحمّلة أو الفارغة) المستخدمة للمواد الخطرة."},"68":{"q":"كم من الوقت بعد التوقف على الطريق يكون لدى سائق CDL في ألاسكا لوضع أجهزة التحذير من الطوارئ؟","options":["خلال 10 دقائق","خلال 5 دقائق","خلال 15 دقيقة","فورًا، خلال دقيقة واحدة"],"explanation":"يذكر دليل CDL في ألاسكا (القسم 2.5) أنه إذا اضطررت إلى التوقف على الطريق أو بجانبه، فيجب عليك وضع أجهزة التحذير من الطوارئ خلال 10 دقائق."},"69":{"q":"عندما يجب على سائق CDL في ألاسكا توقيف مركبة تجارية على جانب الطريق، ما هي أجهزة التحذير الثلاثة المطلوبة؟","options":["ثلاثة مثلثات عاكسة حمراء، أو 6 شعلات ضوئية (fusees)، أو 3 شعلات تعمل بالسائل","فانوسان أحمران وعلَم أحمر واحد","أربعة عاكسات كهرمانية اللون","مثلث عاكس واحد وشعلتان طريق"],"explanation":"يسرد دليل CDL في ألاسكا أجهزة التحذير المقبولة للمركبات المتوقفة بأنها ثلاثة مثلثات عاكسة حمراء، أو 6 شعلات ضوئية (fusees) على الأقل، أو 3 شعلات تعمل بالسائل."},"70":{"q":"سائق حافلة مدرسية في ألاسكا يجب أن يتوقف عند تقاطع السكة الحديدية ينبغي له أيضًا فعل أي مما يلي قبل العبور؟","options":["فتح الباب الأمامي إذا كان ذلك يُحسّن القدرة على رؤية أو سماع قطار مقترب","إطلاق البوق ثلاث مرات","جعل جميع الركاب يغادرون الحافلة أولًا","التحويل إلى ترس أدنى أثناء وجوده على القضبان"],"explanation":"يوجّه دليل CDL في ألاسكا (القسم 4.3.5) سائقي الحافلات إلى التوقف على مسافة 15 إلى 50 قدمًا قبل التقاطع، والنظر والإصغاء في الاتجاهين، وفتح الباب الأمامي إذا كان ذلك يُحسّن القدرة على رؤية أو سماع القطار."},"71":{"q":"إذا توقفت مركبة تجارية على جانب الطريق خلف تلة أو منعطف يحجب رؤية السائقين الآخرين ضمن 500 قدم، فماذا ينبغي لسائق CDL في ألاسكا أن يفعل بالمثلثات التحذيرية؟","options":["تحريك المثلث الخلفي إلى الوراء على الطريق بحيث يُوفَّر التحذير خلف العائق","وضع المثلثات الثلاثة جميعها مباشرة خلف المركبة","إزالة المثلثات والاعتماد على الأضواء الوامضة الرباعية فقط","وضع مثلث فوق سقف الكابينة"],"explanation":"يوجّه دليل CDL في ألاسكا (القسم 2.5) إلى أنه إذا حجبت تلة أو منعطف أو عائق آخر خط الرؤية ضمن 500 قدم، فينبغي للسائق تحريك المثلث الخلفي إلى الوراء على الطريق بحيث يُوفَّر التحذير."},"72":{"q":"على طريق مقسّم في ألاسكا، أي سائق مقترب يُعفى من التوقف لحافلة مدرسية تُحمّل الأطفال؟","options":["السائق على المسلك المقابل المفصول عن الحافلة بجزيرة وسطية أو حاجز","السائق الموجود مباشرة خلف الحافلة في المسار نفسه","السائق الذي يتجاوز الحافلة على الكتف الأيمن","أي سائق يسير بسرعة أقل من 20 ميلًا في الساعة"],"explanation":"ينطبق استثناء المسالك المنفصلة في AS 28.35.145 على السائقين على المسلك المقابل من الطريق المقسّم؛ أما السائقون على المسلك نفسه مثل الحافلة، بمن فيهم من خلفها، فيجب أن يتوقفوا."},"73":{"q":"على طريق به أقل من مسارين يسيران في الاتجاه نفسه، ماذا يشترط قانون التنحّي جانبًا في ألاسكا عندما يتجاوز السائق مركبة طوارئ متوقفة تُظهر أضواءً وامضة؟","options":["التباطؤ إلى سرعة معقولة وحصيفة بالنظر إلى حركة المرور والطريق والطقس","الحفاظ على حد السرعة المحدد بدقة","التوقف توقفًا تامًا حتى يُشار إليه بالمتابعة","الانتقال كليًا إلى الكتف المقابل"],"explanation":"يشترط AS 28.35.185 أنه حيث يوجد أقل من مسارين في الاتجاه نفسه، يجب على السائق التباطؤ إلى سرعة معقولة وحصيفة مع مراعاة ظروف حركة المرور والطريق والطقس."},"74":{"q":"أثناء عبور قضبان السكة الحديدية في ألاسكا، ينبغي لسائق CDL أن:","options":["لا يبدّل التروس أثناء عبور القضبان","يخفّض إلى الترس الأول على القضبان لأقصى تحكم","يتوقف على القضبان إذا لم يكن القطار مرئيًا","يتسارع بقوة ويرفع الترس في منتصف العبور"],"explanation":"يحذّر دليل CDL في ألاسكا (القسمان 2.15 و9.6.12) السائقين من تبديل التروس أبدًا أثناء عبور القضبان، لأن تبديلًا فاشلًا للترس قد يترك المركبة متوقفة على التقاطع."},"75":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة/الحمولة في ألاسكا الذي يجوز أن يسير على طريق عام دون تصريح حجم زائد؟","options":["102 بوصة (8 أقدام و6 بوصات)","96 بوصة (8 أقدام)","120 بوصة (10 أقدام)","108 بوصات (9 أقدام)"],"explanation":"يشير دليل تصاريح الحجم الزائد/الوزن الزائد في ألاسكا إلى حد العرض القانوني البالغ 102 بوصة (8 أقدام و6 بوصات) من 17 AAC 25؛ وأي عرض أكبر من ذلك يتطلب تصريحًا ولافتات OVERSIZE/WIDE LOAD."},"76":{"q":"بموجب قواعد تصاريح الحجم الزائد في ألاسكا، تتطلب الحمولة العريضة مركبة مرافقة/مرشدة واحدة على الأقل على جميع المسارات بمجرد أن يتجاوز عرضها:","options":["10 أقدام و6 بوصات","8 أقدام و6 بوصات","12 قدمًا","9 أقدام"],"explanation":"يتطلب دليل تصاريح الحجم الزائد/الوزن الزائد في ألاسكا (القسم 6.2.1) مركبة مرافقة/مرشدة واحدة على الأقل على جميع المسارات عندما يتجاوز عرض المركبة أو الحمولة 10 أقدام و6 بوصات."},"77":{"q":"بموجب قواعد التصاريح في ألاسكا، تُقيَّد الحمولة التي يتجاوز ارتفاعها 17 قدمًا بأي سرعة قصوى على الطريق السريع (في غياب عامل أكثر تقييدًا)؟","options":["45 ميلًا في الساعة","55 ميلًا في الساعة","35 ميلًا في الساعة","25 ميلًا في الساعة"],"explanation":"يقيّد دليل تصاريح الحجم الزائد/الوزن الزائد في ألاسكا (القسم 9.3.1) الحمولات التي يتجاوز ارتفاعها 17 قدمًا بسرعة قصوى على الطريق السريع تبلغ 45 ميلًا في الساعة ما لم تكن عوامل أخرى أكثر تقييدًا."},"78":{"q":"عند جسر متحرك في ألاسكا لا توجد به إشارة ضوئية أو موظف يتحكم في حركة المرور، أين يجب على سائق CDL أن يتوقف؟","options":["على بُعد 50 قدمًا على الأقل قبل الجزء المتحرك من الجسر","على بُعد 15 قدمًا على الأقل قبل الجزء المتحرك من الجسر","على بُعد 100 قدم على الأقل قبل الجزء المتحرك من الجسر","مباشرة عند حافة الجزء المتحرك"],"explanation":"يشترط دليل CDL في ألاسكا (القسم 4.3.6) التوقف على بُعد 50 قدمًا على الأقل قبل الجزء المتحرك من جسر متحرك لا توجد به إشارة ضوئية أو موظف للتحكم في حركة المرور، والتحقق من أن الجزء المتحرك مغلق تمامًا قبل العبور."},"79":{"q":"أي وكالة حكومية في ألاسكا تُصدر رخص القيادة التجارية (CDLs)؟","options":["شعبة المركبات الآلية في ألاسكا (DMV)","وزارة السلامة العامة في ألاسكا","الإدارة الفيدرالية لسلامة الناقلات الآلية (FMCSA)","وزارة النقل والمرافق العامة في ألاسكا (DOT&PF)"],"explanation":"في ألاسكا، شعبة المركبات الآلية (DMV) هي وكالة الترخيص الحكومية للسائقين التي تُصدر رخص CDL وتُجري اختبارات المعرفة والمهارات. وتضع FMCSA المعايير الفيدرالية لـ CDL لكنها لا تُصدر الرخصة. المصدر: صفحة رخصة القيادة التجارية (CDL) لدى Alaska DMV."},"80":{"q":"ما الحد الأدنى من الدرجة الذي يجب أن يحققه المتقدم لاجتياز كل اختبار معرفة لـ CDL في ألاسكا؟","options":["70%","75%","80%","90%"],"explanation":"تشترط ألاسكا درجة لا تقل عن 80% لاجتياز كل اختبار معرفة لـ CDL (المعرفة العامة وأي اختبارات للتظهيرات). المصدر: دليل CDL لدى Alaska DMV / متطلبات CDL لدى Alaska DMV."},"81":{"q":"ينقسم اختبار مهارات CDL في ألاسكا إلى ثلاثة أجزاء. أي مجموعة تسرد الأجزاء الثلاثة جميعها بشكل صحيح؟","options":["فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","فحص النظر، والمعرفة الكتابية، والقيادة على الطريق","فحص ما قبل الرحلة، وفحص الفرامل الهوائية، والركن الموازي","الرجوع للخلف، والوصل/الفصل، ومسار مناورة محدد بالوقت"],"explanation":"يتكون اختبار مهارات CDL في ألاسكا من ثلاثة أجزاء: اختبار فحص (المركبة) ما قبل الرحلة، واختبار مهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: دليل CDL لدى Alaska DMV."},"82":{"q":"من المسؤول عن توفير المركبة المستخدمة في اختبار مهارات القيادة على الطريق لـ CDL في ألاسكا؟","options":["يجب على المتقدم توفير مركبة تمثيلية من الفئة والنوع اللذين ينوي قيادتهما","توفّر DMV مركبة اختبار قياسية لجميع المتقدمين","يخصص سجل مزودي التدريب التابع لـ FMCSA مركبة","تُعير DOT&PF في ألاسكا مركبة من أسطولها"],"explanation":"يجب على المتقدم إحضار مركبته التمثيلية الخاصة من الفئة والنوع نفسيهما اللذين يخطط لقيادتهما؛ ولا يوفّر مكتب DMV مركبة اختبار. المصدر: دليل CDL لدى Alaska DMV / متطلبات CDL لدى Alaska DMV."},"83":{"q":"بعد إصدار تصريح المتعلّم التجاري (CLP)، كم من الوقت يجب أن ينتظر المتقدم في ألاسكا قبل إجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["14 يومًا على الأقل","7 أيام على الأقل","30 يومًا على الأقل","لا توجد فترة انتظار"],"explanation":"تتبع ألاسكا القاعدة الفيدرالية التي تشترط على حامل CLP الانتظار 14 يومًا على الأقل بعد إصدار CLP قبل إجراء أي اختبار طريق لـ CDL. المصدر: صفحة CLP لدى Alaska DMV (49 CFR 383.25)."},"84":{"q":"كم تبلغ مدة صلاحية تصريح المتعلّم التجاري (CLP) في ألاسكا قبل وجوب تجديده؟","options":["180 يومًا","30 يومًا","سنة واحدة","5 سنوات"],"explanation":"يكون CLP في ألاسكا صالحًا لمدة 180 يومًا، ويجوز تجديده (إعادة إصداره) مرة واحدة لمدة 180 يومًا إضافية دون إعادة إجراء اختبار المعرفة العامة. المصدر: معلومات CLP لدى Alaska DMV (49 CFR 383.25)."},"85":{"q":"كم مرة يجوز تجديد/إعادة إصدار CLP في ألاسكا لفترة 180 يومًا إضافية بموجب المعيار الفيدرالي الذي تتبعه ألاسكا؟","options":["مرة واحدة","لا يمكن تجديده على الإطلاق","مرتان","عدد غير محدود من المرات"],"explanation":"يكون CLP صالحًا لمدة 180 يومًا، ويجوز تجديده مرة واحدة لمدة 180 يومًا إضافية (بحد أقصى 360 يومًا إجمالًا). المصدر: معلومات CLP لدى Alaska DMV (49 CFR 383.25)."},"86":{"q":"قبل أن يتمكن المتقدم لأول مرة من إجراء اختبار مهارات CDL لرخصة من الفئة A أو الفئة B في ألاسكا، ما التدريب الذي يجب إكماله؟","options":["تدريب السائق المبتدئ (ELDT) من مزود مدرج في سجل مزودي التدريب التابع لـ FMCSA","دورة قيادة دفاعية معتمدة من النظام القضائي في ألاسكا","شهادة قيادة شتوية في ألاسكا مدتها 40 ساعة","تدريب مهني مسجّل لدى وزارة العمل في ألاسكا"],"explanation":"منذ 7 فبراير 2022، يجب على المتقدمين لـ CDL لأول مرة إكمال تدريب السائق المبتدئ (ELDT) من مزود مدرج في سجل مزودي التدريب التابع لـ FMCSA قبل إجراء اختبار المهارات؛ ويجب على الولاية التحقق من أن السجل قد قُدِّم. المصدر: قاعدة ELDT لدى FMCSA (49 CFR Part 380)، المطبَّقة من قِبل Alaska DMV."},"87":{"q":"يتطلب التصديق الذاتي لـ CDL في ألاسكا أن يُصرّح السائق بنوع التشغيل الذي يتوقع القيام به. كم عدد فئات التصديق الذاتي؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"يجب على السائقين التصديق الذاتي ضمن واحدة من أربع فئات تتشكل من الجمع بين التشغيل بين الولايات/داخل الولاية والتشغيل المستثنى/غير المستثنى. المصدر: صفحة متطلب التصديق الذاتي لـ CDL لدى Alaska DMV."},"88":{"q":"أي مما يلي يُعد واحدة من فئات التصديق الذاتي الأربع لـ CDL في ألاسكا؟","options":["بين الولايات غير مستثنى","بين الولايات موسمي","داخل الولاية للمواد الخطرة فقط","ناقل فيدرالي معفى"],"explanation":"الفئات الأربع هي: بين الولايات غير مستثنى، وبين الولايات مستثنى، وداخل الولاية غير مستثنى، وداخل الولاية مستثنى. و\"بين الولايات غير مستثنى\" هي الفئة الخاصة بالسائقين الذين يجب أن يستوفوا متطلبات بطاقة DOT الطبية الفيدرالية. المصدر: صفحة متطلب التصديق الذاتي لـ CDL لدى Alaska DMV."},"89":{"q":"السائق في ألاسكا الذي يُصدّق ذاتيًا بأنه \"غير مستثنى\" (بين الولايات أو داخل الولاية) يجب أن يقدّم أي وثيقة إلى DMV؟","options":["شهادة فاحص طبي معتمدة من DOT (البطاقة الطبية) سارية","خطاب رعاية من صاحب العمل موثّق","تنازل موقّع عن المعايير الطبية الفيدرالية","ملصق فحص مركبة تجارية في ألاسكا"],"explanation":"يجب على السائقين غير المستثنين حمل وتقديم شهادة فاحص طبي معتمدة من DOT (البطاقة الطبية) سارية للحفاظ على امتيازات CDL؛ أما السائقون المستثنون فلا يُطلب منهم تقديم واحدة. المصدر: صفحة متطلب التصديق الذاتي لـ CDL لدى Alaska DMV."},"90":{"q":"كيف يجوز لحامل CDL في ألاسكا تقديم تصديقه الذاتي وشهادة الفاحص الطبي المعتمدة من DOT إلى DMV؟","options":["إكمال النموذج 413 وتقديم نسخة مقروءة من البطاقة الطبية أو إرسالها بالبريد الإلكتروني إلى عنوان البريد الإلكتروني الخاص بـ CDL لدى DMV","تحميل البطاقة إلى سجل مزودي التدريب التابع لـ FMCSA فقط","إرسال البطاقة الأصلية مباشرة إلى FMCSA في واشنطن العاصمة","إيداعها لدى وزارة العمل وتنمية القوى العاملة في ألاسكا"],"explanation":"يُكمل السائقون التصديق الذاتي (النموذج 413) مع كل طلب ويقدّمون البطاقة الطبية في مكتب DMV أو يرسلون نسخة مقروءة بالبريد الإلكتروني إلى عنوان CDL لدى DMV (doa.dmv.cdl@alaska.gov). المصدر: صفحة متطلب التصديق الذاتي لـ CDL لدى Alaska DMV."},"91":{"q":"ما العاقبة في ألاسكا إذا فشل حامل CDL غير المستثنى في الإبقاء على شهادة فاحص طبي معتمدة من DOT سارية في ملفه لدى DMV؟","options":["يتم خفض درجة امتيازات CDL أو إلغاؤها","تُفرض غرامة فيدرالية لمرة واحدة قدرها 500 دولار لكن يبقى CDL ساريًا","لا شيء، لأن البطاقة الطبية تُودَع لدى صاحب العمل فقط","يُعاد تصنيف السائق تلقائيًا كسائق داخل الولاية مستثنى"],"explanation":"إذا انقضت صلاحية التصديق الطبي لسائق غير مستثنى، تُلغي Alaska DMV امتيازات CDL أو تخفض درجتها؛ ويُعد تشغيل مركبة تجارية بعد ذلك قيادة دون امتيازات صحيحة. المصدر: صفحة متطلب التصديق الذاتي لـ CDL لدى Alaska DMV."},"92":{"q":"كم تبلغ مدة صلاحية CDL في ألاسكا قبل وجوب تجديده؟","options":["5 سنوات","4 سنوات","8 سنوات","سنتان"],"explanation":"يكون CDL في ألاسكا صالحًا لمدة 5 سنوات وينتهي في يوم ميلاد حامله. المصدر: معلومات التجديد لدى Alaska DMV."},"93":{"q":"في أي تاريخ تنتهي صلاحية CDL في ألاسكا عادةً ضمن سنة تجديده؟","options":["في يوم ميلاد حامله","في 31 ديسمبر","بعد خمس سنوات بالضبط من تاريخ الإصدار بصرف النظر عن يوم الميلاد","في آخر يوم من شهر الإصدار"],"explanation":"تُصدَر رخص القيادة في ألاسكا، بما فيها رخص CDL، لمدة 5 سنوات وتنتهي صلاحيتها في يوم ميلاد حاملها. المصدر: معلومات التجديد لدى Alaska DMV."},"94":{"q":"قبل كم من انتهاء الصلاحية يجوز لحامل CDL في ألاسكا البدء في عملية التجديد؟","options":["حتى سنة واحدة قبل انتهاء الصلاحية","حتى 30 يومًا قبل انتهاء الصلاحية","فقط في تاريخ انتهاء الصلاحية","حتى 6 أشهر بعد انتهاء الصلاحية"],"explanation":"تسمح ألاسكا ببدء تجديد CDL في وقت مبكر يصل إلى سنة واحدة قبل انتهاء صلاحية الرخصة؛ ولا توفّر الولاية أي فترة سماح لرخصة منتهية الصلاحية بالفعل. المصدر: معلومات التجديد لدى Alaska DMV."},"95":{"q":"أي مجموعة وثائق مطلوبة عند التقدم للحصول على CDL أصلي في ألاسكا؟","options":["إثبات الجنسية الأمريكية/الوجود القانوني، وعنوان إقامة/سكن في ألاسكا، ورقم ضمان اجتماعي، وبطاقة DOT الطبية عند الاقتضاء","فقط رخصة CDL سارية من ولاية أخرى وصورة جواز سفر","سند ملكية مركبة، وإثبات تأمين، ورخصة صيد في ألاسكا","رقم ناقل لدى FMCSA وإقرار موثّق فقط"],"explanation":"تشترط ألاسكا إثبات الجنسية/الوجود القانوني، وإثبات عنوان إقامة في ألاسكا (السكن)، ورقم ضمان اجتماعي، ورخصة قيادة سارية، وبطاقة DOT الطبية عند الاقتضاء. المصدر: صفحة رخصة القيادة التجارية (CDL) لدى Alaska DMV."},"96":{"q":"ما الحد الأدنى للعمر للحصول على CDL في ألاسكا مقيّد بالتشغيل داخل الولاية (داخل ألاسكا)؟","options":["18 عامًا","16 عامًا","21 عامًا","25 عامًا"],"explanation":"الحد الأدنى للعمر لـ CDL في ألاسكا هو 18 عامًا للتشغيل داخل الولاية؛ أما التشغيل بين الولايات وتظهيرات HazMat والحافلة المدرسية فتتطلب سن 21 عامًا. المصدر: صفحتا CDL / CLP لدى Alaska DMV."},"97":{"q":"السائق الذي يريد التشغيل في التجارة بين الولايات أو نقل المواد الخطرة يجب أن يكون عمره على الأقل أي مقدار ليحمل CDL في ألاسكا لذلك التشغيل؟","options":["21 عامًا","18 عامًا","19 عامًا","25 عامًا"],"explanation":"تشترط ألاسكا أن يكون عمر السائق 21 عامًا على الأقل للتشغيل بين الولايات أو لحمل تظهير HazMat أو الحافلة المدرسية، في حين تتوفر رخص CDL للتشغيل داخل الولاية فقط عند سن 18 عامًا. المصدر: صفحتا CDL / CLP لدى Alaska DMV."},"98":{"q":"فيما يتعلق برسوم طلب CDL في ألاسكا، أي عبارة دقيقة حول كيفية سير العملية؟","options":["تُدفع رسوم CDL واختبار الطريق المعمول بها إلى DMV عند التقديم، والمبالغ الدقيقة تحددها الولاية ويمكن أن تتغير بمرور الوقت","لا تفرض ألاسكا أي رسوم على CDL أصلي","تُدفع جميع رسوم CDL مباشرة إلى FMCSA، لا إلى DMV","رسوم اختبار الطريق قابلة للاسترداد بالكامل إذا رسب المتقدم"],"explanation":"يدفع المتقدمون لـ CDL في ألاسكا رسوم الرخصة واختبار الطريق المعمول بها إلى DMV وقت التقديم؛ والمبالغ المحددة بالدولار تحددها الولاية وتخضع للتغيير، لذا فإن العملية (وليس مبلغًا ثابتًا) هي النقطة الموثوقة. المصدر: صفحة CDL لدى Alaska DMV / جدول الرسوم."}}};
